-- Poems batch 1
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('3ad6d468-7ff1-4a7b-8b24-a27d70d00ed4','帝京篇十首 一','太宗皇帝','唐','唐诗','tang','','[]','秦川雄帝宅，函谷壯皇居。',48,'全唐诗/poet.tang.0.json','["秦川雄帝宅，函谷壯皇居。", "綺殿千尋起，離宮百雉餘。", "連甍遙接漢，飛觀迥凌虛。", "雲日隱層闕，風煙出綺疎。"]'),
('13e72581-968b-457f-b381-a3b7d95b8b7c','帝京篇十首 二','太宗皇帝','唐','唐诗','tang','','[]','巖廊罷機務，崇文聊駐輦。',48,'全唐诗/poet.tang.0.json','["巖廊罷機務，崇文聊駐輦。", "玉匣啓龍圖，金繩披鳳篆。", "韋編斷仍續，縹帙舒還卷。", "對此乃淹留，欹案觀墳典。"]'),
('a7ff247d-a11c-4ca9-a22f-ca420b8c537c','帝京篇十首 三','太宗皇帝','唐','唐诗','tang','','[]','移步出詞林，停輿欣武宴。',48,'全唐诗/poet.tang.0.json','["移步出詞林，停輿欣武宴。", "琱弓寫明月，駿馬疑流電。", "驚雁落虛弦，啼猿悲急箭。", "閱賞誠多美，於茲乃忘倦。"]'),
('fa374b2b-c196-4362-b4ad-8931fc9a8860','帝京篇十首 四','太宗皇帝','唐','唐诗','tang','','[]','鳴笳臨樂館，眺聽歡芳節。',48,'全唐诗/poet.tang.0.json','["鳴笳臨樂館，眺聽歡芳節。", "急管韻朱絃，清歌凝白雪。", "彩鳳肅來儀，玄鶴紛成列。", "去茲鄭衛聲，雅音方可悅。"]'),
('86952cb3-b622-4398-a56a-01dd39f6c6ec','帝京篇十首 五','太宗皇帝','唐','唐诗','tang','','[]','芳辰追逸趣，禁苑信多奇。',48,'全唐诗/poet.tang.0.json','["芳辰追逸趣，禁苑信多奇。", "橋形通漢上，峰勢接雲危。", "煙霞交隱映，花鳥自參差。", "何如肆轍跡？萬里賞瑤池。"]'),
('90bcc00c-bcdb-424e-947b-cf108c47416b','帝京篇十首 六','太宗皇帝','唐','唐诗','tang','','[]','飛蓋去芳園，蘭橈遊翠渚。',48,'全唐诗/poet.tang.0.json','["飛蓋去芳園，蘭橈遊翠渚。", "萍間日彩亂，荷處香風舉。", "桂楫滿中川，弦歌振長嶼。", "豈必汾河曲，方爲歡宴所。"]'),
('621207da-c9ba-4f95-b637-a6bef91b1411','帝京篇十首 七','太宗皇帝','唐','唐诗','tang','','[]','落日雙闕昏，回輿九重暮。',48,'全唐诗/poet.tang.0.json','["落日雙闕昏，回輿九重暮。", "長煙散初碧，皎月澄輕素。", "搴幌翫琴書，開軒引雲霧。", "斜漢耿層閣，清風搖玉樹。"]'),
('0ed3f92a-d1d2-46ff-ae2c-1e58676a38a7','帝京篇十首 八','太宗皇帝','唐','唐诗','tang','','[]','歡樂難再逢，芳辰良可惜。',48,'全唐诗/poet.tang.0.json','["歡樂難再逢，芳辰良可惜。", "玉酒泛雲罍，蘭殽陳綺席。", "千鍾合堯禹，百獸諧金石。", "得志重寸陰，忘懷輕尺璧。"]'),
('9b6731ea-1ac2-4ed5-88bf-1d7da232fb0b','帝京篇十首 九','太宗皇帝','唐','唐诗','tang','','[]','建章歡賞夕，二八盡妖妍。',48,'全唐诗/poet.tang.0.json','["建章歡賞夕，二八盡妖妍。", "羅綺昭陽殿，芬芳玳瑁筵。", "珮移星正動，扇掩月初圓。", "無勞上懸圃，即此對神仙。"]'),
('6b51924c-4325-4bc7-8134-1217dcbb2585','帝京篇十首 十','太宗皇帝','唐','唐诗','tang','','[]','以茲遊觀極，悠然獨長想。',96,'全唐诗/poet.tang.0.json','["以茲遊觀極，悠然獨長想。", "披卷覽前蹤，撫躬尋既往。", "望古茅茨約，瞻今蘭殿廣。", "人道惡高危，虛心戒盈蕩。", "奉天竭誠敬，臨民思惠養。", "納善察忠諫，明科慎刑賞。", "六五誠難繼，四三非易仰。", "廣待淳化敷，方嗣云亭響。"]'),
('84b9a130-8145-4902-aac7-5779c17e3fef','飲馬長城窟行','太宗皇帝','唐','唐诗','tang','','["\u6218\u4e89", "\u751f\u6d3b", "\u51ac\u5929", "\u7231\u56fd", "\u8fb9\u585e"]','塞外悲風切，交河冰已結。',120,'全唐诗/poet.tang.0.json','["塞外悲風切，交河冰已結。", "瀚海百重波，陰山千里雪。", "迥戍危烽火，層巒引高節。", "悠悠卷斾旌，飲馬出長城。", "寒沙連騎跡，朔吹斷邊聲。", "胡塵清玉塞，羌笛韻金鉦。", "絕漠干戈戢，車徒振原隰。", "都尉反龍堆，將軍旋馬邑。", "揚麾氛霧靜，紀石功名立。", "荒裔一戎衣，靈臺凱歌入。"]'),
('786e30bf-b8a8-4067-a51c-1a5b522ed71d','執契靜三邊','太宗皇帝','唐','唐诗','tang','','[]','執契靜三邊，持衡臨萬姓。',240,'全唐诗/poet.tang.0.json','["執契靜三邊，持衡臨萬姓。", "玉彩輝關燭，金華流日鏡。", "無爲宇宙清，有美璇璣正。", "皎佩星連景，飄衣雲結慶。", "戢武耀七德，昇文輝九功。", "煙波澄舊碧，塵火息前紅。", "霜野韜蓮劒，關城罷月弓。", "錢綴榆天合，新城柳塞空。", "花銷蔥嶺雪，縠盡流沙霧。", "秋駕轉兢懷，春冰彌軫慮。", "書絕龍庭羽，烽休鳳穴戍。", "衣宵寢二難，食旰餐三懼。", "翦暴興先廢，除兇存昔亡。", "圓蓋歸天壤，方輿入地荒。", "孔海池京邑，雙河沼帝鄉。", "循躬思勵己，撫俗媿時康。", "元首佇鹽梅，股肱惟輔弼。", "羽賢崆嶺四，翼聖襄城七。", "澆俗庶反淳，替文聊就質。", "已知隆至道，共歡區宇一。"]'),
('bb81eac8-221c-4d0a-89d7-aa4c0f01d8a1','正日臨朝','太宗皇帝','唐','唐诗','tang','','[]','條風開獻節，灰律動初陽。',96,'全唐诗/poet.tang.0.json','["條風開獻節，灰律動初陽。", "百蠻奉遐賮，萬國朝未央。", "雖無舜禹迹，幸欣天地康。", "車軌同八表，書文混四方。", "赫奕儼冠蓋，紛綸盛服章。", "羽旄飛馳道，鐘鼓震巖廊。", "組練輝霞色，霜戟耀朝光。", "晨宵懷至理，終媿撫遐荒。"]'),
('84bf01fc-ec00-4d81-8189-153cd0c0d4ea','幸武功慶善宮','太宗皇帝','唐','唐诗','tang','','[]','壽丘惟舊跡，酆邑乃前基。',120,'全唐诗/poet.tang.0.json','["壽丘惟舊跡，酆邑乃前基。", "粵予承累聖，懸弧亦在茲。", "弱齡逢運改，提劒鬱匡時。", "指麾八荒定，懷柔萬國夷。", "梯山咸入款，駕海亦來思。", "單于陪武帳，日逐衛文㮰。", "端扆朝四岳，無爲任百司。", "霜節明秋景，輕冰結水湄。", "芸黃徧原隰，禾穎積京畿。", "共樂還鄉宴，歡比大風詩。"]'),
('f5436455-4bdd-4425-96c5-12ed92905950','重幸武功','太宗皇帝','唐','唐诗','tang','','[]','代馬依朔吹，驚禽愁昔叢。',120,'全唐诗/poet.tang.0.json','["代馬依朔吹，驚禽愁昔叢。", "況茲承眷德，懷舊感深衷。", "積善忻餘慶，暢武悅成功。", "垂衣天下治，端拱車書同。", "白水巡前跡，丹陵幸舊宮。", "列筵歡故老，高宴聚新豐。", "駐蹕撫田畯，回輿訪牧童。", "瑞氣縈丹闕，祥煙散碧空。", "孤嶼含霜白，遙山帶日紅。", "於焉歡擊筑，聊以詠南風。"]'),
('4a3c83d8-a6f2-46f7-852b-4d2162d1c6c4','經破薛舉戰地','太宗皇帝','唐','唐诗','tang','','[]','昔年懷壯氣，提戈初仗節。',120,'全唐诗/poet.tang.0.json','["昔年懷壯氣，提戈初仗節。", "心隨朗日高，志與秋霜潔。", "移鋒驚電起，轉戰長河決。", "營碎落星沈，陣卷橫雲裂。", "一揮氛沴靜，再舉鯨鯢滅。", "於茲俯舊原，屬目駐華軒。", "沈沙無故迹，減竈有殘痕。", "浪霞穿水淨，峰霧抱蓮昏。", "世途亟流易，人事殊今昔。", "長想眺前蹤，撫躬聊自適。"]'),
('5ba88d33-b035-4949-b673-e498ccfcee24','過舊宅二首 一','太宗皇帝','唐','唐诗','tang','','[]','新豐停翠輦，譙邑駐鳴笳。',48,'全唐诗/poet.tang.0.json','["新豐停翠輦，譙邑駐鳴笳。", "園荒一徑斷，苔古半階斜。", "前池消舊水，昔樹發今花。", "一朝辭此地，四海遂爲家。"]'),
('4c69b5b5-49c7-4d2b-8472-e11d39ca4106','過舊宅二首 二','太宗皇帝','唐','唐诗','tang','','[]','金輿巡白水，玉輦駐新豐。',84,'全唐诗/poet.tang.0.json','["金輿巡白水，玉輦駐新豐。", "紐落藤披架，花殘菊破叢。", "葉鋪荒草蔓，流竭半池空。", "紉珮蘭凋徑，舒圭葉翦桐。", "昔地一蕃內，今宅九圍中。", "架海波澄鏡，韜戈器反農。", "八表文同軌，無勞歌大風。"]'),
('70ec76dd-b81d-4d0b-944d-a71d13469e19','還陝述懷','太宗皇帝','唐','唐诗','tang','','[]','慨然撫長劒，濟世豈邀名。',60,'全唐诗/poet.tang.0.json','["慨然撫長劒，濟世豈邀名。", "星旂紛電舉，日羽肅天行。", "徧野屯萬騎，臨原駐五營。", "登山麾武節，背水縱神兵。", "在昔戎戈動，今來宇宙平。"]'),
('09848995-b603-4010-8f95-0027fda0d119','入潼關','太宗皇帝','唐','唐诗','tang','','[]','崤函稱地險，襟帶壯兩京。',84,'全唐诗/poet.tang.0.json','["崤函稱地險，襟帶壯兩京。", "霜峰直臨道，冰河曲繞城。", "古木參差影，寒猿斷續聲。", "冠蓋往來合，風塵朝夕驚。", "高談先馬度，僞曉預雞鳴。", "棄繻懷遠志，封泥負壯情。", "別有真人氣，安知名不名。"]'),
('c821f7b5-7b29-4f76-be64-cd5b5f9eca09','於北平作','太宗皇帝','唐','唐诗','tang','','[]','翠野駐戎軒，盧龍轉征斾。',36,'全唐诗/poet.tang.0.json','["翠野駐戎軒，盧龍轉征斾。", "遙山麗如綺，長流縈似帶。", "海氣百重樓，巖松千丈蓋。"]'),
('26d1a470-54cc-4e65-954b-5ab6eeb7358b','遼城望月','太宗皇帝','唐','唐诗','tang','','[]','玄兔月初明，澄輝照遼碣。',60,'全唐诗/poet.tang.0.json','["玄兔月初明，澄輝照遼碣。", "映雲光暫隱，隔樹花如綴。", "魄滿桂枝圓，輪虧鏡彩缺。", "臨城却影散，帶暈重圍結。", "駐蹕俯九都，停觀妖氛滅。"]'),
('7136e8b6-cec9-423f-89e9-a260eeb32481','春日登陝州城樓俯眺原野迴丹碧綴煙霞密翠斑紅芳菲花柳即目川岫聊以命篇','太宗皇帝','唐','唐诗','tang','','[]','碧原開霧隰，綺嶺峻霞城。',60,'全唐诗/poet.tang.0.json','["碧原開霧隰，綺嶺峻霞城。", "煙峰高下翠，日浪淺深明。", "斑紅粧橤樹，圓青壓溜荆。", "迹巖勞傅想，窺野訪莘情。", "巨川何以濟，舟楫佇時英。"]'),
('f85432ef-54f1-4cc0-91c5-91af18ff0d05','春日玄武門宴羣臣','太宗皇帝','唐','唐诗','tang','','[]','韶光開令序，淑氣動芳年。',96,'全唐诗/poet.tang.0.json','["韶光開令序，淑氣動芳年。", "駐輦華林側，高宴柏梁前。", "紫庭文珮滿，丹墀衮紱連。", "九夷簉瑤席，五狄列瓊筵。", "娛賓歌湛露，廣樂奏鈞天。", "清尊浮綠醑，雅曲韻朱弦。", "粵余君萬國，還慙撫八埏。", "庶幾保貞固，虛己厲求賢。"]'),
('db548528-fbd1-4356-bc2d-403760c1267c','登三臺言志','太宗皇帝','唐','唐诗','tang','','[]','未央初壯漢，阿房昔侈秦。',132,'全唐诗/poet.tang.0.json','["未央初壯漢，阿房昔侈秦。", "在危猶騁麗，居奢遂役人。", "豈如家四海，日宇罄朝倫。", "扇天裁戶舊，砌地翦基新。", "引月擎宵桂，飄雲逼曙鱗。", "露除光炫玉，霜闕映雕銀。", "舞接花梁燕，歌迎鳥路塵。", "鏡池波太液，莊苑麗宜春。", "作異甘泉日，停非路寢辰。", "念勞慙逸己，居曠返勞神。", "所欣成大厦，宏材佇渭濱。"]'),
('822d55ea-2b24-4067-a997-106adf6d6f55','出獵','太宗皇帝','唐','唐诗','tang','','[]','楚王雲夢澤，漢帝長楊宮。',96,'全唐诗/poet.tang.0.json','["楚王雲夢澤，漢帝長楊宮。", "豈若因農暇，閱武出轘嵩。", "三驅陳銳卒，七萃列材雄。", "寒野霜氛白，平原燒火紅。", "琱戈夏服箭，羽騎綠沈弓。", "怖獸潛幽壑，驚禽散翠空。", "長煙晦落景，灌木振嚴風。", "所爲除民瘼，非是悅林叢。"]'),
('b11c8320-d662-41e0-a9f2-8f4d4c4ceccd','冬狩','太宗皇帝','唐','唐诗','tang','','[]','烈烈寒風起，慘慘飛雲浮。',108,'全唐诗/poet.tang.0.json','["烈烈寒風起，慘慘飛雲浮。", "霜濃凝廣隰，冰厚結清流。", "金鞍移上苑，玉勒騁平疇。", "旌旗四望合，罝羅一面求。", "楚踣爭兕殪，秦亡角鹿愁。", "獸忙投密樹，鴻驚起礫洲。", "騎斂原塵靜，戈迴嶺日收。", "心非洛汭逸，意在渭濱游。", "禽荒非所樂，撫轡更招憂。"]'),
('fdf597bd-d45c-407d-9a5b-739be83771de','春日望海','太宗皇帝','唐','唐诗','tang','','[]','披襟眺滄海，憑軾翫春芳。',120,'全唐诗/poet.tang.0.json','["披襟眺滄海，憑軾翫春芳。", "積流橫地紀，疎派引天潢。", "仙氣凝三嶺，和風扇八荒。", "拂潮雲布色，穿浪日舒光。", "照岸花分彩，迷雲雁斷行。", "懷卑運深廣，持滿守靈長。", "有形非易測，無源詎可量。", "洪濤經變野，翠島屢成桑。", "之罘思漢帝，碣石想秦皇。", "霓裳非本意，端拱且圖王。"]'),
('602688e2-e83d-4afd-87aa-af6f8f971a8a','臨洛水','太宗皇帝','唐','唐诗','tang','','[]','春蒐馳駿骨，總轡俯長河。',48,'全唐诗/poet.tang.0.json','["春蒐馳駿骨，總轡俯長河。", "霞處流縈錦，風前瀁卷羅。", "水花翻照樹，堤蘭倒插波。", "豈必汾陰曲，秋雲發棹歌。"]'),
('4714a2d4-49c5-45f5-a2ae-4a0eceac88f8','望終南山','太宗皇帝','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','重巒俯渭水，碧嶂插遙天。',48,'全唐诗/poet.tang.0.json','["重巒俯渭水，碧嶂插遙天。", "出紅扶嶺日，入翠貯巖煙。", "疊松朝若夜，複岫闕疑全。", "對此恬千慮，無勞訪九仙。"]'),
('63397c51-1271-4a83-b1c3-a9daef8f406a','元日','太宗皇帝','唐','唐诗','tang','','["\u6625\u8282"]','高軒曖春色，邃閣媚朝光。',96,'全唐诗/poet.tang.0.json','["高軒曖春色，邃閣媚朝光。", "彤庭飛綵斾，翠幌曜明璫。", "恭己臨四極，垂衣馭八荒。", "霜戟列丹陛，絲竹韻長廊。", "穆矣熏風茂，康哉帝道昌。", "繼文遵後軌，循古鑒前王。", "草秀故春色，梅豔昔年粧。", "巨川思欲濟，終以寄舟航。"]'),
('fd63be75-f6b3-491d-91d5-04179194f1aa','初春登樓即目觀作述懷','太宗皇帝','唐','唐诗','tang','','[]','憑軒俯蘭閣，眺矚散靈襟。',96,'全唐诗/poet.tang.0.json','["憑軒俯蘭閣，眺矚散靈襟。", "綺峰含翠霧，照日蕊紅林。", "鏤丹霞錦岫，殘素雪斑岑。", "拂浪堤垂柳，嬌花鳥續吟。", "連甍豈一拱，衆幹如千尋。", "明非獨材力，終藉棟梁深。", "彌懷矜樂志，更懼戒盈心。", "媿制勞居逸，方規十產金。"]'),
('75f1983d-2147-4028-a0d8-fdfc4c2d8244','首春','太宗皇帝','唐','唐诗','tang','','[]','寒隨窮律變，春逐鳥聲開。',48,'全唐诗/poet.tang.0.json','["寒隨窮律變，春逐鳥聲開。", "初風飄帶柳，晚雪間花梅。", "碧林青舊竹，綠沼翠新苔。", "芝田初雁去，綺樹巧鸎來。"]'),
('847b969b-de24-48b5-9917-29f1e0233c08','初晴落景','太宗皇帝','唐','唐诗','tang','','[]','晚霞聊自怡，初晴彌可喜。',48,'全唐诗/poet.tang.0.json','["晚霞聊自怡，初晴彌可喜。", "日晃百花色，風動千林翠。", "池魚躍不同，園鳥聲還異。", "寄言博通者，知予物外志。"]'),
('8d2bd14f-e18f-4296-a4f0-972b09a7928a','初夏','太宗皇帝','唐','唐诗','tang','','[]','一朝春夏改，隔夜鳥花遷。',72,'全唐诗/poet.tang.0.json','["一朝春夏改，隔夜鳥花遷。", "陰陽深淺葉，曉夕重輕煙。", "哢鸎猶響殿，橫絲正網天。", "珮高蘭影接，綬細草紋連。", "碧鱗驚櫂側，玄燕舞檐前。", "何必汾陽處，始復有山泉。"]'),
('fc15b398-9ab5-4210-b1df-885c70cf846f','度秋','太宗皇帝','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','夏律昨留灰，秋箭今移晷。',48,'全唐诗/poet.tang.0.json','["夏律昨留灰，秋箭今移晷。", "峨嵋岫初出，洞庭波漸起。", "桂白發幽巖，菊黃開灞涘。", "運流方可歎，含毫屬微理。"]'),
('09bbfe4c-d07c-4f0d-96b1-92647d37cd1e','儀鸞殿早秋','太宗皇帝','唐','唐诗','tang','','[]','寒驚薊門葉，秋發小山枝。',48,'全唐诗/poet.tang.0.json','["寒驚薊門葉，秋發小山枝。", "松陰背日轉，竹影避風移。", "提壺菊花岸，高興芙蓉池。", "欲知涼氣早，巢空燕不窺。"]'),
('a609556d-746c-4703-97a2-0aac7168fce7','秋日即目','太宗皇帝','唐','唐诗','tang','','[]','爽氣浮丹闕，秋光澹紫宮。',96,'全唐诗/poet.tang.0.json','["爽氣浮丹闕，秋光澹紫宮。", "衣碎荷疎影，花明菊點叢。", "袍輕低草露，蓋側舞松風。", "散岫飄雲葉，迷路飛煙鴻。", "砌冷蘭凋佩，閨寒樹隕桐。", "別鶴棲琴裏，離猿啼峽中。", "落野飛星箭，弦虛半月弓。", "芳菲夕霧起，暮色滿房櫳。"]'),
('5f4f255b-13f1-4a5f-b36c-5ef48f8fc455','山閣晚秋','太宗皇帝','唐','唐诗','tang','','[]','山亭秋色滿，巖牖涼風度。',48,'全唐诗/poet.tang.0.json','["山亭秋色滿，巖牖涼風度。", "疎蘭尚染煙，殘菊猶承露。", "古石衣新苔，新巢封古樹。", "歷覽情無極，咫尺輸光暮。"]'),
('9d2bcfb9-1052-40ca-8a14-87ba811aee4e','秋暮言志','太宗皇帝','唐','唐诗','tang','','[]','朝光浮燒野，霜華淨碧空。',48,'全唐诗/poet.tang.0.json','["朝光浮燒野，霜華淨碧空。", "結浪冰初鏡，在逕菊方叢。", "約嶺煙深翠，分旗霞散紅。", "抽思滋泉側，飛想傅巖中。"]'),
('8de88b9b-bb36-4f7e-a2cd-4771ff984a8a','喜雪','太宗皇帝','唐','唐诗','tang','','[]','碧昏朝合霧，丹卷暝韜霞。',132,'全唐诗/poet.tang.0.json','["碧昏朝合霧，丹卷暝韜霞。", "結葉繁雲色，凝璚徧雪華。", "光樓皎若粉，映幕集疑沙。", "泛柳飛飛絮，粧梅片片花。", "照璧臺圓月，飄珠箔穿露。", "瑤潔短長階，玉藂高下樹。", "映桐珪累白，縈峰蓮抱素。", "斷續氣將沈，徘徊歲云暮。", "懷珍媿隱德，表瑞佇豐年。", "橤間飛禁苑，鶴處舞伊川。", "儻詠幽蘭曲，同懽黃竹篇。"]'),
('7be96695-a98f-43ce-a539-db885c3b0cf0','秋日斅庾信體','太宗皇帝','唐','唐诗','tang','','[]','嶺銜宵月桂，珠穿曉露叢。',60,'全唐诗/poet.tang.0.json','["嶺銜宵月桂，珠穿曉露叢。", "蟬啼覺樹冷，螢火不溫風。", "花生圓菊橤，荷盡戲魚通。", "晨浦鳴飛雁，夕渚集栖鴻。", "颯颯高天吹，氛澄下熾空。"]'),
('69f09ef2-88a4-4fd3-979d-8cfb6541eb93','賦尚書','太宗皇帝','唐','唐诗','tang','','[]','崇文時駐步，東觀還停輦。',72,'全唐诗/poet.tang.0.json','["崇文時駐步，東觀還停輦。", "輟膳翫三墳，暉燈披五典。", "寒心覩肉林，飛魄看沈湎。", "縱情昏主多，克己明君鮮。", "滅身資累惡，成名由積善。", "既承百王末，戰兢隨歲轉。"]'),
('2236d4fc-b6ec-481c-97cb-ac7609dd8382','詠司馬彪續漢志','太宗皇帝','唐','唐诗','tang','','[]','二儀初創象，三才乃分位。',264,'全唐诗/poet.tang.0.json','["二儀初創象，三才乃分位。", "非惟樹司牧，固亦垂文字。", "緜代更膺期，芳圖無輟記。", "炎漢承君道，英謨纂神器。", "潛龍既可躍，逵兔奚難致。", "前史殫妙詞，後昆沈雅思。", "書言揚盛跡，補闕興洪志。", "川谷猶舊途，郡國開新意。", "梅山未覺朽，穀水誰云異。", "車服隨名表，文物因時置。", "鳳戟翼康衢，鑾輿總柔轡。", "清濁必能澄，洪纖幸無棄。", "觀儀不失序，遵禮方由事。", "政宣竹律和，時平玉條備。", "文囿雕奇彩，藝門蘊深致。", "雲飛星共流，風揚月兼至。", "類禋遵令典，壇壝資良地。", "五勝竟無違，百司誠有庇。", "粵予承暇景，談叢引泉祕。", "討論窮義府，看覈披經笥。", "大辨良難仰，小學終先匱。", "聞道諒知榮，含毫孰忘媿。"]'),
('7d4ab8fc-aa99-46f4-8571-54af4d4666bf','詠風','太宗皇帝','唐','唐诗','tang','','[]','蕭條起關塞，搖颺下蓬瀛。',48,'全唐诗/poet.tang.0.json','["蕭條起關塞，搖颺下蓬瀛。", "拂林花亂彩，響谷鳥分聲。", "披雲羅影散，泛水織文生。", "勞歌大風曲，威加四海清。"]'),
('28968a18-20d9-4c42-91ea-98e53f9e769e','詠雨','太宗皇帝','唐','唐诗','tang','','["\u5199\u96e8", "\u96e8", "\u548f\u7269", "\u548f\u7269\u8bd7"]','罩雲飄遠岫，噴雨泛長河。',48,'全唐诗/poet.tang.0.json','["罩雲飄遠岫，噴雨泛長河。", "低飛昏嶺腹，斜足灑巖阿。", "泫叢珠締葉，起溜鏡圖波。", "濛柳添絲密，含吹織空羅。"]'),
('125c6392-6a3b-4ba2-a0af-d9520b6b7e6b','詠雪','太宗皇帝','唐','唐诗','tang','','[]','潔野凝晨曜，裝墀帶夕暉。',48,'全唐诗/poet.tang.0.json','["潔野凝晨曜，裝墀帶夕暉。", "集條分樹玉，拂浪影泉璣。", "色灑妝臺粉，花飄綺席衣。", "入扇縈離匣，點素皎殘機。"]'),
('3850fcde-577f-4a8a-8fae-3efe63b00439','賦得夏首啓節','太宗皇帝','唐','唐诗','tang','','[]','北闕三春晚，南榮九夏初。',60,'全唐诗/poet.tang.0.json','["北闕三春晚，南榮九夏初。", "黃鶯弄漸變，翠林花落餘。", "瀑流還響谷，猿啼自應虛。", "早荷向心卷，長楊就影舒。", "此時歡不極，調軫坐相於。"]'),
('e5060cf4-fac1-454f-b85e-014ec8c2870b','賦得白日半西山','太宗皇帝','唐','唐诗','tang','','[]','紅輪不暫駐，烏飛豈復停。',48,'全唐诗/poet.tang.0.json','["紅輪不暫駐，烏飛豈復停。", "岑霞漸漸落，溪陰寸寸生。", "藿葉隨光轉，葵心逐照傾。", "晚煙含樹色，棲鳥雜流聲。"]'),
('5c05f129-817c-4e03-af67-4ab13a07a172','置酒坐飛閣','太宗皇帝','唐','唐诗','tang','','[]','高軒臨碧渚，飛檐迥架空。',48,'全唐诗/poet.tang.0.json','["高軒臨碧渚，飛檐迥架空。", "餘花攢鏤檻，殘柳散雕櫳。", "岸菊初含橤，園梨始帶紅。", "莫慮崑山暗，還共盡杯中。"]'),
('403f95d9-35f0-4a0a-9570-1337546203c6','采芙蓉','太宗皇帝','唐','唐诗','tang','','[]','結伴戲方塘，攜手上雕航。',60,'全唐诗/poet.tang.0.json','["結伴戲方塘，攜手上雕航。", "船移分細浪，風散動浮香。", "遊鸎無定曲，驚鳧有亂行。", "蓮稀釧聲斷，水廣櫂歌長。", "棲烏還密樹，泛流歸建章。"]'),
('d3ab98da-082d-4117-98e1-79bc8c2635ed','賦得櫻桃','太宗皇帝','唐','唐诗','tang','','[]','華林滿芳景，洛陽徧陽春。',48,'全唐诗/poet.tang.0.json','["華林滿芳景，洛陽徧陽春。", "朱顏含遠日，翠色影長津。", "喬柯囀嬌鳥，低枝映美人。", "昔作園中實，今來席上珍。"]'),
('7cc40e68-b5bb-4af8-9a5b-5b6118881e86','賦得李','太宗皇帝','唐','唐诗','tang','','[]','玉衡流桂圃，成蹊正可尋。',48,'全唐诗/poet.tang.0.json','["玉衡流桂圃，成蹊正可尋。", "鸎啼密葉外，蝶戲脆花心。", "麗景光朝彩，輕霞散夕陰。", "暫顧暉章側，還眺靈山林。"]'),
('0c1d43ec-220c-4983-a6f9-e4e55631ad44','賦得浮橋','太宗皇帝','唐','唐诗','tang','','[]','岸曲非千里，橋斜異七星。',48,'全唐诗/poet.tang.0.json','["岸曲非千里，橋斜異七星。", "暫低逢輦度，還高值浪驚。", "水搖文鷁動，纜轉錦花縈。", "遠近隨輪影，輕重應人行。"]'),
('147b640e-e767-4dbb-8934-23c199390f9f','謁幷州大興國寺詩','太宗皇帝','唐','唐诗','tang','','[]','回鑾遊福地，極目玩芳晨。',72,'全唐诗/poet.tang.0.json','["回鑾遊福地，極目玩芳晨。", "梵鐘交二響，法日轉雙輪。", "寶剎遙承露，天花近足春。", "未佩蘭猶小，無絲柳尚新。", "圓光低月殿，碎影亂風筠。", "對此留餘想，超然離俗塵。"]'),
('ed3c7340-40dd-4581-8fa0-73f4060473ae','詠興國寺佛殿前幡','太宗皇帝','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269"]','拂霞疑電落，騰虛狀寫虹。',48,'全唐诗/poet.tang.0.json','["拂霞疑電落，騰虛狀寫虹。", "屈伸煙霧裏，低舉白雲中。", "紛披乍依迥，掣曳或隨風。", "念茲輕薄質，無翅強搖空。"]'),
('5f444f7d-1c9a-42c5-a2dd-1dda1aac432a','望送魏徵葬','太宗皇帝','唐','唐诗','tang','','[]','閶闔總金鞍，上林移玉輦。',72,'全唐诗/poet.tang.0.json','["閶闔總金鞍，上林移玉輦。", "野郊愴新別，河橋非舊餞。", "慘日映峰沈，愁雲隨蓋轉。", "哀笳時斷續，悲旌乍舒卷。", "望望情何極，浪浪淚空泫。", "無復昔時人，芳春共誰遣。"]'),
('c59e8104-e7ec-433d-ae2f-033ba7267993','傷遼東戰亡','太宗皇帝','唐','唐诗','tang','','[]','鑿門初奉律，仗戰始臨戎。',48,'全唐诗/poet.tang.0.json','["鑿門初奉律，仗戰始臨戎。", "振鱗方躍浪，騁翼正凌風。", "未展六奇術，先虧一簣功。", "防身豈乏智，殉命有餘忠。"]'),
('8f179f71-6bfa-4329-9340-2aa81745b2c6','月晦','太宗皇帝','唐','唐诗','tang','','[]','晦魄移中律，凝暄起麗城。',48,'全唐诗/poet.tang.0.json','["晦魄移中律，凝暄起麗城。", "罩雲朝蓋上，穿露曉珠呈。", "笑樹花分色，啼枝鳥合聲。", "披襟歡眺望，極目暢春情。"]'),
('fbb8a283-d6a5-4fc0-9fc3-33e422157b3f','秋日翠微宮','太宗皇帝','唐','唐诗','tang','','[]','秋光凝翠嶺，涼吹肅離宮。',48,'全唐诗/poet.tang.0.json','["秋光凝翠嶺，涼吹肅離宮。", "荷疎一蓋缺，樹冷半帷空。", "側陣移鴻影，圓花釘菊叢。", "攄懷俗塵外，高眺白雲中。"]'),
('6f0897e1-ef12-4042-8e56-8cb1134cf9c3','初秋夜坐','太宗皇帝','唐','唐诗','tang','','[]','斜廊連綺閣，初月照宵幃。',48,'全唐诗/poet.tang.0.json','["斜廊連綺閣，初月照宵幃。", "塞冷鴻飛疾，園秋蟬噪遲。", "露結林疎葉，寒輕菊吐滋。", "愁心逢此節，長歎獨含悲。"]'),
('ff2b3cb0-be10-47e9-986f-3fa62c69e727','秋日二首 一','太宗皇帝','唐','唐诗','tang','','[]','菊散金風起，荷疎玉露圓。',48,'全唐诗/poet.tang.0.json','["菊散金風起，荷疎玉露圓。", "將秋數行雁，離夏幾林蟬。", "雲凝愁半嶺，霞碎纈高天。", "還似成都望，直見峨眉前。"]'),
('731721e5-508d-452f-aaab-5b61f196de4c','秋日二首 二','太宗皇帝','唐','唐诗','tang','','[]','爽氣澄蘭沼，秋風動桂林。',48,'全唐诗/poet.tang.0.json','["爽氣澄蘭沼，秋風動桂林。", "露凝千片玉，菊散一叢金。", "日岫高低影，雲空點綴陰。", "蓬瀛不可望，泉石且娛心。"]'),
('ed13392c-ff75-46b4-923b-509cadddbc24','冬宵各爲四韻','太宗皇帝','唐','唐诗','tang','','[]','雕宮靜龍漏，綺閣宴公侯。',36,'全唐诗/poet.tang.0.json','["雕宮靜龍漏，綺閣宴公侯。", "珠簾燭燄動，繡柱月光浮。", "雲起將歌發，風停與管遒。"]'),
('c34fab35-9a2e-4bc3-82e7-e6d79c091b0b','冬日臨昆明池','太宗皇帝','唐','唐诗','tang','','[]','石鯨分玉溜，劫燼隱平沙。',48,'全唐诗/poet.tang.0.json','["石鯨分玉溜，劫燼隱平沙。", "柳影冰無葉，梅心凍有花。", "寒野凝朝霧，霜天散夕霞。", "歡情猶未極，落景遽西斜。"]'),
('c81a3a3f-0eec-4fe0-b482-40c50959b37e','望雪','太宗皇帝','唐','唐诗','tang','','["\u5199\u96ea", "\u96ea", "\u4eba\u751f", "\u611f\u6168"]','凍雲宵徧嶺，素雪曉凝華。',48,'全唐诗/poet.tang.0.json','["凍雲宵徧嶺，素雪曉凝華。", "入牖千重碎，迎風一半斜。", "不妝空散粉，無樹獨飄花。", "縈空慙夕照，破彩謝晨霞。"]'),
('95db82fe-9e50-4bc6-be79-d1c79c61ce32','守歲','太宗皇帝','唐','唐诗','tang','','["\u95f2\u9002", "\u6625\u8282"]','暮景斜芳殿，年華麗綺宮。',48,'全唐诗/poet.tang.0.json','["暮景斜芳殿，年華麗綺宮。", "寒辭去冬雪，暖帶入春風。", "階馥舒梅素，盤花卷燭紅。", "共歡新故歲，迎送一宵中。"]'),
('15fac24c-4cf1-424d-8758-511f755aa8fc','除夜','太宗皇帝','唐','唐诗','tang','','[]','歲陰窮暮紀，獻節啓新芳。',48,'全唐诗/poet.tang.0.json','["歲陰窮暮紀，獻節啓新芳。", "冬盡今宵促，年開明日長。", "冰消出鏡水，梅散入風香。", "對此歡終宴，傾壺待曙光。"]'),
('bbad458d-8996-48f7-856d-1931d49f0e2c','詠雨','太宗皇帝','唐','唐诗','tang','','["\u5199\u96e8", "\u96e8"]','和氣吹綠野，梅雨灑芳田。',48,'全唐诗/poet.tang.0.json','["和氣吹綠野，梅雨灑芳田。", "新流添舊澗，宿霧足朝煙。", "雁溼行無次，花霑色更鮮。", "對此欣登歲，披襟弄五弦。"]'),
('0c1c7765-a078-485f-9e03-f3905bc9d517','賦得含峰雲','太宗皇帝','唐','唐诗','tang','','[]','翠樓含曉霧，蓮峰帶晚雲。',48,'全唐诗/poet.tang.0.json','["翠樓含曉霧，蓮峰帶晚雲。", "玉葉依巖聚，金枝觸石分。", "橫天結陣影，逐吹起羅文。", "非復陽臺下，空將惑楚君。"]'),
('e022fa7a-ae8e-49c2-9369-f9d286b972e2','三層閣上置音聲','太宗皇帝','唐','唐诗','tang','','[]','綺筵移暮景，紫閣引宵煙。',48,'全唐诗/poet.tang.0.json','["綺筵移暮景，紫閣引宵煙。", "隔棟歌塵合，分階舞影連。", "聲流三處管，響亂一重絃。", "不似秦樓上，吹簫空學仙。"]'),
('1fcbff48-e228-417c-bb6d-79979dddc1b2','遠山澄碧霧','太宗皇帝','唐','唐诗','tang','','[]','殘雲收翠嶺，夕霧結長空。',48,'全唐诗/poet.tang.0.json','["殘雲收翠嶺，夕霧結長空。", "帶岫凝全碧，障霞隱半紅。", "髣髴分初月，飄颻度曉風。", "還因三里處，冠蓋遠相通。"]'),
('53cabac3-3558-4bcb-8845-9ebe1c3eb562','賦得花庭霧','太宗皇帝','唐','唐诗','tang','','[]','蘭氣已熏宮，新橤半粧叢。',48,'全唐诗/poet.tang.0.json','["蘭氣已熏宮，新橤半粧叢。", "色含輕重霧，香引去來風。", "拂樹濃舒碧，縈花薄蔽紅。", "還當雜行雨，髣髴隱遙空。"]'),
('2bfd3472-5aea-48b4-ae78-6c030ef4e64f','春池柳','太宗皇帝','唐','唐诗','tang','','[]','年柳變池臺，隋堤曲直回。',48,'全唐诗/poet.tang.0.json','["年柳變池臺，隋堤曲直回。", "逐浪絲陰去，迎風帶影來。", "疎黃一鳥弄，半翠幾眉開。", "縈雪臨春岸，參差間早梅。"]'),
('5a422f68-ee50-4809-a6f7-e1ef510e51a5','芳蘭','太宗皇帝','唐','唐诗','tang','','[]','春暉開紫苑，淑景媚蘭場。',48,'全唐诗/poet.tang.0.json','["春暉開紫苑，淑景媚蘭場。", "映庭含淺色，凝露泫浮光。", "日麗參差影，風傳輕重香。", "會須君子折，佩裏作芬芳。"]'),
('8098529a-3316-4f89-a17f-6e6a2ce52d59','詠桃','太宗皇帝','唐','唐诗','tang','','[]','禁苑春暉麗，花蹊綺樹妝。',48,'全唐诗/poet.tang.0.json','["禁苑春暉麗，花蹊綺樹妝。", "綴條深淺色，點露參差光。", "向日分千笑，迎風共一香。", "如何仙嶺側，獨秀隱遙芳。"]'),
('48bb657b-455d-4dd1-a38a-4312d39968fd','賦簾','太宗皇帝','唐','唐诗','tang','','[]','參差垂玉闕，舒卷映蘭宮。',48,'全唐诗/poet.tang.0.json','["參差垂玉闕，舒卷映蘭宮。", "珠光搖素月，竹影亂清風。", "彩散銀鉤上，文斜桂戶中。", "惟當雜羅綺，相與媚房櫳。"]'),
('2b4fdd33-abbc-4c1b-a33e-4e786e544865','詠烏代陳師道','太宗皇帝','唐','唐诗','tang','','[]','凌晨麗城去，薄暮上林棲。',48,'全唐诗/poet.tang.0.json','["凌晨麗城去，薄暮上林棲。", "辭枝枝暫起，停樹樹還低。", "向日終難託，迎風詎肯迷。", "只待纖纖手，曲裏作宵啼。"]'),
('aab2f610-6652-486f-bbc7-034366eb35a4','詠飲馬','太宗皇帝','唐','唐诗','tang','','[]','駿骨飲長涇，奔流灑絡纓。',48,'全唐诗/poet.tang.0.json','["駿骨飲長涇，奔流灑絡纓。", "細紋連噴聚，亂荇繞蹄縈。", "水光鞍上側，馬影溜中橫。", "翻似天池裏，騰波龍種生。"]'),
('4e85cb66-dc1d-42b5-9f64-c5a19b4e9fed','賦得殘菊','太宗皇帝','唐','唐诗','tang','','[]','階蘭凝曙霜，岸菊照晨光。',48,'全唐诗/poet.tang.0.json','["階蘭凝曙霜，岸菊照晨光。", "露濃晞晚笑，風勁淺殘香。", "細葉凋輕翠，圓花飛碎黃。", "還持今歲色，復結後年芳。"]'),
('c23bb21b-7230-4256-b5e2-dbed22360c2e','賦秋日懸清光賜房玄齡','太宗皇帝','唐','唐诗','tang','','[]','秋露凝高掌，朝光上翠微。',60,'全唐诗/poet.tang.0.json','["秋露凝高掌，朝光上翠微。", "參差麗雙闕，照耀滿重闈。", "仙馭隨輪轉，靈烏帶影飛。", "臨波無定彩，入隙有圓暉。", "還當葵藿志，傾葉自相依。"]'),
('c5629da4-989d-4af5-a5e8-db1a6aaa8e6f','琵琶','太宗皇帝','唐','唐诗','tang','','[]','半月無雙影，全花有四時。',60,'全唐诗/poet.tang.0.json','["半月無雙影，全花有四時。", "摧藏千里態，掩抑幾重悲。", "促節縈紅袖，清音滿翠帷。", "駛彈風響急，緩曲釧聲遲。", "空餘關隴恨，因此代相思。"]'),
('d7c51477-e08e-4f2e-ba3b-361807bbecea','宴中山','太宗皇帝','唐','唐诗','tang','','[]','驅馬出遼陽，萬里轉旂常。',72,'全唐诗/poet.tang.0.json','["驅馬出遼陽，萬里轉旂常。", "對敵六奇舉，臨戎八陣張。", "斬鯨澄碧海，卷霧掃扶桑。", "昔去蘭縈翠，今來桂染芳。", "雲芝浮碎葉，冰鏡上朝光。", "回首長安道，方歡宴柏梁。"]'),
('8c6e81ed-cfe2-4900-aa3b-9d44ef7f1bea','餞中書侍郎來濟','太宗皇帝','唐','唐诗','tang','','[]','曖曖去塵昏灞岸，飛飛輕蓋指河梁。',64,'全唐诗/poet.tang.0.json','["曖曖去塵昏灞岸，飛飛輕蓋指河梁。", "雲峰衣結千重葉，雪岫花開幾樹妝。", "深悲黃鶴孤舟遠，獨歎青山別路長。", "聊將分袂霑巾淚，還用持添離席觴。"]'),
('7822c305-f1b3-4ed3-8011-f69dca0e965a','於太原召侍臣賜宴守歲','太宗皇帝','唐','唐诗','tang','','[]','四時運灰琯，一夕變冬春。',24,'全唐诗/poet.tang.0.json','["四時運灰琯，一夕變冬春。", "送寒餘雪盡，迎歲早梅新。"]'),
('e4ea593e-ab38-4278-9d9b-ea23e30b3421','詠燭二首 一','太宗皇帝','唐','唐诗','tang','','[]','燄聽風來動，花開不待春。',24,'全唐诗/poet.tang.0.json','["燄聽風來動，花開不待春。", "鎮下千行淚，非是爲思人。"]'),
('c3fd8880-154d-479b-a852-c5f31ad5463e','詠燭二首 二','太宗皇帝','唐','唐诗','tang','','[]','九龍蟠燄動，四照逐花生。',24,'全唐诗/poet.tang.0.json','["九龍蟠燄動，四照逐花生。", "即此流高殿，堪持待月明。"]'),
('3f79db59-87f2-4b64-9605-be330724d4de','詠弓','太宗皇帝','唐','唐诗','tang','','[]','上弦明月半，激箭流星遠。',24,'全唐诗/poet.tang.0.json','["上弦明月半，激箭流星遠。", "落雁帶書驚，啼猿映枝轉。"]'),
('c353940d-4bbc-4420-83bf-07cb4606d35f','賦得早雁出雲鳴','太宗皇帝','唐','唐诗','tang','','[]','初秋玉露清，早雁出空鳴。',24,'全唐诗/poet.tang.0.json','["初秋玉露清，早雁出空鳴。", "隔雲時亂影，因風乍含聲。"]'),
('02e00858-8361-4f48-9e95-d0353a54ab49','賦得臨池柳','太宗皇帝','唐','唐诗','tang','','[]','岸曲絲陰聚，波移帶影疎。',24,'全唐诗/poet.tang.0.json','["岸曲絲陰聚，波移帶影疎。", "還將眉裏翠，來就鏡中舒。"]'),
('d340ad23-8f26-4ee8-9873-8b044a6f158b','賦得臨池竹','太宗皇帝','唐','唐诗','tang','','[]','貞條障曲砌，翠葉貫寒霜。',24,'全唐诗/poet.tang.0.json','["貞條障曲砌，翠葉貫寒霜。", "拂牖分龍影，臨池待鳳翔。"]'),
('487805d3-fe67-46d9-912d-29587a2cb1c5','賦得弱柳鳴秋蟬','太宗皇帝','唐','唐诗','tang','','[]','散影玉階柳，含翠隱鳴蟬。',24,'全唐诗/poet.tang.0.json','["散影玉階柳，含翠隱鳴蟬。", "微形藏葉裏，亂響出風前。"]'),
('edabeb38-248a-4bc6-a4f3-5dcdf340729c','探得李','太宗皇帝','唐','唐诗','tang','','[]','盤根直盈渚，交幹橫倚天。',24,'全唐诗/poet.tang.0.json','["盤根直盈渚，交幹橫倚天。", "舒華光四海，卷葉蔭三川。"]'),
('cbeb0337-1af4-4987-87a7-34bb9e79d812','詠小山','太宗皇帝','唐','唐诗','tang','','[]','近谷交縈橤，遙峰對出蓮。',24,'全唐诗/poet.tang.0.json','["近谷交縈橤，遙峰對出蓮。", "徑細無全磴，松小未含煙。"]'),
('5737750c-bf61-45a3-b38e-44bd6038b425','賜蕭瑀','太宗皇帝','唐','唐诗','tang','','["\u54f2\u7406", "\u542f\u793a"]','疾風知勁草，板蕩識誠臣。',24,'全唐诗/poet.tang.0.json','["疾風知勁草，板蕩識誠臣。", "勇夫安識義，智者必懷仁。"]'),
('291dd1f7-f61e-42b0-bb46-a8b28f9a8ffd','賜房玄齡','太宗皇帝','唐','唐诗','tang','','["\u8d5e\u9882", "\u5199\u4eba", "\u5199\u4eba\u8bd7"]','太液仙舟迥，西園隱上才。',24,'全唐诗/poet.tang.0.json','["太液仙舟迥，西園隱上才。", "未曉征車度，雞鳴關早開。"]'),
('297cc055-e94c-41a9-bdfb-2cbfef8cae83','遼東山夜臨秋','太宗皇帝','唐','唐诗','tang','','[]','煙生遙岸隱，月落半崖陰。',24,'全唐诗/poet.tang.0.json','["煙生遙岸隱，月落半崖陰。", "連山驚鳥亂，隔岫斷猿吟。"]'),
('8fcbec86-3e3e-4250-ae58-47b567af7e8e','賜魏徵詩','太宗皇帝','唐','唐诗','tang','','[]','醽醁勝蘭生，翠濤過玉䪥。',24,'全唐诗/poet.tang.0.json','["醽醁勝蘭生，翠濤過玉䪥。", "千日醉不醒，十年味不敗。"]'),
('bf2685a1-fc35-4238-87ee-9f27fd58432a','兩儀殿賦柏梁體','太宗皇帝','唐','唐诗','tang','','[]','絕域降附天下平，八表無事悅聖情。',40,'全唐诗/poet.tang.0.json','["絕域降附天下平，八表無事悅聖情。", "雲披霧斂天地明，登封日觀禪云亭。", "太常具禮方告成。"]'),
('861c1378-8568-4606-8e50-e0b54d194c5e','句','太宗皇帝','唐','唐诗','tang','','[]','雪恥酬百王，除兇報千古。',35,'全唐诗/poet.tang.0.json','["雪恥酬百王，除兇報千古。", "昔乘匹馬去，今驅萬乘來。", "近日毛雖暖聞弦心已驚。"]'),
('f99f99d1-0379-4ce5-a570-90e6b5db19b4','太子納妃太平公主出降','高宗皇帝','唐','唐诗','tang','','[]','龍樓光曙景，魯館啓朝扉。',144,'全唐诗/poet.tang.0.json','["龍樓光曙景，魯館啓朝扉。", "豔日濃妝影，低星降婺輝。", "玉庭浮瑞色，銀牓藻祥徽。", "雲轉花縈蓋，霞飄葉綴旂。", "雕軒回翠陌，寶駕歸丹殿。", "鳴珠佩曉衣，鏤璧輪開扇。", "華冠列綺筵，蘭醑申芳宴。", "環階鳳樂陳，玳席珍羞薦。", "蝶舞袖香新，歌分落素塵。", "歡凝歡懿戚，慶叶慶初姻。", "暑闌炎氣息，涼早吹疎頻。", "方期六合泰，共賞萬年春。"]'),
('f971131c-5b36-4888-9f4e-6e9410adf659','七夕宴懸圃二首 一','高宗皇帝','唐','唐诗','tang','','[]','羽蓋飛天漢，鳳駕越層巒。',48,'全唐诗/poet.tang.0.json','["羽蓋飛天漢，鳳駕越層巒。", "俱歎三秋阻，共敍一宵歡。", "璜虧夜月落，靨碎曉星殘。", "誰能重操杼，纖手濯清瀾。"]'),
('792e7017-3954-4a3b-a167-e183f17ca707','七夕宴懸圃二首 二','高宗皇帝','唐','唐诗','tang','','[]','霓裳轉雲路，鳳駕儼天潢。',48,'全唐诗/poet.tang.0.json','["霓裳轉雲路，鳳駕儼天潢。", "虧星凋夜靨，殘月落朝璜。", "促歡今夕促，長離別後長。", "輕梭聊駐織，掩淚獨悲傷。"]'),
('ca84f1d3-1494-4add-a44d-6ccd8f6484a2','過溫湯','高宗皇帝','唐','唐诗','tang','','[]','溫渚停仙蹕，豐郊駐曉旌。',60,'全唐诗/poet.tang.0.json','["溫渚停仙蹕，豐郊駐曉旌。", "路曲迴輸影，巖虛傳漏聲。", "暖溜驚湍駛，寒空碧霧輕。", "林黃疎葉下，野白曙霜明。", "眺聽良無已，煙霞斷續生。"]'),
('694314d7-c1d5-4b3b-9e0d-b355697cced3','九月九日','高宗皇帝','唐','唐诗','tang','','[]','端居臨玉扆，初律啓金商。',108,'全唐诗/poet.tang.0.json','["端居臨玉扆，初律啓金商。", "鳳闕澄秋色，龍闈引夕涼。", "野淨山氣斂，林疎風露長。", "砌蘭虧半影，巖桂發全香。", "滿蓋荷凋翠，圓花菊散黃。", "揮鞭爭電烈，飛羽亂星光。", "柳空穿石碎，弦虛側月張。", "怯猿啼落岫，驚雁斷分行。", "斜輪低夕景，歸斾擁通莊。"]'),
('2f442360-9ecd-40ad-9b97-8afef21e2a85','謁慈恩寺題奘法師房','高宗皇帝','唐','唐诗','tang','','[]','停軒觀福殿，遊目眺皇畿。',60,'全唐诗/poet.tang.0.json','["停軒觀福殿，遊目眺皇畿。", "法輪含日轉，花蓋接雲飛。", "翠煙香綺閣，丹霞光寶衣。", "幡虹遙合彩，定水迥分暉。", "蕭然登十地，自得會三歸。"]'),
('7a91f55d-4f60-45b4-b9e2-36ddfd8ac342','謁大慈恩寺','高宗皇帝','唐','唐诗','tang','','[]','日宮開萬仞，月殿聳千尋。',48,'全唐诗/poet.tang.0.json','["日宮開萬仞，月殿聳千尋。", "花蓋飛團影，幡虹曳曲陰。", "綺霞遙籠帳，叢珠細網林。", "寥廓煙雲表，超然物外心。"]'),
('527b27aa-af81-41ed-b7f4-31c4eb7bb57f','守歲','高宗皇帝','唐','唐诗','tang','','[]','今宵冬律盡，來朝麗景新。',60,'全唐诗/poet.tang.0.json','["今宵冬律盡，來朝麗景新。", "花餘凝地雪，條含煖吹分。", "綬吐芽猶嫩，冰□已鏤津。", "薄紅梅色冷，淺綠柳輕春。", "送迎交兩節，暄寒變一辰。"]'),
('589c213c-6793-4ba6-b0d8-ef674ea4a544','咸亨殿宴近臣諸親柏梁體','高宗皇帝','唐','唐诗','tang','','[]','屏欲除奢政返淳。',8,'全唐诗/poet.tang.0.json','["屏欲除奢政返淳。"]'),
('103a8266-2d76-413d-9cde-e32f15f47d4c','九月九日幸臨渭亭登高得秋字','中宗皇帝','唐','唐诗','tang','','[]','九月正乘秋，三杯興已周。',36,'全唐诗/poet.tang.0.json','["九月正乘秋，三杯興已周。", "泛桂迎尊滿，吹花向酒浮。", "長房萸早熟，彭澤菊初收。"]'),
('c4305274-656b-4379-a658-eed9909fbaa2','登驪山高頂寓目','中宗皇帝','唐','唐诗','tang','','[]','四郊秦漢國，八水帝王都。',48,'全唐诗/poet.tang.0.json','["四郊秦漢國，八水帝王都。", "閶闔雄里閈，城闕壯規模。", "貫渭稱天邑，含岐實奧區。", "金門披玉館，因此識皇圖。"]'),
('651e8254-c709-49e8-86fd-0153306ff555','幸秦始皇陵','中宗皇帝','唐','唐诗','tang','','[]','眷言君失德，驪邑想秦餘。',48,'全唐诗/poet.tang.0.json','["眷言君失德，驪邑想秦餘。", "政煩方改篆，愚俗乃焚書。", "阿房久已滅，閣道遂成墟。", "欲厭東南氣，翻傷掩鮑車。"]'),
('2fe88983-0ad0-490b-b08a-8c359af920a3','立春日遊苑迎春','中宗皇帝','唐','唐诗','tang','','[]','神皐福地三秦邑，玉臺金闕九仙家。',64,'全唐诗/poet.tang.0.json','["神皐福地三秦邑，玉臺金闕九仙家。", "寒光猶戀甘泉樹，淑景偏臨建始花。", "綵蝶黃鸎未歌舞，梅香柳色已矜誇。", "迎春正啓流霞席，暫囑曦輪勿遽斜。"]'),
('49359d18-613c-4aa0-8836-e2253b88d772','十月誕辰內殿宴羣臣效柏梁體聯句','中宗皇帝','唐','唐诗','tang','','[]','潤色鴻業寄賢才，叨居右弼媿鹽梅。',128,'全唐诗/poet.tang.0.json','["潤色鴻業寄賢才，叨居右弼媿鹽梅。", "運籌帷幄荷時來，職掌圖籍濫蓬萊。", "兩司謬忝謝鍾裴，禮樂銓管效涓埃。", "陳師振旅清九垓，欣承顧問侍天杯。", "銜恩獻壽梁柏臺，黃縑青簡奉康哉。", "鯫生侍從忝王枚，右掖司言實不才。", "宗伯秩禮天地開，帝歌難續仰昭回。", "微臣捧日變寒灰，遠慙班左媿遊陪。"]'),
('19a60c13-e4f4-4653-8262-70e474cc636a','景龍四年正月五日移仗蓬萊宮御大明殿會吐蕃騎馬之戲因重爲柏梁體聯句','中宗皇帝','唐','唐诗','tang','','[]','大明御宇臨萬方，顧慙內政翊陶唐。',112,'全唐诗/poet.tang.0.json','["大明御宇臨萬方，顧慙內政翊陶唐。", "鸞鳴鳳舞向平陽，秦樓魯館沐恩光。", "無心爲子輒求郎，雄才七步謝陳王。", "當熊讓輦媿前芳，再司銓筦恩可忘。", "文江學海思濟航，萬邦考績臣所詳。", "著作不休出中腸，權豪屏迹肅嚴霜。", "鑄鼎開岳造明堂，玉醴由來獻壽觴。"]'),
('3da0d066-be3c-427c-ad15-5b6c38d3ccf6','石淙','中宗皇帝','唐','唐诗','tang','','[]','三陽本是標靈紀，二室由來獨擅名。',64,'全唐诗/poet.tang.0.json','["三陽本是標靈紀，二室由來獨擅名。", "霞衣霞錦千般狀，雲峰雲岫百重生。", "水炫珠光遇泉客，巖懸石鏡厭山精。", "永願乾坤符睿算，長居膝下屬歡情。"]'),
('b8c1489d-d98c-49bc-a2f6-6d8449664e26','石淙','睿宗皇帝','唐','唐诗','tang','','[]','奇峰嶾嶙箕山北，秀崿岹嶢嵩鎮南。',64,'全唐诗/poet.tang.0.json','["奇峰嶾嶙箕山北，秀崿岹嶢嵩鎮南。", "地首地肺何曾擬，天目天台倍覺慙。", "樹影蒙蘢鄣疊岫，波深洶湧落懸潭。", "□願紫宸居得一，永欣丹扆御通三。"]'),
('d0337427-89fa-44ca-8f08-6f989572feb6','過晉陽宮','明皇帝','唐','唐诗','tang','','[]','緬想封唐處，實惟建國初。',144,'全唐诗/poet.tang.0.json','["緬想封唐處，實惟建國初。", "俯察伊晉野，仰觀乃參虛。", "井邑龍斯躍，城池鳳翔餘。", "林塘猶沛澤，臺榭宛舊居。", "運革祚中否，時遷命茲符。", "顧循承丕構，怵惕多憂虞。", "尚恐威不逮，復慮化未孚。", "豈徒勞轍迹，所期訓戎車。", "習俗問黎人，親巡慰里閭。", "永言念成功，頌德臨康衢。", "長懷經綸日，歎息履庭隅。", "艱難安可忘，欲去良踟躕。"]'),
('2aaa788e-05f6-4bdf-acb9-773e3a5fa4d9','行次成皋途經先聖擒建德之所緬思功業感而賦詩','明皇帝','唐','唐诗','tang','','[]','有隋政昏虐，羣雄已交爭。',72,'全唐诗/poet.tang.0.json','["有隋政昏虐，羣雄已交爭。", "先聖按劒起，叱咤風雲生。", "飲馬河洛竭，作氣嵩華驚。", "克敵睿圖就，擒俘帝道亨。", "顧慙嗣寶曆，恭承天下平。", "幸過翦鯨地，感慕神且英。"]'),
('8a2266dd-ed4e-4168-8464-ec32d966daaa','校獵義成喜逢大雪率題九韻以示羣官','明皇帝','唐','唐诗','tang','','[]','弧矢威天下，旌旗遊近縣。',108,'全唐诗/poet.tang.0.json','["弧矢威天下，旌旗遊近縣。", "一面施鳥羅，三驅教人戰。", "暮雲成積雪，曉色開行殿。", "皓然原隰同，不覺林野變。", "北風勇士馬，東日華組練。", "觸地銀麞出，連山縞鹿見。", "月兔落高矰，星狼下急箭。", "既欣盈尺兆，復憶磻谿便。", "歲豐將遇賢，俱荷皇天眷。"]'),
('66f00c11-e79e-4fe8-9890-1679f17a2dae','賜諸州刺史以題座右','明皇帝','唐','唐诗','tang','','[]','眷言思共理，鑑夢想維良。',120,'全唐诗/poet.tang.0.json','["眷言思共理，鑑夢想維良。", "猗歟此推擇，聲績著周行。", "賢能既俟進，黎獻實佇康。", "視人當如子，愛人亦如傷。", "講學試誦論，阡陌勸耕桑。", "虛譽不可飾，清知不可忘。", "求名迹易見，安貞德自彰。", "訟獄必以情，教民貴有常。", "恤惸且存老，撫弱復綏強。", "勉哉各祗命，知予眷萬方。"]'),
('b792850c-9098-4cd8-821c-6a8a303ae01a','送忠州太守康昭遠等','明皇帝','唐','唐诗','tang','','[]','端拱臨中樞，緬懷共予理。',84,'全唐诗/poet.tang.0.json','["端拱臨中樞，緬懷共予理。", "不有臺閣英，孰振循良美。", "分符侯甸內，拜手明庭裏。", "誓節期飲冰，調人方導水。", "嘉聲馳九牧，惠化光千祀。", "時雨侔昔賢，芳猷貫前史。", "佇爾頌中和，吾將令卿士。"]'),
('a492586e-5029-4c46-8d6e-1915e18b9d3a','送李邕之任滑臺','明皇帝','唐','唐诗','tang','','[]','漢家重東郡，宛彼白馬津。',48,'全唐诗/poet.tang.0.json','["漢家重東郡，宛彼白馬津。", "黎庶既蕃殖，臨之勞近臣。", "遠別初首路，今行方及春。", "課成應第一，良牧爾當仁。"]'),
('8784b5fa-245f-4a1f-acc1-ca891154180e','端午三殿宴羣臣探得神字','明皇帝','唐','唐诗','tang','','[]','五月符天數，五音調夏鈞。',84,'全唐诗/poet.tang.0.json','["五月符天數，五音調夏鈞。", "舊來傳五日，無事不稱神。", "穴枕通靈氣，長絲續命人。", "四時花競巧，九子糉爭新。", "方殿臨華節，圓宮宴雅臣。", "進對一言重，遒文六義陳。", "股肱良足詠，風化可還淳。"]'),
('305ed419-7cad-4659-b393-9b52aafa375f','溫湯對雪','明皇帝','唐','唐诗','tang','','[]','北風吹同雲，同雲飛白雪。',48,'全唐诗/poet.tang.0.json','["北風吹同雲，同雲飛白雪。", "白雪乍迴散，同雲何慘烈。", "未見溫泉冰，寧知火井滅。", "表瑞良在茲，庶幾可怡悅。"]'),
('3fff5496-d24c-48c6-9c61-0d8925b663fe','登蒲州逍遙樓','明皇帝','唐','唐诗','tang','','["\u9ec4\u6cb3"]','長榆息烽火，高柳靜風塵。',72,'全唐诗/poet.tang.0.json','["長榆息烽火，高柳靜風塵。", "卜征巡九洛，展豫出三秦。", "昔是潛龍地，今爲上理辰。", "時平乘道泰，聊賞遇年春。", "黃河分地絡，飛觀接天津。", "一覽遺芳翰，千載肅如神。"]'),
('1669d597-4c37-4897-b5f8-a15eedd8cdf0','經河上公廟','明皇帝','唐','唐诗','tang','','[]','昔聞有耆叟，河上獨遺榮。',72,'全唐诗/poet.tang.0.json','["昔聞有耆叟，河上獨遺榮。", "跡與塵嚻隔，心將道德幷。", "詎以天地累，寧爲寵辱驚。", "矯然翔寥廓，如何屈堅貞。", "玄玄妙門啓，肅肅祠宇清。", "冥漠無先後，那能紀姓名。"]'),
('6ae53f2c-48fa-464c-8453-de7b2434c716','過王濬暮','明皇帝','唐','唐诗','tang','','[]','吳國分牛斗，晉室命龍驤。',72,'全唐诗/poet.tang.0.json','["吳國分牛斗，晉室命龍驤。", "受任敵已滅，策勳名不彰。", "居美未盡善，矜功徒自傷。", "長戟今何在？孤墳此路傍。", "不觀松柏茂，空餘荆棘場。", "歎嗟懸劒隴，誰識夢刀祥。"]'),
('f4b72624-5f7c-4885-940b-5c1812023ead','初入秦川路逢寒食','明皇帝','唐','唐诗','tang','','[]','洛陽芳樹映天津，灞岸垂楊窣地新。',160,'全唐诗/poet.tang.0.json','["洛陽芳樹映天津，灞岸垂楊窣地新。", "直爲經過行處樂，不知虛度兩京春。", "去年餘閏今春早，曙色和風著花草。", "可憐寒食與清明，光輝幷在長安道。", "自從關路入秦川，爭道何人不戲鞭。", "公子途中妨蹴踘，佳人馬上廢鞦韆。", "渭水長橋今欲渡，蔥蔥漸見新豐樹。", "遠看驪岫入雲霄，預想湯池起煙霧。", "煙霧氛氳水殿開，暫拂香輪歸去來。", "今歲清明行已晚，明年寒食更相陪。"]'),
('2465f80e-c739-41c6-b446-80aa00bed183','春臺望','明皇帝','唐','唐诗','tang','','[]','暇景屬三春，高臺聊四望。',204,'全唐诗/poet.tang.0.json','["暇景屬三春，高臺聊四望。", "目極千里際，山川一何壯。", "太華見重巖，終南分疊嶂。", "郊原紛綺錯，參差多異狀。", "佳氣滿通溝，遲步入綺樓。", "初鸎一一鳴紅樹，歸雁雙雙去綠洲。", "太液池中下黃鶴，昆明水上映牽牛。", "聞道漢家全盛日，別館離宮趣非一。", "甘泉逶迤亘明光，五柞連延接未央。", "周廬徼道縱橫轉，飛閣迴軒左右長。", "須念作勞居者逸，勿言我後焉能恤。", "爲想雄豪壯柏梁，何如儉陋卑茅室。", "陽烏黯黯向山沈，夕鳥喧喧入上林。", "薄暮賞餘回步輦，還念中人罷百金。"]'),
('71c6c90b-67c3-451e-9463-23cd78cb05aa','過大哥宅探得歌字韻','明皇帝','唐','唐诗','tang','','[]','魯衛情先重，親賢愛轉多。',48,'全唐诗/poet.tang.0.json','["魯衛情先重，親賢愛轉多。", "冕旒豐暇日，乘景暫經過。", "戚里申高宴，平臺奏雅歌。", "復尋爲善樂，方驗保山河。"]'),
('31f91bce-39c0-4eb6-b905-c344eb337ecf','同玉真公主過大哥山池','明皇帝','唐','唐诗','tang','','[]','地有招賢處，人傳樂善名。',48,'全唐诗/poet.tang.0.json','["地有招賢處，人傳樂善名。", "鶩池臨九達，龍岫對層城。", "桂月先秋冷，蘋風向晚清。", "鳳樓遙可見，彷彿玉簫聲。"]'),
('a1824eb8-4e2e-4d53-9a33-e1dcfe7d1c73','經鄒魯祭孔子而歎之','明皇帝','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4f24\u6000", "\u5199\u4eba", "\u4e94\u8a00\u5f8b\u8bd7"]','夫子何爲者？栖栖一代中。',48,'全唐诗/poet.tang.0.json','["夫子何爲者？栖栖一代中。", "地猶鄹氏邑，宅即魯王宮。", "歎鳳嗟身否，傷麟怨道窮。", "今看兩楹奠，當與夢時同。"]'),
('ed5ce508-2df4-4ef2-a6a0-5b8586766d6f','惟此溫泉是稱愈疾豈予獨受其福思與兆人共之乘暇巡遊乃言其志','明皇帝','唐','唐诗','tang','','[]','桂殿與山連，蘭湯湧自然。',48,'全唐诗/poet.tang.0.json','["桂殿與山連，蘭湯湧自然。", "陰崖含秀色，溫谷吐潺湲。", "績爲蠲邪著，功因養正宣。", "願言將億兆，同此共昌延。"]'),
('09b3b3e9-1c6d-4c01-a400-da5d81367407','旋師喜捷','明皇帝','唐','唐诗','tang','','[]','邊服胡塵起，長安漢將飛。',48,'全唐诗/poet.tang.0.json','["邊服胡塵起，長安漢將飛。", "龍蛇開陣法，貔虎振軍威。", "詐虜腦塗地，征夫血染衣。", "今朝書奏入，明日凱歌歸。"]'),
('e850ef1a-ddc7-4d29-a946-5fa8f1b32d7b','過老子廟','明皇帝','唐','唐诗','tang','','[]','仙居懷聖德，靈廟肅神心。',48,'全唐诗/poet.tang.0.json','["仙居懷聖德，靈廟肅神心。", "草合人蹤斷，塵濃鳥跡深。", "流沙丹竈沒，關路紫煙沈。", "獨傷千載後，空餘松柏林。"]'),
('5675d954-3da8-4071-be97-da4c66f4675a','途次陝州','明皇帝','唐','唐诗','tang','','[]','境出三秦外，途分二陝中。',48,'全唐诗/poet.tang.0.json','["境出三秦外，途分二陝中。", "山川入虞虢，風俗限西東。", "樹古棠陰在，耕餘讓畔空。", "鳴笳從此去，行見洛陽宮。"]'),
('1cdf7e65-ec12-41de-9474-7ff1eeacd5f3','野次喜雪','明皇帝','唐','唐诗','tang','','[]','拂曙闢行宮，寒皋野望通。',48,'全唐诗/poet.tang.0.json','["拂曙闢行宮，寒皋野望通。", "繁雲低遠岫，飛雪舞長空。", "賦象恆依物，縈迴屢逐風。", "爲知勤恤意，先此示年豐。"]'),
('535734bd-4603-4944-a44b-0f3ff9ee4da4','送賀知章歸四明','明皇帝','唐','唐诗','tang','','[]','遺榮期入道，辭老竟抽簪。',48,'全唐诗/poet.tang.0.json','["遺榮期入道，辭老竟抽簪。", "豈不惜賢達，其如高尚心。", "寰中得祕要，方外散幽襟。", "獨有青門餞，羣僚悵別深。"]'),
('d3737773-2dc5-436c-aa3e-39f324aaef16','軒遊宮十五夜','明皇帝','唐','唐诗','tang','','[]','行邁離秦國，巡方赴洛師。',48,'全唐诗/poet.tang.0.json','["行邁離秦國，巡方赴洛師。", "路逢三五夜，春色暗中期。", "關外長河轉，宮中淑氣遲。", "歌鐘對明月，不減舊遊時。"]'),
('3fe183cd-7771-4bb4-81d1-0d3ee507c647','觀拔河俗戲','明皇帝','唐','唐诗','tang','','[]','壯徒恆賈勇，拔拒抵長河。',48,'全唐诗/poet.tang.0.json','["壯徒恆賈勇，拔拒抵長河。", "欲練英雄志，須明勝負多。", "譟齊山岌嶪，氣作水騰波。", "預期年歲稔，先此樂時和。"]'),
('865bf66e-c1ad-4fee-8ab0-45876065155a','同劉晃喜雨','明皇帝','唐','唐诗','tang','','[]','節變寒初盡，時和氣已春。',48,'全唐诗/poet.tang.0.json','["節變寒初盡，時和氣已春。", "繁雲先合寸，膏雨自依旬。", "颯颯飛平野，霏霏靜暗塵。", "懸知花葉意，朝夕望中新。"]'),
('fe3a7358-9350-44e1-b04d-637ed5425b50','千秋節賜羣臣鏡','明皇帝','唐','唐诗','tang','','[]','鑄得千秋鏡，光生百鍊金。',48,'全唐诗/poet.tang.0.json','["鑄得千秋鏡，光生百鍊金。", "分將賜羣后，遇象見清心。", "臺上冰華澈，窗中月影臨。", "更銜長綬帶，留意感人深。"]'),
('612c3100-a4ee-4478-87d3-6499a58a4430','賜道士鄧紫陽','明皇帝','唐','唐诗','tang','','[]','太乙三門訣，元君六甲符。',48,'全唐诗/poet.tang.0.json','["太乙三門訣，元君六甲符。", "下傳金版術，上刻玉清書。", "有美探真士，囊中得祕書。", "自知三醮後，翊我滅殘胡。"]'),
('1373b7fb-a34d-468f-8bc3-127bce69027e','幸蜀西至劒門','明皇帝','唐','唐诗','tang','','[]','劒閣橫雲峻，鑾輿出狩回。',48,'全唐诗/poet.tang.0.json','["劒閣橫雲峻，鑾輿出狩回。", "翠屏千仞合，丹嶂五丁開。", "灌木縈旗轉，仙雲拂馬來。", "乘時方在德，嗟爾勒銘才。"]'),
('1ea9b354-24bc-497a-a8fb-0e83e0a00c9f','答司馬承禎上劒鏡','明皇帝','唐','唐诗','tang','','[]','寶照含天地，神劒合陰陽。',48,'全唐诗/poet.tang.0.json','["寶照含天地，神劒合陰陽。", "日月麗光景，星斗裁文章。", "寫鑑表容質，佩服爲身防。", "從茲一賞玩，永德保齡長。"]'),
('d9cf7b72-41cc-4e86-a5ff-b3b142fc2f1f','送趙法師還蜀因名山奠簡','明皇帝','唐','唐诗','tang','','[]','道家奠靈簡，自昔仰神仙。',48,'全唐诗/poet.tang.0.json','["道家奠靈簡，自昔仰神仙。", "真子今將命，蒼生福可傳。", "江山尋故國，城郭信依然。", "二室遙相望，雲回洞裏天。"]'),
('1fec324a-a88c-4c65-ab64-8c6fda63294c','送道士薛季昌還山','明皇帝','唐','唐诗','tang','','[]','洞府修真客，衡陽念舊居。',48,'全唐诗/poet.tang.0.json','["洞府修真客，衡陽念舊居。", "將成金闕要，願奉玉清書。", "雲路三天近，松溪萬籟虛。", "猶期傳祕訣，來往候仙輿。"]'),
('3175be79-7852-4d21-ae00-6e99046947d5','送玄同真人李抱朴謁灊山仙祠','明皇帝','唐','唐诗','tang','','[]','城闕天中近，蓬瀛海上遙。',48,'全唐诗/poet.tang.0.json','["城闕天中近，蓬瀛海上遙。", "歸期千載鶴，春至一來朝。", "采藥逢三秀，餐霞臥九霄。", "參同如有旨，金鼎待君燒。"]'),
('b69a61f7-c412-4d23-9f4d-e33115184411','春日出苑遊矚','明皇帝','唐','唐诗','tang','','[]','三陽麗景早芳辰，四序佳園物候新。',64,'全唐诗/poet.tang.0.json','["三陽麗景早芳辰，四序佳園物候新。", "梅花百樹障去路，垂柳千條暗回津。", "鳥飛直爲驚風葉，魚沒都由怯岸人。", "惟願聖主南山壽，何愁不賞萬年春。"]'),
('83a52b39-32c7-4394-b619-3ede125ed7fd','春晚宴兩相及禮官麗正殿學士探得風字','明皇帝','唐','唐诗','tang','','[]','乾道運無窮，恆將人代工。',72,'全唐诗/poet.tang.0.json','["乾道運無窮，恆將人代工。", "陰陽調曆象，禮樂報玄穹。", "介胄清荒外，衣冠佐域中。", "言談延國輔，詞賦引文雄。", "野霽伊川綠，郊明鞏樹紅。", "冕旒多暇景，詩酒會春風。"]'),
('9a42f0ea-06a9-4bb4-a71a-f4ba0485cb5f','首夏花萼樓觀羣臣宴寧王山亭回樓下又申之以賞樂賦詩','明皇帝','唐','唐诗','tang','','[]','今年通閏月，入夏展春輝。',72,'全唐诗/poet.tang.0.json','["今年通閏月，入夏展春輝。", "樓下風光晚，城隅宴賞歸。", "九歌揚政要，六舞散朝衣。", "天喜時相合，人和事不違。", "禮中推意厚，樂處感心微。", "別賞陽臺樂，前旬暮雨飛。"]'),
('4db72c93-5036-478a-8ce9-bf6f87469198','同二相已下羣官樂遊園宴','明皇帝','唐','唐诗','tang','','[]','撰日巖廊暇，需雲宴樂初。',72,'全唐诗/poet.tang.0.json','["撰日巖廊暇，需雲宴樂初。", "萬方朝玉帛，千品會簪裾。", "地入南山近，城分北斗餘。", "池塘垂柳密，原隰野花疎。", "帟幕看逾暗，歌鐘聽自虛。", "興闌歸騎轉，還奏弼違書。"]'),
('40b8cae3-f68b-4e8a-ad5f-fc33d8644185','集賢書院成送張說上集賢學士賜宴得珍字','明皇帝','唐','唐诗','tang','','[]','廣學開書院，崇儒引席珍。',72,'全唐诗/poet.tang.0.json','["廣學開書院，崇儒引席珍。", "集賢招衮職，論道命台臣。", "禮樂沿今古，文章革舊新。", "獻酬尊俎列，賓主位班陳。", "節變雲初夏，時移氣尚春。", "所希光史冊，千載仰茲晨。"]'),
('1f894b7c-19a6-43d2-9f59-2fdc76cf6579','王屋山送道士司馬承禎還天台','明皇帝','唐','唐诗','tang','','[]','紫府求賢士，清谿祖逸人。',72,'全唐诗/poet.tang.0.json','["紫府求賢士，清谿祖逸人。", "江湖與城闕，異跡且殊倫。", "間有幽棲者，居然厭俗塵。", "林泉先得性，芝桂欲調神。", "地道踰稽嶺，天台接海濱。", "音徽從此間，萬古一芳春。"]'),
('099ccd32-ce26-4dd2-83e8-da38093c303f','早度蒲津關','明皇帝','唐','唐诗','tang','','[]','鐘鼓嚴更曙，山河野望通。',72,'全唐诗/poet.tang.0.json','["鐘鼓嚴更曙，山河野望通。", "鳴鑾下蒲坂，飛斾入秦中。", "地險關逾壯，天平鎮尚雄。", "春來津樹合，月落戍樓空。", "馬色分朝景，雞聲逐曉風。", "所希常道泰，非復候繻同。"]'),
('dedf14b9-362c-435a-b206-bdccc02811e3','途經華嶽','明皇帝','唐','唐诗','tang','','["\u534e\u5c71"]','飭駕去京邑，鳴鸞指洛川。',72,'全唐诗/poet.tang.0.json','["飭駕去京邑，鳴鸞指洛川。", "循途經太華，回蹕暫周旋。", "翠崿留斜影，懸巖冒夕煙。", "四方皆石壁，五位配金天。", "彷彿看高掌，依稀聽子先。", "終當銘歲月，從此記靈仙。"]'),
('20bfd036-c115-4eef-9a08-927a697c870c','喜雪','明皇帝','唐','唐诗','tang','','[]','日觀卜先征，時巡順物情。',72,'全唐诗/poet.tang.0.json','["日觀卜先征，時巡順物情。", "風行未備禮，雲密遽飄霙。", "委樹寒花發，縈空落絮輕。", "朝如玉已會，庭似月猶明。", "既覩膚先合，還欣尺有盈。", "登封何以報？因此謝功成。"]'),
('9b49d25c-69a8-49d2-926c-203141e28410','幸鳳泉湯','明皇帝','唐','唐诗','tang','','[]','西狩觀周俗，南山歷漢宮。',72,'全唐诗/poet.tang.0.json','["西狩觀周俗，南山歷漢宮。", "薦鮮知路近，省斂覺年豐。", "陰谷含神爨，湯泉養聖功。", "益齡仙井合，愈疾醴源通。", "不重鳴岐鳳，誰矜陳寶雄。", "願將無限澤，霑沐衆心同。"]'),
('d5ff7429-35fd-4f63-9e75-f4cfd9f750c2','南出雀鼠谷答張說','明皇帝','唐','唐诗','tang','','[]','雷出應乾象，風行順國人。',72,'全唐诗/poet.tang.0.json','["雷出應乾象，風行順國人。", "川途猶在晉，車馬漸歸秦。", "背陝關山險，橫汾鼓吹頻。", "草依陽谷變，花待北巖春。", "聞有鵷鸞客，清詞雅調新。", "求音思欲報，心跡竟難陳。"]'),
('f4c46b77-4c2d-456e-bf07-3414a6ff0d5f','賜崔日知往潞州','明皇帝','唐','唐诗','tang','','[]','潞國開新府，壺關寵舊林。',72,'全唐诗/poet.tang.0.json','["潞國開新府，壺關寵舊林。", "妙旌循吏德，持悅庶氓心。", "禮樂中朝貴，神明列郡欽。", "揚風非贈扇，易俗是張琴。", "藩鎮謳謠滿，行宮雨露深。", "會書丞相策，先賜潁川金。"]'),
('5c02660f-f015-42fb-85be-a7a1420add8d','爲趙法師別造精院過院賦詩','明皇帝','唐','唐诗','tang','','[]','宗師心物外，爲道運虛舟。',72,'全唐诗/poet.tang.0.json','["宗師心物外，爲道運虛舟。", "不戀巖泉賞，來從宮禁遊。", "探玄知幾歲，習靜更宜秋。", "煙樹辨朝色，風湍聞夜流。", "坐朝繁聽覽，尋勝在清幽。", "欲廣無爲化，因茲庶可求。"]'),
('6ac93ab8-f32b-49b6-8f72-938e414c9cca','端午','明皇帝','唐','唐诗','tang','','["\u7aef\u5348\u8282"]','端午臨中夏，時清日復長。',72,'全唐诗/poet.tang.0.json','["端午臨中夏，時清日復長。", "鹽梅已佐鼎，麯糵且傳觴。", "事古人留迹，年深縷積長。", "當軒知槿茂，向水覺蘆香。", "億兆同歸壽，羣公共保昌。", "忠貞如不替，貽厥後昆芳。"]'),
('7afe8f0f-5f85-4b83-a957-e3bfa0a29587','春中興慶宮酺宴','明皇帝','唐','唐诗','tang','','[]','九達長安道，三陽別館春。',96,'全唐诗/poet.tang.0.json','["九達長安道，三陽別館春。", "還將聽朝暇，回作豫遊晨。", "不戰要荒服，無刑禮樂新。", "合酺覃土宇，歡宴接羣臣。", "玉斝飛千日，瓊筵薦八珍。", "舞衣雲曳影，歌扇月開輪。", "伐鼓魚龍雜，撞鐘角觝陳。", "曲終酣興晚，須有醉歸人。"]'),
('746656b4-b41f-4ef8-ad6d-02a30edc5fc5','千秋節宴','明皇帝','唐','唐诗','tang','','[]','蘭殿千秋節，稱名萬壽觴。',96,'全唐诗/poet.tang.0.json','["蘭殿千秋節，稱名萬壽觴。", "風傳率土慶，日表繼天祥。", "玉宇開花蕚，宮縣動會昌。", "衣冠白鷺下，帟幕翠雲長。", "獻遺成新俗，朝儀入舊章。", "月銜花綬鏡，露綴綵絲囊。", "處處祠田祖，年年宴杖鄉。", "深思一德事，小獲萬人康。"]'),
('d1ba29c5-333c-4b5d-978f-d5bfdf29a89b','左丞相說右丞相璟太子少傅乾曜同日上官命宴東堂賜詩','明皇帝','唐','唐诗','tang','','[]','赤帝收三傑，黃軒舉二臣。',96,'全唐诗/poet.tang.0.json','["赤帝收三傑，黃軒舉二臣。", "由來丞相重，分掌國之鈞。", "我有握中璧，雙飛席上珍。", "子房推道要，仲子訝風神。", "復輟台衡老，將爲調護人。", "鵷鸞同拜日，車騎擁行塵。", "樂聚南宮宴，觴連北斗醇。", "俾予成百揆，垂拱問彝倫。"]'),
('5b721d41-b555-48ff-8c1d-c81104498e39','早登太行山中言志','明皇帝','唐','唐诗','tang','','[]','清蹕度河陽，凝笳上太行。',84,'全唐诗/poet.tang.0.json','["清蹕度河陽，凝笳上太行。", "火龍明鳥道，鐵騎繞羊腸。", "白霧埋陰壑，丹霞助曉光。", "澗泉含宿凍，山木帶餘霜。", "野老茅爲屋，樵人薜作裳。", "宣風問耆艾，敦俗勸耕桑。", "涼德慙先哲，徽猷慕昔皇。"]'),
('4d6d713f-e241-4cc9-b332-733225339044','平胡','明皇帝','唐','唐诗','tang','','[]','雜虜忽猖狂，無何敢亂常。',96,'全唐诗/poet.tang.0.json','["雜虜忽猖狂，無何敢亂常。", "羽書朝繼入，烽火夜相望。", "將出凶門勇，兵因死地強。", "蒙輪皆突騎，按劒盡鷹揚。", "鼓角雄山野，龍蛇入戰場。", "流膏潤沙漠，濺血染鋒鋩。", "霧掃清玄塞，雲開靜朔方。", "武功今已立，文德愧前王。"]'),
('dcaab812-5769-4667-b564-92fcd3180956','遊興慶宮作','明皇帝','唐','唐诗','tang','','[]','代邸青門右，離宮紫陌陲。',120,'全唐诗/poet.tang.0.json','["代邸青門右，離宮紫陌陲。", "庭如過沛日，水若渡江時。", "綺觀連雞岫，朱樓接雁池。", "從來敦棣蕚，今此茂荆枝。", "萬葉傳餘慶，千年志不移。", "凭軒聊屬目，輕輦共追隨。", "務本方崇訓，相輝保羽儀。", "時康俗易漸，德薄政難施。", "鼓吹迎飛蓋，弦歌送羽巵。", "所希覃率土，孝弟一同規。"]'),
('1748c5bc-f20c-42f0-87e2-b7b78fce31cb','送張說巡邊','明皇帝','唐','唐诗','tang','','[]','端拱復垂裳，長懷御遠方。',120,'全唐诗/poet.tang.0.json','["端拱復垂裳，長懷御遠方。", "股肱申教義，戈劒靖要荒。", "命將綏邊服，雄圖出廟堂。", "三台入武帳，八座起文昌。", "寶胄匡韓主，華宗輔漢王。", "茂先慙博物，平子謝文章。", "盡節恢時佐，輸誠禦寇場。", "三軍臨朔野，駟馬即戎行。", "鼓吹威夷狄，旌軒溢洛陽。", "雲臺先著美，今日更貽芳。"]'),
('99dbd2f9-5430-4250-8073-6925811afb72','餞王晙巡邊','明皇帝','唐','唐诗','tang','','[]','振武威荒服，揚文肅遠墟。',120,'全唐诗/poet.tang.0.json','["振武威荒服，揚文肅遠墟。", "金壇申將禮，玉節授軍符。", "免胄三方外，銜刀萬里餘。", "昔時吳會靜，今日虜庭虛。", "分閫仍推轂，援桴且訓車。", "風揚旌斾遠，雨洗甲兵初。", "坐見台階謐，行聞祅祲除。", "檄來雖插羽，箭去亦飛書。", "舟檝功須著，鹽梅望匪疎。", "不應陳七德，欲使化先敷。"]'),
('e3e09dbc-9565-4d64-a1e3-92f22726430f','巡省途次上黨舊宮賦','明皇帝','唐','唐诗','tang','','[]','三千初擊浪，九萬欲摶空。',144,'全唐诗/poet.tang.0.json','["三千初擊浪，九萬欲摶空。", "天地猶驚否，陰陽始遇蒙。", "存貞期歷試，佐貳佇昭融。", "多謝時康理，良慙實賴功。", "長懷問鼎氣，夙負拔山雄。", "不學劉琨舞，先歌漢祖風。", "英髦既包括，豪傑自牢籠。", "人事一朝異，謳歌四海同。", "如何昔朱邸，今此作離宮？", "雁沼澄瀾翠，猿巖落照紅。", "小山秋桂馥，長坂舊蘭叢。", "即是淹留處，乘歡樂未窮。"]'),
('cabdbd9c-d957-4881-aff2-479d08c3c583','潼關口號','明皇帝','唐','唐诗','tang','','[]','河曲回千里，關門限二京。',24,'全唐诗/poet.tang.0.json','["河曲回千里，關門限二京。", "所嗟非恃德，設險到天平。"]'),
('275ae461-9263-47e1-8a47-d477e519c3a9','千秋節賜羣臣鏡','明皇帝','唐','唐诗','tang','','[]','瑞露垂花綬，寒冰澈寶輸。',24,'全唐诗/poet.tang.0.json','["瑞露垂花綬，寒冰澈寶輸。", "對茲臺上月，聊以慶佳辰。"]'),
('c4567287-ed9d-4ae9-b24a-69740afc9222','續薛令之題壁','明皇帝','唐','唐诗','tang','','[]','啄木觜距長，鳳皇羽毛短。',24,'全唐诗/poet.tang.0.json','["啄木觜距長，鳳皇羽毛短。", "苦嫌松桂寒，任逐桑榆煖。"]'),
('adfebde8-4ae5-47f8-9cd6-536c584fb6f6','送胡真師還西山','明皇帝','唐','唐诗','tang','','[]','仙客厭人間，孤雲比性閒。',24,'全唐诗/poet.tang.0.json','["仙客厭人間，孤雲比性閒。", "話離情未已，煙水萬重山。"]'),
('66f8c48a-f6c8-4247-9863-4ee9d832b202','過大哥山池題石壁','明皇帝','唐','唐诗','tang','','[]','澄潭皎鏡石崔巍，萬壑千巖暗綠苔。',32,'全唐诗/poet.tang.0.json','["澄潭皎鏡石崔巍，萬壑千巖暗綠苔。", "林亭自有幽貞趣，況復秋深爽氣來。"]'),
('1b0a3511-24ee-414c-a93f-b561d791f545','題梅妃畫真','明皇帝','唐','唐诗','tang','','[]','憶昔嬌妃在紫宸，鉛華不御得天真。',32,'全唐诗/poet.tang.0.json','["憶昔嬌妃在紫宸，鉛華不御得天真。", "霜綃雖似當時態，爭奈嬌波不顧人。"]'),
('e455ec15-d04b-4797-8a01-da7fa5a5c367','鶺鴒頌','明皇帝','唐','唐诗','tang','','[]','伊我軒宮，奇樹青葱。',165,'全唐诗/poet.tang.0.json','["伊我軒宮，奇樹青葱。", "藹周廬兮，冒霜停雪，以茂以悅。", "恣卷舒兮，連枝同榮，吐綠含英。", "曜春初兮，蓐收御節，寒露微結。", "氣清虛兮，桂宮蘭殿，唯所息宴。", "棲雍渠兮，行搖飛鳴，急難有情。", "情有餘兮，顧惟德涼，夙夜兢惶。", "慙化疎兮，上之所教，下之所效。", "實在予兮，天倫之性，魯衛分政。", "親賢居兮，爰遊爰處，爰笑爰語。", "巡庭除兮，觀此翔禽，以悅我心，良史書兮。"]'),
('c7cf9007-f2af-4954-a355-045c9589a7a8','傀儡吟','明皇帝','唐','唐诗','tang','','[]','刻木牽絲作老翁，雞皮鶴髮與真同。',32,'全唐诗/poet.tang.0.json','["刻木牽絲作老翁，雞皮鶴髮與真同。", "須臾弄罷寂無事，還似人生一夢中。"]'),
('63e5f845-6aac-4453-9bc0-23b81643aebd','句','明皇帝','唐','唐诗','tang','','[]','昔見漳濱臥，言將人事違。',48,'全唐诗/poet.tang.0.json','["昔見漳濱臥，言將人事違。", "今逢慶誕日，猶謂學仙歸。", "棠棣花重發，鴒原鳥再飛。", "德比代雲布，心如晉水清。"]'),
('8390b439-f7e4-42c1-b6c7-cdf9d9480f57','延英殿玉靈芝詩三章章八句 一','肅宗皇帝','唐','唐诗','tang','','[]','玉殿肅肅，靈芝煌煌。',30,'全唐诗/poet.tang.0.json','["玉殿肅肅，靈芝煌煌。", "重英發秀，連葉分房。", "宗廟之福，垂其耿光。"]'),
('247aeb58-ca1c-46e4-8bf3-81c400f0ec8a','延英殿玉靈芝詩三章章八句 二','肅宗皇帝','唐','唐诗','tang','','[]','元氣產芝，明神合德。',40,'全唐诗/poet.tang.0.json','["元氣產芝，明神合德。", "紫微間采，白蕣呈色。", "載啓瑞圖，庶符皇極。", "天心有眷，王道惟直。"]'),
('a4b77a86-2d4a-4e4b-815e-cd6e7d4b127a','延英殿玉靈芝詩三章章八句 三','肅宗皇帝','唐','唐诗','tang','','[]','幸生芳本，當我扆旒。',40,'全唐诗/poet.tang.0.json','["幸生芳本，當我扆旒。", "效此靈質，賁其王猷。", "神惟不愛，道亦無求。", "端拱思惟，永荷天休。"]'),
('3120b8ba-bc2b-40a0-a768-8aeef43eee6b','賜棃李泌與諸王聯句','肅宗皇帝','唐','唐诗','tang','','[]','先生年幾許，顏色似童兒。',48,'全唐诗/poet.tang.0.json','["先生年幾許，顏色似童兒。", "夜抱九仙骨，朝披一品衣。", "不食千鍾粟，唯餐兩顆棃。", "天生此間氣，助我化無爲。"]'),
('2ba2c561-9752-49e3-9575-b1b3d935ab05','中和節日宴百僚賜詩','德宗皇帝','唐','唐诗','tang','','[]','韶年啓仲序，初吉諧良辰。',72,'全唐诗/poet.tang.0.json','["韶年啓仲序，初吉諧良辰。", "肇茲中和節，式慶天地春。", "歡酣朝野同，生德區宇均。", "雲開灑膏露，草疏芳河津。", "歲華今載陽，東作方肆勤。", "慙非熏風唱，曷用慰吾人。"]'),
('cac5a624-4332-4200-9b3d-735cb790e16d','中和節賜百官燕集因示所懷','德宗皇帝','唐','唐诗','tang','','[]','至化恆在宥，保和茲息人。',72,'全唐诗/poet.tang.0.json','["至化恆在宥，保和茲息人。", "推誠撫諸夏，與物長爲春。", "仲月風景暖，禁城花柳新。", "芳時協金奏，賜宴同羣臣。", "絲竹豈云樂，忠賢惟所親。", "庶洽朝野意，曠然天地均。"]'),
('b0fbc276-8bbc-4f26-a0e9-efc8696f9351','重陽日賜宴曲江亭賦六韻詩用清字','德宗皇帝','唐','唐诗','tang','','[]','早衣對庭燎，躬化勤意誠。',72,'全唐诗/poet.tang.0.json','["早衣對庭燎，躬化勤意誠。", "時此萬機暇，適與佳節幷。", "曲池潔寒流，芳菊舒金英。", "乾坤爽氣滿，臺殿秋光清。", "朝野慶年豐，高會多歡聲。", "永懷無荒戒，良士同斯情。"]'),
('0aaa5f00-4541-4d06-a915-0e71b2306c98','九月十八賜百僚追賞因書所懷','德宗皇帝','唐','唐诗','tang','','[]','雨霽霜氣肅，天高雲日明。',72,'全唐诗/poet.tang.0.json','["雨霽霜氣肅，天高雲日明。", "繁林已墜葉，寒菊仍舒榮。", "懿此秋節時，更延追賞情。", "池臺列廣宴，絲竹傳新聲。", "至樂非外獎，浹歡同中誠。", "庶敦朝野意，永使風化清。"]'),
('73f35093-8a40-44ba-ba98-6b4457303408','送徐州張建封還鎮','德宗皇帝','唐','唐诗','tang','','[]','牧守寄所重，才賢生爲時。',96,'全唐诗/poet.tang.0.json','["牧守寄所重，才賢生爲時。", "宣風自淮甸，授鉞膺藩維。", "入覲展遐戀，臨軒慰來思。", "忠誠在方寸，感激陳情詞。", "報國爾所向，恤人予是資。", "歡宴不盡懷，車馬當還期。", "穀雨將應候，行春猶未遲。", "勿以千里遙，而云無己知。"]'),
('ac02826d-1549-4338-83cc-a58238ea737d','麟德殿宴百僚','德宗皇帝','唐','唐诗','tang','','[]','憂勤承聖緒，開泰喜時康。',72,'全唐诗/poet.tang.0.json','["憂勤承聖緒，開泰喜時康。", "恭己臨羣后，垂衣御八荒。", "務閑春向暮，朝罷日猶長。", "紫殿初筵列，彤庭廣樂張。", "成功歸輔弼，致理賴忠良。", "共此歡娛事，千秋樂未央。"]'),
('f7f2b9e3-e7c6-4049-84d1-2a585f98c4a2','元日退朝觀軍仗歸營','德宗皇帝','唐','唐诗','tang','','[]','獻歲視元朔，萬方咸在庭。',96,'全唐诗/poet.tang.0.json','["獻歲視元朔，萬方咸在庭。", "端旒揖羣后，回輦閱師貞。", "綵仗宿華殿，退朝歸禁營。", "分行左右出，轉斾風雲生。", "歷歷趨複道，容容映層城。", "勇餘矜捷技，令肅無喧聲。", "眷此戎旅節，載嘉良士誠。", "順時傾宴賞，亦以助文經。"]'),
('9f07ad1d-8a95-4e2f-984d-b2f35a057ca6','中和節賜羣臣宴賦七韻','德宗皇帝','唐','唐诗','tang','','[]','東風變梅柳，萬彙生春光。',84,'全唐诗/poet.tang.0.json','["東風變梅柳，萬彙生春光。", "中和紀月令，方與天地長。", "耽樂豈予尚，懿茲時景良。", "庶遂亭育恩，同致寰海康。", "君臣永終始，交泰符陰陽。", "曲沼水新碧，華林桃稍芳。", "勝賞信多歡，戒之在無荒。"]'),
('7fa19519-78a9-494b-b6f2-2a22a48ba3f3','三日書懷因示百僚','德宗皇帝','唐','唐诗','tang','','[]','佳節上元巳，芳時屬暮春。',72,'全唐诗/poet.tang.0.json','["佳節上元巳，芳時屬暮春。", "流觴想蘭亭，捧劒得金人。", "風輕水初綠，日晴花更新。", "天文信昭回，皇道頗敷陳。", "恭己每從儉，清心常保真。", "戒茲游衍樂，書以示羣臣。"]'),
('26bda590-69ee-4667-88e4-07e217c0ebaf','重陽日中外同歡以詩言志因示羣官','德宗皇帝','唐','唐诗','tang','','[]','[爽]節在重九，物華新雨餘。',86,'全唐诗/poet.tang.0.json','["[爽]節在重九，物華新雨餘。", "清秋黃葉下，菊散金潭初。", "萬實行就稔，百工欣所如。", "歡心暢遐邇，殊俗同車書。", "至化自敦睦，佳辰宜宴胥。", "鏘鏘間絲竹，濟濟羅簪裾。", "此樂匪足耽，此誠期永孚。"]'),
('ea2b7e59-3d59-4f78-ac87-e06e9526950b','重陽日即事','德宗皇帝','唐','唐诗','tang','','[]','令節曉澄霽，四郊煙靄空。',72,'全唐诗/poet.tang.0.json','["令節曉澄霽，四郊煙靄空。", "天清白露潔，菊散黃金叢。", "寡德荷天貺，順時休百工。", "豈懷歌鐘樂，思爲君臣同。", "至化在亭育，相成資始終。", "未知康衢詠，所仰惟年豐。"]'),
('776916a8-bf58-4662-9596-e233239efdec','豐年多慶九日示懷','德宗皇帝','唐','唐诗','tang','','[]','爽氣肅時令，早衣聞朔鴻。',72,'全唐诗/poet.tang.0.json','["爽氣肅時令，早衣聞朔鴻。", "重陽有佳節，具物欣年豐。", "皎潔暮潭色，芬敷新菊叢。", "芳尊滿衢室，繁吹凝煙空。", "惠合信吾道，保和惟爾同。", "推誠至玄化，天下期爲公。"]'),
('5197293d-6d7e-48f7-9387-f992e9c3a2ee','七月十五日題章敬寺','德宗皇帝','唐','唐诗','tang','','[]','招提邇皇邑，複道連重城。',108,'全唐诗/poet.tang.0.json','["招提邇皇邑，複道連重城。", "法筵會早秋，駕言訪禪扃。", "嘗聞大仙教，清淨宗無生。", "七物匪吾寶，萬行先求成。", "名相既雙寂，繁華奚所榮。", "金風扇微涼，遠煙凝翠晶。", "松院靜苔色，竹房深磬聲。", "境幽真慮恬，道勝外物輕。", "意適本非說，含毫空復情。"]'),
('88f88d70-f0cb-4250-8926-4d31d42abc44','中春麟德殿會百僚觀新樂詩一章章十六句','德宗皇帝','唐','唐诗','tang','','[]','芳歲肇佳節，物華當仲春。',96,'全唐诗/poet.tang.0.json','["芳歲肇佳節，物華當仲春。", "乾坤既昭泰，煙景含氤氳。", "德淺荷玄貺，樂成思治人。", "前庭列鐘鼓，廣殿延羣臣。", "八卦隨舞意，五音轉曲新。", "顧非咸池奏，庶協南風熏。", "式宴禮所重，浹歡情必均。", "同和諒在茲，萬國希可親。"]'),
('f1b0eaa8-b5f7-4fd4-8431-2cb0bb304f54','九日絕句','德宗皇帝','唐','唐诗','tang','','[]','禁苑秋來爽氣多，昆明風動起滄波。',32,'全唐诗/poet.tang.0.json','["禁苑秋來爽氣多，昆明風動起滄波。", "中流簫鼓誠堪賞，詎假橫汾發櫂歌。"]'),
('30cd14b3-98fd-4a64-b57f-6d2cc05f52d9','暮春喜雨詩','文宗皇帝','唐','唐诗','tang','','[]','風雲喜際會，雷雨遂流滋。',72,'全唐诗/poet.tang.0.json','["風雲喜際會，雷雨遂流滋。", "薦幣虛陳禮，動天實精思。", "漸侵九夏節，復在三春時。", "霢霂垂朱闕，飄颻入綠墀。", "郊坰既霑足，黍稷有豐期。", "百辟同康樂，萬方佇雍熙。"]'),
('6a0d85ba-b322-48e5-8dbc-4ce3f6efac5e','題程修己竹障','文宗皇帝','唐','唐诗','tang','','[]','良工運精思，巧極似有神。',28,'全唐诗/poet.tang.0.json','["良工運精思，巧極似有神。", "臨窗忽覩繁陰合，再盼真假殊未分。"]'),
('534288d0-412e-44e5-aff6-b38879e01cd8','宮中題','文宗皇帝','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f", "\u82e6\u95f7"]','輦路生春草，上林花發時。',24,'全唐诗/poet.tang.0.json','["輦路生春草，上林花發時。", "憑高何限意，無復侍臣知。"]'),
('9b99f129-4039-41f1-b8db-b12d21035fc2','上巳日賜裴度','文宗皇帝','唐','唐诗','tang','','[]','注想待元老，識君恨不早。',24,'全唐诗/poet.tang.0.json','["注想待元老，識君恨不早。", "我家柱石衰，憂來學丘禱。"]'),
('6edbac82-339f-45d9-908d-89dd67f941e5','上元日二首 一','文宗皇帝','唐','唐诗','tang','','[]','上元高會集羣仙，心齋何事欲祈年。',32,'全唐诗/poet.tang.0.json','["上元高會集羣仙，心齋何事欲祈年。", "丹誠儻徹玉帝座，且共吾人慶大田。"]'),
('78b979f0-9d59-4905-ae9a-5ba2445d0cf8','上元日二首 二','文宗皇帝','唐','唐诗','tang','','[]','蓂生三五葉初齊，上元羽客出桃蹊。',32,'全唐诗/poet.tang.0.json','["蓂生三五葉初齊，上元羽客出桃蹊。", "不愛仙家登真訣，願蒙四海福黔黎。"]'),
('078cc610-552e-4224-8413-3dda0ac3c0f5','夏日聯句','文宗皇帝','唐','唐诗','tang','','[]','人皆苦炎熱，我愛夏日長。',24,'全唐诗/poet.tang.0.json','["人皆苦炎熱，我愛夏日長。", "熏風自南來，殿閣生微涼。"]'),
('3cc12092-e338-458d-a730-5ee07b08d888','百丈山','宣宗皇帝','唐','唐诗','tang','','[]','大雄真跡枕危巒，梵宇層樓聳萬般。',64,'全唐诗/poet.tang.0.json','["大雄真跡枕危巒，梵宇層樓聳萬般。", "日月每從肩上過，山河長在掌中看。", "仙峰不間三春秀，靈境何時六月寒？", "更有上方人罕到，暮鐘朝磬碧雲端。"]'),
('f129bf81-4ca2-41c1-912e-4348dfb7956e','弔白居易','宣宗皇帝','唐','唐诗','tang','','["\u60bc\u4ea1"]','綴玉聯珠六十年，誰教冥路作詩仙。',68,'全唐诗/poet.tang.0.json','["綴玉聯珠六十年，誰教冥路作詩仙。", "浮雲不繫名居易，造化無爲字樂天。", "童子解吟《長恨曲》，胡兒能唱《琵琶篇》。", "文章已滿行人耳，一度思卿一愴然。"]'),
('dbc8ea5e-53eb-4a81-b9af-5a7db544fb1c','幸華嚴寺','宣宗皇帝','唐','唐诗','tang','','[]','雲散晴山幾萬重，煙收春色更沖融。',64,'全唐诗/poet.tang.0.json','["雲散晴山幾萬重，煙收春色更沖融。", "帳殿出空登碧漢，遐川俯望色藍籠。", "林光入戶低韶景，嶺氣通宵展霽風。", "今日追遊何所似，莫慙漢武賞汾中。"]'),
('afecb511-1ff4-415f-ba1b-4a6136513d17','重陽錫宴羣臣','宣宗皇帝','唐','唐诗','tang','','[]','款塞旋征騎，和戎委廟賢。',24,'全唐诗/poet.tang.0.json','["款塞旋征騎，和戎委廟賢。", "傾心方倚注，叶力共安邊。"]'),
('9abf192a-34e2-410d-addc-68171f00c3f0','題涇縣水西寺','宣宗皇帝','唐','唐诗','tang','','[]','大殿連雲接爽溪，鐘聲還與鼓聲齊。',32,'全唐诗/poet.tang.0.json','["大殿連雲接爽溪，鐘聲還與鼓聲齊。", "長安若問江南事，說道風光在水西。"]'),
('79b4be2b-65d5-412f-82ed-48d8b804fabc','瀑布聯句','宣宗皇帝','唐','唐诗','tang','','[]','千巖萬壑不辭勞，遠看方知出處高。',32,'全唐诗/poet.tang.0.json','["千巖萬壑不辭勞，遠看方知出處高。", "溪澗豈能留得住，終歸大海作波濤。"]'),
('8ffd7a8b-f55f-4dff-955f-d3a95fc5abfb','句','宣宗皇帝','唐','唐诗','tang','','[]','海岳宴咸通，七載秉鈞調四序。',22,'全唐诗/poet.tang.0.json','["海岳宴咸通，七載秉鈞調四序。", "一方獄市獲來蘇。"]'),
('c0413c53-4729-431f-ae31-51ba5902dfe7','詠雷句','昭宗皇帝','唐','唐诗','tang','','[]','只解劈牛兼劈樹，不能誅惡與誅兇。',16,'全唐诗/poet.tang.0.json','["只解劈牛兼劈樹，不能誅惡與誅兇。"]'),
('a25186df-0de3-49e6-81f2-2cc5c0853b43','春遊曲','文德皇后','唐','唐诗','tang','','[]','上苑桃花朝日明，蘭閨豔妾動春情。',64,'全唐诗/poet.tang.0.json','["上苑桃花朝日明，蘭閨豔妾動春情。", "井上新桃偷面色，檐邊嫩柳學身輕。", "花中來去看舞蝶，樹上長短聽啼鶯。", "林下何須遠借問，出衆風流舊有名。"]'),
('623de378-ac00-4dec-99c2-10e4668ff7ce','曳鼎歌','則天皇后','唐','唐诗','tang','','[]','羲農首出，軒昊膺期。',40,'全唐诗/poet.tang.0.json','["羲農首出，軒昊膺期。", "唐虞繼踵，湯禹乘時。", "天下光宅，海內雍熙。", "上玄降鑒，方建隆基。"]'),
('23c871de-760f-4030-a5f2-3abe14c67d01','唐享昊天樂 第一','則天皇后','唐','唐诗','tang','','[]','太陰凝至化，真耀蘊軒儀。',38,'全唐诗/poet.tang.0.json','["太陰凝至化，真耀蘊軒儀。", "德邁娥臺敞，仁高[姒]幄披。", "捫天遂啓極，夢日乃昇曦。"]'),
('d3715888-a6cc-4332-b3fe-d8fa4a2f27be','唐享昊天樂 第二','則天皇后','唐','唐诗','tang','','[]','瞻紫極，望玄穹。',32,'全唐诗/poet.tang.0.json','["瞻紫極，望玄穹。", "翹至懇，罄深衷。", "聽雖遠，誠必通。", "垂厚澤，降雲宮。"]'),
('1644c7db-cc77-421d-a0bb-beed6030406e','唐享昊天樂 第三','則天皇后','唐','唐诗','tang','','[]','乾儀混成沖邃，天道下濟高明。',56,'全唐诗/poet.tang.0.json','["乾儀混成沖邃，天道下濟高明。", "闓陽晨披紫闕，太一曉降黃庭。", "圜壇敢申昭報，方璧冀展虔情。", "丹襟式敷衷懇，玄鑒庶察微誠。"]'),
('fab579bd-1352-4182-94b7-884e42c83bc4','唐享昊天樂 第四','則天皇后','唐','唐诗','tang','','[]','巍巍叡業廣，赫赫聖基隆。',60,'全唐诗/poet.tang.0.json','["巍巍叡業廣，赫赫聖基隆。", "菲德承先顧，禎符萃眇躬。", "銘開武巖側，圖薦洛川中。", "微誠詎幽感，景命忽昭融。", "有懷慙紫極，無以謝玄穹。"]'),
('2ceac26c-7518-4ff2-994d-106b88c860e3','唐享昊天樂 第五','則天皇后','唐','唐诗','tang','','[]','朝壇霧卷，曙嶺煙沈。',40,'全唐诗/poet.tang.0.json','["朝壇霧卷，曙嶺煙沈。", "爰設筐幣，式表誠心。", "筵輝麗璧，樂暢和音。", "仰惟靈鑒，俯察翹襟。"]'),
('9c638cf2-866e-4573-aadf-ea5aaf6da04e','唐享昊天樂 第六','則天皇后','唐','唐诗','tang','','[]','昭昭上帝，穆穆下臨。',40,'全唐诗/poet.tang.0.json','["昭昭上帝，穆穆下臨。", "禮崇備物，樂奏鏘金。", "蘭羞委薦，桂醑盈斟。", "敢希明德，幸罄莊心。"]'),
('3e5a7471-21a3-42f3-91ea-51700910fbb3','唐享昊天樂 第七','則天皇后','唐','唐诗','tang','','[]','尊浮九醞，禮備三周。',20,'全唐诗/poet.tang.0.json','["尊浮九醞，禮備三周。", "陳誠菲奠，契福神猷。"]'),
('a0704ea2-1e40-4d08-ba3e-0ec7e73169ee','唐享昊天樂 第八','則天皇后','唐','唐诗','tang','','[]','奠璧郊壇昭大禮，鏘金拊石表虔誠。',32,'全唐诗/poet.tang.0.json','["奠璧郊壇昭大禮，鏘金拊石表虔誠。", "始奏承雲娛帝賞，復歌調露暢韶英。"]'),
('20970cd3-7041-486e-b7b5-3ec719f181b3','唐享昊天樂 第九','則天皇后','唐','唐诗','tang','','[]','荷恩承顧託，執契恭臨撫。',48,'全唐诗/poet.tang.0.json','["荷恩承顧託，執契恭臨撫。", "廟略靜邊荒，天兵曜神武。", "有截資先化，無爲遵舊矩。", "禎符降昊穹，大業光寰宇。"]'),
('20286700-303e-4d6f-96a8-39e528e2a9df','唐享昊天樂 第十','則天皇后','唐','唐诗','tang','','[]','肅肅祀典，邕邕禮秩。',40,'全唐诗/poet.tang.0.json','["肅肅祀典，邕邕禮秩。", "三獻已周，九成斯畢。", "爰撤其俎，載遷其實。", "或升或降，惟誠惟質。"]'),
('f14b9577-28a8-47e4-9085-9ffac7012bbc','唐享昊天樂 第十一','則天皇后','唐','唐诗','tang','','[]','禮終肆類，樂闋九成。',40,'全唐诗/poet.tang.0.json','["禮終肆類，樂闋九成。", "仰惟明德，敢薦非馨。", "顧慙菲奠，久馳雲軿。", "瞻荷靈澤，悚戀兼盈。"]'),
('94e6de39-7468-4b6a-9cb0-7be23b7a5ee4','唐享昊天樂 第十二','則天皇后','唐','唐诗','tang','','[]','式乾路，闢天扉。',32,'全唐诗/poet.tang.0.json','["式乾路，闢天扉。", "迴日馭，動雲衣。", "登金闕，入紫微。", "望仙駕，仰恩徽。"]'),
('c1d98eb6-0c36-429e-9646-32e9893e16ec','唐明堂樂章 外辦將出','則天皇后','唐','唐诗','tang','','[]','總章陳昔典，衢室禮惟神。',48,'全唐诗/poet.tang.0.json','["總章陳昔典，衢室禮惟神。", "宏規則天地，神用叶陶鈞。", "負扆三春旦，充庭萬宇賓。", "顧己誠虛薄，空慙馭兆人。"]'),
('96964fe2-9087-42a4-abe9-87cc8e846c59','唐明堂樂章 皇帝行','則天皇后','唐','唐诗','tang','','[]','仰膺曆數，俯順謳歌。',40,'全唐诗/poet.tang.0.json','["仰膺曆數，俯順謳歌。", "遠安邇肅，俗阜時和。", "化光玉鏡，訟息金科。", "方興典禮，永戢干戈。"]'),
('8800914f-7b85-488c-a18b-9cd4b51992f2','唐明堂樂章 皇嗣出入升降','則天皇后','唐','唐诗','tang','','[]','至人光俗，大孝通神。',40,'全唐诗/poet.tang.0.json','["至人光俗，大孝通神。", "謙以表性，恭惟立身。", "洪規載啓，茂典方陳。", "譽隆三善，祥開萬春。"]'),
('f9ad1795-2a0b-4397-8589-cb53fb7f65f1','唐明堂樂章 迎送王公','則天皇后','唐','唐诗','tang','','[]','千官肅事，萬國朝宗。',40,'全唐诗/poet.tang.0.json','["千官肅事，萬國朝宗。", "載延百辟，爰集三宮。", "君臣德合，魚水斯同。", "睿圖方永，周曆長隆。"]'),
('e50e0711-540a-4496-a911-8118d2cb7250','唐明堂樂章 登歌','則天皇后','唐','唐诗','tang','','[]','禮崇宗祀，志表嚴禋。',40,'全唐诗/poet.tang.0.json','["禮崇宗祀，志表嚴禋。", "笙鏞合奏，文物惟新。", "敬遵茂典，敢擇良辰。", "絜誠斯著，奠謁方申。"]'),
('9f23da9b-b91b-4673-b628-562e0a371b16','唐明堂樂章 配饗','則天皇后','唐','唐诗','tang','','[]','笙鏞間玉宇，文物昭清輝。',36,'全唐诗/poet.tang.0.json','["笙鏞間玉宇，文物昭清輝。", "晬影臨芳奠，休光下太微。", "孝思期有感，明絜庶無違。"]'),
('a1c6b056-1c6a-44d9-9e61-9fa5ef3029fb','唐明堂樂章 宮音','則天皇后','唐','唐诗','tang','','[]','履艮包羣望，居中冠百靈。',48,'全唐诗/poet.tang.0.json','["履艮包羣望，居中冠百靈。", "萬方資廣運，庶品荷財成。", "神功諒匪測，盛德實難名。", "藻奠申誠敬，恭祀表惟馨。"]'),
('a692624e-ab66-4525-a082-b0e0a1025912','唐明堂樂章 角音','則天皇后','唐','唐诗','tang','','[]','出震位，開平秩。',32,'全唐诗/poet.tang.0.json','["出震位，開平秩。", "扇條風，乘甲乙。", "龍德盛，鳥星出。", "薦珪篚，陳誠實。"]'),
('6804729b-e657-4b19-b04a-300fcc6307ed','唐明堂樂章 徵音','則天皇后','唐','唐诗','tang','','[]','赫赫離精御炎陸，滔滔熾景開隆暑。',32,'全唐诗/poet.tang.0.json','["赫赫離精御炎陸，滔滔熾景開隆暑。", "冀延神鑒俯蘭尊，式表虔襟陳桂俎。"]'),
('03b61beb-de06-436f-8073-8b31ba88ec9a','唐明堂樂章 商音','則天皇后','唐','唐诗','tang','','[]','律中夷則，序應收成。',40,'全唐诗/poet.tang.0.json','["律中夷則，序應收成。", "功宣建武，義表惟明。", "爰申禮奠，庶展翹誠。", "九秋是式，百穀斯盈。"]'),
('a0fdbeaf-ac46-407c-a611-24775a378981','唐明堂樂章 羽音','則天皇后','唐','唐诗','tang','','[]','葭律肇啓隆冬，蘋藻攸陳饗祭。',28,'全唐诗/poet.tang.0.json','["葭律肇啓隆冬，蘋藻攸陳饗祭。", "黃鍾既陳玉燭，紅粒方殷稔歲。"]'),
('b838cc4b-fb09-4800-8a2b-e2de4ed1441a','唐大饗拜洛樂章 昭和','則天皇后','唐','唐诗','tang','','[]','九玄眷命，三聖基隆。',40,'全唐诗/poet.tang.0.json','["九玄眷命，三聖基隆。", "奉成先旨，明臺畢功。", "宗祀展敬，冀表深衷。", "永昌帝業，式播淳風。"]'),
('095016f5-ecaf-4787-bb95-f971534eeaf9','唐大饗拜洛樂章 致和','則天皇后','唐','唐诗','tang','','[]','神功不測兮運陰陽，包藏萬宇兮孕八荒。',36,'全唐诗/poet.tang.0.json','["神功不測兮運陰陽，包藏萬宇兮孕八荒。", "天符既出兮帝業昌，願臨明祀兮降禎祥。"]'),
('64575578-6e0b-47f9-921e-0ec2ba44bd5e','唐大饗拜洛樂章 咸和','則天皇后','唐','唐诗','tang','','[]','坎澤祠容備舉，坤壇祭典爰申。',49,'全唐诗/poet.tang.0.json','["坎澤祠容備舉，坤壇祭典爰申。", "靈睠遙行祕躅，嘉貺薦委殊珍。", "肅禮恭禋載展，翹襟邈志逾殷。", "方期交際懸應。"]'),
('c84ce639-d85c-45be-95c2-aac639e85efc','唐大饗拜洛樂章 九和','則天皇后','唐','唐诗','tang','','[]','祗荷坤德，欽若乾靈。',40,'全唐诗/poet.tang.0.json','["祗荷坤德，欽若乾靈。", "慙惕罔寘，興居匪寧。", "恭崇禮則，肅奉儀形。", "惟憑展敬，敢薦非馨。"]'),
('245cb870-8fa7-4da0-9c49-ad680d1c38db','唐大饗拜洛樂章 拜洛','則天皇后','唐','唐诗','tang','','[]','菲躬承睿顧，薄德忝坤儀。',48,'全唐诗/poet.tang.0.json','["菲躬承睿顧，薄德忝坤儀。", "乾乾遵後命，翼翼奉先規。", "撫俗勤雖切，還淳化尚虧。", "未能弘至道，何以契明祇。"]'),
('396fd7fa-de45-48e7-b379-0937f6429019','唐大饗拜洛樂章 顯和','則天皇后','唐','唐诗','tang','','[]','顧德有慙虛菲，明祇屢降禎符。',42,'全唐诗/poet.tang.0.json','["顧德有慙虛菲，明祇屢降禎符。", "汜水初呈祕象，溫洛薦表昌圖。", "玄澤流恩載洽，丹襟荷渥增愉。"]'),
('a58856d5-d424-405a-957d-9b3206583c18','唐大饗拜洛樂章 昭和','則天皇后','唐','唐诗','tang','','[]','舒云致養，合大資生。',40,'全唐诗/poet.tang.0.json','["舒云致養，合大資生。", "德以恆固，功由永貞。", "升歌薦序，垂幣翹誠。", "虹開玉照，鳳引金聲。"]'),
('0c3546fa-1331-49aa-8f8e-4e5776359ef7','唐大饗拜洛樂章 敬和','則天皇后','唐','唐诗','tang','','[]','蘭俎既升，蘋羞可薦。',40,'全唐诗/poet.tang.0.json','["蘭俎既升，蘋羞可薦。", "金石載設，咸英已變。", "林澤斯總，山川是徧。", "敢用敷誠，實惟忘倦。"]'),
('c2578f05-3b91-436d-82b7-4f0ee3c3941f','唐大饗拜洛樂章 齊和','則天皇后','唐','唐诗','tang','','[]','沈潛演貺分三極，廣大凝禎總萬方。',32,'全唐诗/poet.tang.0.json','["沈潛演貺分三極，廣大凝禎總萬方。", "既薦羽旌文化啓，還呈干戚武威揚。"]'),
('2dcc4325-2ddf-44a9-b397-b33b9d084cb3','唐大饗拜洛樂章 德和','則天皇后','唐','唐诗','tang','','[]','夕惕同龍契，晨兢當鳳扆。',48,'全唐诗/poet.tang.0.json','["夕惕同龍契，晨兢當鳳扆。", "崇儒習舊規，偃伯循先旨。", "絕壤飛冠蓋，遐區麗山水。", "幸承三聖餘，忻屬千年始。"]'),
('169ff044-695d-4889-b2d0-3c1bd70dfc6c','唐大饗拜洛樂章 禋和','則天皇后','唐','唐诗','tang','','[]','百禮崇容，千官肅事。',40,'全唐诗/poet.tang.0.json','["百禮崇容，千官肅事。", "靈降舞兆，神凝有粹。", "奠享咸周，威儀畢備。", "奏夏登列，歌雍撤肆。"]'),
('8ee6bcb7-cb08-467c-91bd-ece8e555228c','唐大饗拜洛樂章 通和','則天皇后','唐','唐诗','tang','','[]','皇皇靈睠，穆穆神心。',40,'全唐诗/poet.tang.0.json','["皇皇靈睠，穆穆神心。", "暫動凝質，還歸積陰。", "功玄樞紐，理寂高深。", "銜恩佩德，聳志翹襟。"]'),
('8d12c520-fd3c-4db1-ac44-f8475130ab63','唐大饗拜洛樂章 歸和','則天皇后','唐','唐诗','tang','','[]','言旋雲洞兮躡煙塗，永寧中宇兮安下都。',36,'全唐诗/poet.tang.0.json','["言旋雲洞兮躡煙塗，永寧中宇兮安下都。", "包涵動植兮順榮枯，長貽寶貺兮贊璇圖。"]'),
('ab15b93a-75c9-4665-89a5-7c64bf2dc484','唐大饗拜洛樂章 歸和','則天皇后','唐','唐诗','tang','','[]','調雲闋兮神座興，驂雲駕兮儼將升。',32,'全唐诗/poet.tang.0.json','["調雲闋兮神座興，驂雲駕兮儼將升。", "騰絳霄兮垂景祜，翹丹懇兮荷休徵。"]'),
('167be2a8-7084-403c-b072-27a62233625e','唐武氏享先廟樂章','則天皇后','唐','唐诗','tang','','[]','先德謙撝冠昔，嚴規節素超今。',84,'全唐诗/poet.tang.0.json','["先德謙撝冠昔，嚴規節素超今。", "奉國忠誠每竭，承家至孝純深。", "追崇懼乖尊意，顯號恐玷徽音。", "既迫王公屢請，方乃俯遂羣心。", "有限無由展敬，奠醑每闕親斟。", "大禮虔申典冊，蘋藻敬薦翹襟。"]'),
('50321411-cd02-476d-bb62-f1e3f753481d','早春夜宴','則天皇后','唐','唐诗','tang','','["\u63cf\u5199\u6c34", "\u5bb4\u4f1a", "\u63cf\u5199\u5c71", "\u5199\u5c71", "\u5199\u6c34", "\u6109\u60a6"]','九春開上節，千門敞夜扉。',48,'全唐诗/poet.tang.0.json','["九春開上節，千門敞夜扉。", "蘭燈吐新燄，桂魄朗圓輝。", "送酒惟須滿，流杯不用稀。", "務使霞漿興，方乘汎洛歸。"]'),
('2b349c17-dac3-4bd8-9673-05f49cb96d0c','遊九龍潭','則天皇后','唐','唐诗','tang','','["\u601d\u4e61", "\u8e0f\u9752", "\u5199\u666f", "\u5c71\u6c34"]','山窗遊玉女，澗戶對瓊峰。',48,'全唐诗/poet.tang.0.json','["山窗遊玉女，澗戶對瓊峰。", "巖頂翔雙鳳，潭心倒九龍。", "酒中浮竹葉，杯上寫芙蓉。", "故驗家山賞，惟有風入松。"]'),
('ebc91c19-1486-4a61-84fb-649eadef3f51','贈胡天師','則天皇后','唐','唐诗','tang','','[]','高人叶高志，山服往山家。',48,'全唐诗/poet.tang.0.json','["高人叶高志，山服往山家。", "迢迢間風月，去去隔煙霞。", "碧岫窺玄洞，玉竈鍊丹砂。", "今日星津上，延首望靈槎。"]'),
('2b4284f7-cfab-4ec2-abcf-11255250f325','從駕幸少林寺','則天皇后','唐','唐诗','tang','','[]','陪鑾遊禁苑，侍賞出蘭闈。',120,'全唐诗/poet.tang.0.json','["陪鑾遊禁苑，侍賞出蘭闈。", "雲偃攢峰蓋，霞低插浪旂。", "日宮疏澗戶，月殿啓巖扉。", "金輪轉金地，香閣曳香衣。", "鐸吟輕吹發，幡搖薄霧霏。", "昔遇焚芝火，山紅連野飛。", "花臺無半影，蓮塔有全輝。", "實賴能仁力，攸資善世威。", "慈緣興福緒，於此罄歸依。", "風枝不可靜，泣血竟何追。"]'),
('22a81685-1b2f-447b-aca0-27646037db90','石淙','則天皇后','唐','唐诗','tang','','[]','三山十洞光玄籙，玉嶠金巒鎮紫微。',64,'全唐诗/poet.tang.0.json','["三山十洞光玄籙，玉嶠金巒鎮紫微。", "均露均霜標勝壤，交風交雨列皇畿。", "萬仞高巖藏日色，千尋幽澗浴雲衣。", "且駐歡筵賞仁智，琱鞍薄晚雜塵飛。"]'),
('e2b0e927-1ed7-4df6-9747-2c0d1f559cf0','臘日宣詔幸上苑','則天皇后','唐','唐诗','tang','','["\u82b1", "\u51ac\u5929", "\u5199\u82b1"]','明朝遊上苑，火急報春知。',24,'全唐诗/poet.tang.0.json','["明朝遊上苑，火急報春知。", "花須連夜發，莫待曉風吹。"]'),
('ec37a853-d136-4093-9dc8-cfde84fae230','如意娘','則天皇后','唐','唐诗','tang','','["\u5a49\u7ea6\u8bcd", "\u76f8\u601d", "\u5a49\u7ea6"]','看朱成碧思紛紛，顦顇支離爲憶君。',32,'全唐诗/poet.tang.0.json','["看朱成碧思紛紛，顦顇支離爲憶君。", "不信比來長下淚，開箱驗取石榴裙。"]'),
('44493567-505b-484b-91b4-df069b09fc88','製袍字賜狄仁傑','則天皇后','唐','唐诗','tang','','["\u5199\u4eba", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','敷政術，守清勤。',16,'全唐诗/poet.tang.0.json','["敷政術，守清勤。", "升顯位，勵相臣。"]'),
('ed8056df-5365-4a99-9364-34e685253390','擬小山篇','徐賢妃','唐','唐诗','tang','','[]','仰幽巖而流盼，撫桂枝以凝想。',28,'全唐诗/poet.tang.0.json','["仰幽巖而流盼，撫桂枝以凝想。", "將千齡兮此遇，荃何爲兮獨往。"]'),
('6ac98d23-849c-4cdc-9c66-72fc3d6c87c7','長門怨','徐賢妃','唐','唐诗','tang','','[]','舊愛柏梁臺，新寵昭陽殿。',48,'全唐诗/poet.tang.0.json','["舊愛柏梁臺，新寵昭陽殿。", "守分辭芳輦，含情泣團扇。", "一朝歌舞榮，夙昔詩書賤。", "頹恩誠已矣，覆水難重薦。"]'),
('a891f80d-fe12-429e-a820-3890a3c6af9e','秋風函谷應詔','徐賢妃','唐','唐诗','tang','','[]','秋風起函谷，勁氣動河山。',48,'全唐诗/poet.tang.0.json','["秋風起函谷，勁氣動河山。", "偃松千嶺上，雜雨二陵間。", "低雲愁廣隰，落日慘重關。", "此時飄紫氣，應驗真人還。"]'),
('6d46b6ce-5c89-4a0b-b496-c1718293fa90','賦得北方有佳人','徐賢妃','唐','唐诗','tang','','["\u5199\u4eba", "\u5148\u79e6\u4e24\u6c49\u8bd7"]','由來稱獨立，本自號傾城。',60,'全唐诗/poet.tang.0.json','["由來稱獨立，本自號傾城。", "柳葉眉間發，桃花臉上生。", "腕搖金釧響，步轉玉環鳴。", "纖腰宜寶袜，紅衫豔織成。", "懸知一顧重，別覺舞腰輕。"]'),
('8410fa94-bfb9-4217-8bbd-f20a35b357fe','進太宗','徐賢妃','唐','唐诗','tang','','[]','朝來臨鏡臺，粧罷暫裴回。',24,'全唐诗/poet.tang.0.json','["朝來臨鏡臺，粧罷暫裴回。", "千金始一笑，一召詎能來。"]'),
('595cdc85-b376-45d2-97fc-fb7e946ab5fd','奉和聖製立春日侍宴內殿出翦綵花應制','上官昭容','唐','唐诗','tang','','[]','密葉因裁吐，新花逐翦舒。',36,'全唐诗/poet.tang.0.json','["密葉因裁吐，新花逐翦舒。", "攀條雖不謬，摘橤詎知虛。", "春至由來發，秋還未肯疎。"]'),
('81981192-77b7-407d-ab89-18ebf00d8de4','九月九日上幸慈恩寺登浮圖羣臣上菊花壽酒','上官昭容','唐','唐诗','tang','','[]','帝里重陽節，香園萬乘來。',48,'全唐诗/poet.tang.0.json','["帝里重陽節，香園萬乘來。", "卻邪萸入佩，獻壽菊傳杯。", "墖類承天湧，門疑待佛開。", "睿詞懸日月，長得仰昭回。"]'),
('0e0d5bc9-dc63-4c00-9409-8ff3c7e66140','綵書怨','上官昭容','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','葉下洞庭初，思君萬里餘。',48,'全唐诗/poet.tang.0.json','["葉下洞庭初，思君萬里餘。", "露濃香被冷，月落錦屏虛。", "欲奏江南曲，貪封薊北書。", "書中無別意，惟悵久離居。"]'),
('3f1f308b-60d8-4cd0-987b-a8c0d02801cd','駕幸三會寺應制','上官昭容','唐','唐诗','tang','','[]','釋子談經處，軒臣刻字留。',72,'全唐诗/poet.tang.0.json','["釋子談經處，軒臣刻字留。", "故臺遺老識，殘簡聖皇求。", "駐蹕懷千古，開襟望九州。", "四山緣塞合，二水夾城流。", "宸翰陪瞻仰，天杯接獻酬。", "太平詞藻盛，長願紀鴻休。"]'),
('bcad32a8-54b7-4b67-b811-bb0f46d1428b','駕幸新豐溫泉宮獻詩三首 一','上官昭容','唐','唐诗','tang','','[]','三冬季月景[龍]年，萬乘觀風出灞川。',34,'全唐诗/poet.tang.0.json','["三冬季月景[龍]年，萬乘觀風出灞川。", "遙看電躍龍爲馬，回矚霜原玉作田。"]'),
('47e4501e-c5e4-4074-90db-2cd50aeaf708','駕幸新豐溫泉宮獻詩三首 二','上官昭容','唐','唐诗','tang','','[]','鸞旂掣曳拂空回，羽騎驂驔躡景來。',32,'全唐诗/poet.tang.0.json','["鸞旂掣曳拂空回，羽騎驂驔躡景來。", "隱隱驪山雲外聳，迢迢御帳日邊開。"]'),
('9686d740-a96f-4a0c-834b-c83db48d33e4','駕幸新豐溫泉宮獻詩三首 三','上官昭容','唐','唐诗','tang','','[]','翠幕珠幃敞月營，金罍玉斝泛蘭英。',32,'全唐诗/poet.tang.0.json','["翠幕珠幃敞月營，金罍玉斝泛蘭英。", "歲歲年年常扈蹕，長長久久樂升平。"]'),
('788b3936-5fdc-4ee4-b414-f9ab803c95f9','遊長寧公主流杯池二十五首 一','上官昭容','唐','唐诗','tang','','[]','逐仙賞，展幽情。',16,'全唐诗/poet.tang.0.json','["逐仙賞，展幽情。", "踰崑閬，邁蓬瀛。"]'),
('39d21a74-e45e-4c99-bd65-40a41a38ed7e','遊長寧公主流杯池二十五首 二','上官昭容','唐','唐诗','tang','','[]','遊魯館，陟秦臺。',16,'全唐诗/poet.tang.0.json','["遊魯館，陟秦臺。", "汚山壁，媿瓊瓌。"]'),
('06f8cae4-3045-45f8-ae8b-01eddcfd4fcf','遊長寧公主流杯池二十五首 三','上官昭容','唐','唐诗','tang','','[]','檀欒竹影，飆䫻松聲。',20,'全唐诗/poet.tang.0.json','["檀欒竹影，飆䫻松聲。", "不煩歌吹，自足娛情。"]'),
('f696fcf6-52a5-4637-bf2e-0feda4325bc6','遊長寧公主流杯池二十五首 四','上官昭容','唐','唐诗','tang','','[]','仰循茅宇，俯眄喬枝。',20,'全唐诗/poet.tang.0.json','["仰循茅宇，俯眄喬枝。", "煙霞問訊，風月相知。"]'),
('87f585dd-729d-45be-bdba-a6ea474ceefb','遊長寧公主流杯池二十五首 五','上官昭容','唐','唐诗','tang','','[]','枝條鬱鬱，文質彬彬。',20,'全唐诗/poet.tang.0.json','["枝條鬱鬱，文質彬彬。", "山林作伴，松桂爲鄰。"]'),
('2387aa85-45b4-4884-baf8-83de0d071285','遊長寧公主流杯池二十五首 六','上官昭容','唐','唐诗','tang','','[]','清波洶湧，碧樹冥蒙。',20,'全唐诗/poet.tang.0.json','["清波洶湧，碧樹冥蒙。", "莫怪留步，因攀桂叢。"]'),
('c43d47da-630c-4a86-bcf4-f9abf991b6c7','遊長寧公主流杯池二十五首 七','上官昭容','唐','唐诗','tang','','[]','莫論圓嶠，休說方壺。',20,'全唐诗/poet.tang.0.json','["莫論圓嶠，休說方壺。", "何如魯館，即是仙都。"]'),
('d6bc732b-e080-4c0c-b1a1-9902374c0372','遊長寧公主流杯池二十五首 八','上官昭容','唐','唐诗','tang','','[]','玉環騰遠創，金埒荷殊榮。',48,'全唐诗/poet.tang.0.json','["玉環騰遠創，金埒荷殊榮。", "弗玩珠璣飾，仍留仁智情。", "鑿山便作室，憑樹即爲楹。", "公輸與班爾，從此遂韜聲。"]'),
('e11e3a24-c739-4054-b66f-2d7ae8ca09dd','遊長寧公主流杯池二十五首 九','上官昭容','唐','唐诗','tang','','[]','登山一長望，正遇九春初。',48,'全唐诗/poet.tang.0.json','["登山一長望，正遇九春初。", "結駟填街術，閭閻滿邑居。", "鬬雪梅先吐，驚風柳未舒。", "直愁斜日落，不畏酒尊虛。"]'),
('050572f1-02f6-40f3-8318-dbe7f8353a84','遊長寧公主流杯池二十五首 十','上官昭容','唐','唐诗','tang','','[]','霽曉氣清和，披襟賞薜蘿。',48,'全唐诗/poet.tang.0.json','["霽曉氣清和，披襟賞薜蘿。", "玳瑁凝春色，琉璃漾水波。", "跂石聊長嘯，攀松乍短歌。", "除非物外者，誰就此經過。"]'),
('cec1b138-6e5a-4e43-963b-7dae24a295fc','遊長寧公主流杯池二十五首 十一','上官昭容','唐','唐诗','tang','','[]','暫爾遊山第，淹留惜未歸。',48,'全唐诗/poet.tang.0.json','["暫爾遊山第，淹留惜未歸。", "霞窗明月滿，澗戶白雲飛。", "書引藤爲架，人將薜作衣。", "此真攀玩所，臨睨賞光輝。"]'),
('5c9271d7-7837-4f32-ac69-2d78708665f6','遊長寧公主流杯池二十五首 十二','上官昭容','唐','唐诗','tang','','[]','放曠出煙雲，蕭條自不羣。',48,'全唐诗/poet.tang.0.json','["放曠出煙雲，蕭條自不羣。", "漱流清意府，隱几避嚻氛。", "石畫妝苔色，風梭織水文。", "山室何爲貴？唯餘蘭桂熏。"]'),
('202f8187-f247-41cc-84dc-29c91d4ba11c','遊長寧公主流杯池二十五首 十三','上官昭容','唐','唐诗','tang','','[]','策杖臨霞岫，危步下霜蹊。',48,'全唐诗/poet.tang.0.json','["策杖臨霞岫，危步下霜蹊。", "志逐深山靜，途隨曲澗迷。", "漸覺心神逸，俄看雲霧低。", "莫怪人題樹，祗爲賞幽棲。"]'),
('75cab210-6be6-4de7-905e-4ca56e574ac5','遊長寧公主流杯池二十五首 十四','上官昭容','唐','唐诗','tang','','[]','攀藤招逸客，偃桂協幽情。',24,'全唐诗/poet.tang.0.json','["攀藤招逸客，偃桂協幽情。", "水中看樹影，風裏聽松聲。"]'),
('d54a5d9e-3996-4c1a-b83f-921c73221c4b','遊長寧公主流杯池二十五首 十五','上官昭容','唐','唐诗','tang','','[]','攜琴侍叔夜，負局訪安期。',24,'全唐诗/poet.tang.0.json','["攜琴侍叔夜，負局訪安期。", "不應題石壁，爲記賞山時。"]'),
('f44c2a8c-9a5a-4056-a0f0-a6b06e943b1e','遊長寧公主流杯池二十五首 十六','上官昭容','唐','唐诗','tang','','[]','泉石多仙趣，巖壑寫奇形。',24,'全唐诗/poet.tang.0.json','["泉石多仙趣，巖壑寫奇形。", "欲知堪悅耳，唯聽水泠泠。"]'),
('42f7d5fe-12aa-4b61-bc09-5a53316f474f','遊長寧公主流杯池二十五首 十七','上官昭容','唐','唐诗','tang','','[]','巖壑恣登臨，瑩目復怡心。',24,'全唐诗/poet.tang.0.json','["巖壑恣登臨，瑩目復怡心。", "風篁類長笛，流水當鳴琴。"]'),
('55c1a855-991d-44ed-8671-73733b0697fa','遊長寧公主流杯池二十五首 十八','上官昭容','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','嬾步天台路，惟登地肺山。',24,'全唐诗/poet.tang.0.json','["嬾步天台路，惟登地肺山。", "幽巖仙桂滿，今日恣情攀。"]'),
('dd4c3198-29e8-4d2a-bdb1-184ba15f7d3d','遊長寧公主流杯池二十五首 十九','上官昭容','唐','唐诗','tang','','[]','暫遊仁智所，蕭然松桂情。',24,'全唐诗/poet.tang.0.json','["暫遊仁智所，蕭然松桂情。", "寄言棲遯客，勿復訪蓬瀛。"]'),
('3ba02423-e8b6-491d-8478-4d2fe15eca91','遊長寧公主流杯池二十五首 二十','上官昭容','唐','唐诗','tang','','[]','瀑溜晴疑雨，叢篁晝似昏。',24,'全唐诗/poet.tang.0.json','["瀑溜晴疑雨，叢篁晝似昏。", "山中真可玩，暫請報王孫。"]'),
('0279adf4-af13-41e9-b12a-a094f2860a06','遊長寧公主流杯池二十五首 二十一','上官昭容','唐','唐诗','tang','','[]','傍池聊試筆，倚石旋題詩。',24,'全唐诗/poet.tang.0.json','["傍池聊試筆，倚石旋題詩。", "豫彈山水調，終擬從鍾期。"]'),
('38bcda3c-a23f-4906-acd7-bcda8ec8bc2c','遊長寧公主流杯池二十五首 二十二','上官昭容','唐','唐诗','tang','','[]','橫鋪豹皮褥，側帶鹿胎巾。',24,'全唐诗/poet.tang.0.json','["橫鋪豹皮褥，側帶鹿胎巾。", "借問何爲者，山中有逸人。"]'),
('bfbe3236-35b2-48c1-b9e2-8785bfbc2e09','遊長寧公主流杯池二十五首 二十三','上官昭容','唐','唐诗','tang','','[]','沁水田園先自多，齊城樓觀更無過。',32,'全唐诗/poet.tang.0.json','["沁水田園先自多，齊城樓觀更無過。", "倩語張騫莫辛苦，人今從此識天河。"]'),
('991314e4-fee9-4758-9d63-917d9283f3f8','遊長寧公主流杯池二十五首 二十四','上官昭容','唐','唐诗','tang','','[]','參差碧岫聳蓮花，潺湲綠水瑩金沙。',32,'全唐诗/poet.tang.0.json','["參差碧岫聳蓮花，潺湲綠水瑩金沙。", "何須遠訪三山路，人今已到九仙家。"]'),
('a1247751-df1c-4685-af76-18058f7df051','遊長寧公主流杯池二十五首 二十五','上官昭容','唐','唐诗','tang','','[]','憑高瞰險足怡心，菌閣桃源不暇尋。',32,'全唐诗/poet.tang.0.json','["憑高瞰險足怡心，菌閣桃源不暇尋。", "餘雪依林成玉樹，殘霙點岫即瑤岑。"]'),
('ce68cb98-d933-4ddd-a4f5-6ced5062c361','句','上官昭容','唐','唐诗','tang','','[]','勢如連璧友，心似臭蘭人。',12,'全唐诗/poet.tang.0.json','["勢如連璧友，心似臭蘭人。"]'),
('225f48d3-f1c0-4917-bbee-32aa163d5077','贈張雲容舞','楊貴妃','唐','唐诗','tang','','[]','羅袖動香香不已，紅蕖褭褭秋煙裏。',32,'全唐诗/poet.tang.0.json','["羅袖動香香不已，紅蕖褭褭秋煙裏。", "輕雲嶺上乍搖風，嫩柳池邊初拂水。"]'),
('06c84041-b4d9-4317-8d51-863fe37b087b','謝賜珍珠','江妃','唐','唐诗','tang','','["\u601d\u5ff5", "\u5973\u5b50", "\u5bab\u6028"]','桂葉雙眉久不描，殘妝和淚汚紅綃。',32,'全唐诗/poet.tang.0.json','["桂葉雙眉久不描，殘妝和淚汚紅綃。", "長門盡日無梳洗，何必珍珠慰寂寥。"]'),
('ef8c04bf-a29b-4537-bebb-256c6604126c','黃臺瓜辭','章懷太子','唐','唐诗','tang','','[]','種瓜黃臺下，瓜熟子離離。',36,'全唐诗/poet.tang.0.json','["種瓜黃臺下，瓜熟子離離。", "一摘使瓜好，再摘使瓜稀。", "三摘猶自可，摘絕抱蔓歸。"]'),
('8aee9434-79c4-44ec-a455-d3b9749a4ac6','奉和同太子監守違戀','韓王元嘉','唐','唐诗','tang','','[]','乾象開層構，離明啓少陽。',84,'全唐诗/poet.tang.0.json','["乾象開層構，離明啓少陽。", "卜征從獻吉，守器屬元良。", "逖矣凌周誦，遙哉掩漢莊。", "好士傾南洛，多才盛北場。", "地分丹鷲嶺，途間白雲鄉。", "儲誠虔曉夕，宸愛積炎涼。", "珠璧連霄漢，萬物仰重光。"]'),
('98d6b63d-b3c2-4875-95d1-00bf11b0cff1','奉和聖製過溫湯','越王貞','唐','唐诗','tang','','[]','鳳輦騰宸駕，驪籞次乾遊。',60,'全唐诗/poet.tang.0.json','["鳳輦騰宸駕，驪籞次乾遊。", "坎德疎溫液，山隈派暖流。", "寒氛空外擁，蒸氣沼中浮。", "林凋帷影散，雲斂蓋陰收。", "霜郊暢玄覽，參差落景遒。"]'),
('e4a02904-d561-4be5-9d9a-296456744bcf','石橋','信安王禕','唐','唐诗','tang','','[]','別有經行所，迥跨重巒側。',120,'全唐诗/poet.tang.0.json','["別有經行所，迥跨重巒側。", "粵因求瘼餘，倏想尋真域。", "放情恣披拂，杖策聊□□。", "□□□□□，□□□□色。", "亂幡霧中見，雁塔雲間識。", "薄煙冪遠郊，遙峰沒歸翼。", "仙橋危石架，幽洞乘□□。", "□□□□□，□□□易測。", "二教無先後，一相平而直。", "冀茲捐俗心，永懷依妙力。"]'),
('7c19167f-da19-47bb-94d1-dc3b6d648acf','虛池驛題屏風','宜芬公主','唐','唐诗','tang','','[]','出嫁辭鄉國，由來此別難。',48,'全唐诗/poet.tang.0.json','["出嫁辭鄉國，由來此別難。", "聖恩愁遠道，行路泣相看。", "沙塞容顏盡，邊隅粉黛殘。", "妾心何所斷，他日望長安。"]'),
('2b0e2a03-4c0b-4808-a4d4-9752daad3ca4','嘲陸暢','女學士宋氏若華','唐','唐诗','tang','','[]','十二層樓倚翠空，鳳鸞相對立梧桐。',32,'全唐诗/poet.tang.0.json','["十二層樓倚翠空，鳳鸞相對立梧桐。", "雙成走報監門衛，莫使吳歈入漢宮。"]'),
('8a5d0a21-2700-46ec-b018-e7dc9329251e','奉和御製麟德殿宴百僚應制','尚宮宋氏若昭','唐','唐诗','tang','','[]','垂衣臨八極，肅穆四門通。',72,'全唐诗/poet.tang.0.json','["垂衣臨八極，肅穆四門通。", "自是無爲化，非關輔弼功。", "修文招隱伏，尚武殄妖兇。", "德炳韶光熾，恩霑雨露濃。", "衣冠陪御宴，禮樂盛朝宗。", "萬壽稱觴舉，千年信一同。"]'),
('9d4d8cf5-599f-45b8-bc1d-f337a1f7e5ba','奉和御製麟德殿宴百官','尚宮宋氏若憲','唐','唐诗','tang','','[]','端拱承休命，時清荷聖皇。',72,'全唐诗/poet.tang.0.json','["端拱承休命，時清荷聖皇。", "四聰聞受諫，五服遠朝王。", "景媚鶯初囀，春殘日更長。", "命筵多濟濟，盛樂復鏘鏘。", "酆鎬誰將敵，橫汾未可方。", "願齊山嶽壽，祉福永無疆。"]'),
('c0c495ed-8887-4294-9e38-2499b629c3e9','奉和麟德殿宴百僚應[制]','鮑氏君徽','唐','唐诗','tang','','[]','睿澤先寰海，功成展武韶。',74,'全唐诗/poet.tang.0.json','["睿澤先寰海，功成展武韶。", "戈鋋清外壘，文物盛中朝。", "聖祚山河固，宸章日月昭。", "玉筵鸞鵠集，仙管鳳皇調。", "御柳新低綠，宮鶯乍囀嬌。", "願將[億]兆慶，千祀奉神堯。"]'),
('59e2fe4b-c925-4b3e-851d-e1c355c43b98','關山月','鮑氏君徽','唐','唐诗','tang','','[]','高高秋月明，北照遼陽城。',72,'全唐诗/poet.tang.0.json','["高高秋月明，北照遼陽城。", "塞迥光初滿，風多暈更生。", "征人望鄉思，戰馬聞鼙驚。", "朔風悲邊草，胡沙暗虜營。", "霜凝匣中劒，風憊原上旌。", "早晚謁金闕，不聞刁斗聲。"]'),
('7ff83e4f-cf78-4123-8a0c-4e39cb867020','惜花吟','鮑氏君徽','唐','唐诗','tang','','[]','枝上花，花下人，可憐顏色俱青春。',80,'全唐诗/poet.tang.0.json','["枝上花，花下人，可憐顏色俱青春。", "昨日看花花灼灼，今朝看花花欲落。", "不如盡此花下歡，莫待春風總吹卻。", "鶯歌蝶舞韶光長，紅爐煑茗松花香。", "妝成罷吟恣遊後，獨把芳枝歸洞房。"]'),
('45e01605-620b-4b86-acd4-02e10ae12e89','東亭茶宴','鮑氏君徽','唐','唐诗','tang','','[]','閑朝向曉出簾櫳，茗宴東亭四望通。',64,'全唐诗/poet.tang.0.json','["閑朝向曉出簾櫳，茗宴東亭四望通。", "遠眺城池山色裏，俯聆絃管水聲中。", "幽篁引沼新抽翠，芳槿低檐欲吐紅。", "坐久此中無限興，更憐團扇起清風。"]'),
('9bc25c25-81f9-4003-8592-9f413774e85f','夜夢','蕭妃','唐','唐诗','tang','','[]','昨日夢君歸，賤妾下鳴機。',36,'全唐诗/poet.tang.0.json','["昨日夢君歸，賤妾下鳴機。", "極知意氣薄，不著去時衣。", "故言如夢裏，賴得雁書飛。"]'),
('6a4385e9-97c5-4425-8c96-472b0fea4cf9','詠燈','南唐先主李昪','唐','唐诗','tang','','[]','一點分明值萬金，開時惟怕冷風侵。',32,'全唐诗/poet.tang.0.json','["一點分明值萬金，開時惟怕冷風侵。", "主人若也勤挑撥，敢向尊前不盡心。"]'),
('e1ea09bb-0ca8-4ec2-b9ee-f1299f878734','遊後湖賞蓮花','嗣主璟','唐','唐诗','tang','','[]','蓼花蘸水火不滅，水鳥驚魚銀梭投。',48,'全唐诗/poet.tang.0.json','["蓼花蘸水火不滅，水鳥驚魚銀梭投。", "滿目荷花千萬頃，紅碧相雜敷清流。", "孫武已斬吳宮女，琉璃池上佳人頭。"]'),
('d6631944-18f1-4767-a2d4-77b1516758cd','保大五年元日大雪同太弟景遂汪王景逷齊王景逵進士李建勳中書徐鉉勤政殿學士張義方登樓賦','嗣主璟','唐','唐诗','tang','','[]','珠簾高卷莫輕遮，往往相逢隔歲華。',64,'全唐诗/poet.tang.0.json','["珠簾高卷莫輕遮，往往相逢隔歲華。", "春氣昨宵飄律管，東風今日放梅花。", "素姿好把芳姿掩，落勢還同舞勢斜。", "坐有賓朋尊有酒，可憐清味屬儂家。"]'),
('5c236f02-7a4d-41c6-ac4f-ae6f2cc9887f','句','嗣主璟','唐','唐诗','tang','','[]','靈槎思浩蕩，老鶴倚崆峒。',40,'全唐诗/poet.tang.0.json','["靈槎思浩蕩，老鶴倚崆峒。", "蒼苔迷古道，紅葉亂朝霞。", "棲鳳枝梢猶輭弱，化龍形狀已依稀。"]'),
('89667d89-cd91-4777-b087-e51873cc3823','九月十日偶書','後主煜','唐','唐诗','tang','','[]','晚雨秋陰酒乍醒，感時心緒杳難平。',64,'全唐诗/poet.tang.0.json','["晚雨秋陰酒乍醒，感時心緒杳難平。", "黃花冷落不成豔，紅葉颼飀競鼓聲。", "背世返能厭俗態，偶緣猶未忘多情。", "自從雙鬢斑斑白，不學安仁卻自驚。"]'),
('05d03b46-d786-4acf-995e-a20721f16583','秋鶯','後主煜','唐','唐诗','tang','','[]','殘鶯何事不知秋，橫過幽林尚獨遊。',64,'全唐诗/poet.tang.0.json','["殘鶯何事不知秋，橫過幽林尚獨遊。", "老舌百般傾耳聽，深黃一點入煙流。", "棲遲背世同悲魯，瀏亮如笙碎在緱。", "莫更留連好歸去，露華淒冷蓼花愁。"]'),
('5067fb0b-3f4d-4498-a7a6-a49dd0446067','病起題山舍壁','後主煜','唐','唐诗','tang','','[]','山舍初成病乍輕，杖藜巾褐稱閑情。',64,'全唐诗/poet.tang.0.json','["山舍初成病乍輕，杖藜巾褐稱閑情。", "爐開小火深回暖，溝引新流幾曲聲。", "暫約彭涓安朽質，終期宗遠問無生。", "誰能役役塵中累，貪合魚龍搆強名。"]'),
('ae40f021-8209-4019-a612-4c477e4c12be','送鄧王二十弟從益牧宣城','後主煜','唐','唐诗','tang','','[]','且維輕舸更遲遲，別酒重傾惜解攜。',64,'全唐诗/poet.tang.0.json','["且維輕舸更遲遲，別酒重傾惜解攜。", "浩浪侵愁光蕩漾，亂山凝恨色高低。", "君馳檜楫情何極，我凭闌干日向西。", "咫尺煙江幾多地，不須懷抱重淒淒。"]'),
('6533dc36-cc73-4798-b24a-fbff04fc2a85','渡中江望石城泣下','後主煜','唐','唐诗','tang','','["\u6292\u60c5", "\u4f24\u6000"]','江南江北舊家鄉，三十年來夢一場。',64,'全唐诗/poet.tang.0.json','["江南江北舊家鄉，三十年來夢一場。", "吳苑宮闈今冷落，廣陵臺殿已荒涼。", "雲籠遠岫愁千片，雨打歸舟淚萬行。", "兄弟四人三百口，不堪閑坐細思量。"]'),
('018cab44-8167-40eb-8934-09667eb405da','輓辭 一','後主煜','唐','唐诗','tang','','[]','珠碎眼前珍，花凋世外春。',48,'全唐诗/poet.tang.0.json','["珠碎眼前珍，花凋世外春。", "未銷心裏恨，又失掌中身。", "玉笥猶殘藥，香匳已染塵。", "前哀將後感，無淚可霑巾。"]'),
('1aaa5f58-ec89-4cdc-b96a-2717e03edf95','輓辭 二','後主煜','唐','唐诗','tang','','[]','豔質同芳樹，浮危道略同。',48,'全唐诗/poet.tang.0.json','["豔質同芳樹，浮危道略同。", "正悲春落實，又苦雨傷叢。", "穠麗今何在？飄零事已空。", "沈沈無問處，千載謝東風。"]'),
('932de3da-b56d-4987-b9cc-3b2d5956a4ff','悼詩','後主煜','唐','唐诗','tang','','[]','永念難消釋，孤懷痛自嗟。',48,'全唐诗/poet.tang.0.json','["永念難消釋，孤懷痛自嗟。", "雨深秋寂莫，愁引病增加。", "咽絕風前思，昏濛眼上花。", "空王應念我，窮子正迷家。"]'),
('4efebbe9-a40d-4428-b82a-752c48f67793','感懷 一','後主煜','唐','唐诗','tang','','[]','又見桐花發舊枝，一樓煙雨暮淒淒。',32,'全唐诗/poet.tang.0.json','["又見桐花發舊枝，一樓煙雨暮淒淒。", "凭闌惆悵人誰會，不覺澘然淚眼低。"]'),
('ad067534-b1c5-4baa-8454-3dc50c11e1c3','感懷 二','後主煜','唐','唐诗','tang','','[]','層城無復見嬌姿，佳節纏哀不自持。',32,'全唐诗/poet.tang.0.json','["層城無復見嬌姿，佳節纏哀不自持。", "空有當年舊煙月，芙蓉城上哭蛾眉。"]'),
('8881d860-4e39-4a12-97f0-a222687988d5','梅花','後主煜','唐','唐诗','tang','','["\u6292\u60c5", "\u6885\u82b1"]','殷勤移植地，曲檻小闌邊。',48,'全唐诗/poet.tang.0.json','["殷勤移植地，曲檻小闌邊。", "共約重芳日，還憂不盛妍。", "阻風開步障，乘月溉寒泉。", "誰料花前後，蛾眉卻不全。"]'),
('82f109d2-3bc1-447a-a73e-018133ac8929','梅花','後主煜','唐','唐诗','tang','','[]','失却煙花主，東君自不知。',24,'全唐诗/poet.tang.0.json','["失却煙花主，東君自不知。", "清香更何用，猶發去年枝。"]'),
('a1bfef77-89cd-4e38-90b7-bc41784d58de','書靈筵手巾','後主煜','唐','唐诗','tang','','[]','浮生共顦顇，壯歲失嬋娟。',24,'全唐诗/poet.tang.0.json','["浮生共顦顇，壯歲失嬋娟。", "汗手遺香漬，痕眉染黛煙。"]'),
('bbf02817-86a8-42de-b8bf-9d13c764fdb3','書琵琶背','後主煜','唐','唐诗','tang','','["\u6000\u4eba", "\u60bc\u4ea1"]','侁自肩如削，難勝數縷絛。',24,'全唐诗/poet.tang.0.json','["侁自肩如削，難勝數縷絛。", "天香留鳳尾，餘煖在檀槽。"]'),
('5a7dd159-6c84-4436-a9a0-99e2e86d426f','病中感懷','後主煜','唐','唐诗','tang','','[]','顦顇年來甚，蕭條益自傷。',48,'全唐诗/poet.tang.0.json','["顦顇年來甚，蕭條益自傷。", "風威侵病骨，雨氣咽愁腸。", "夜鼎唯煎藥，朝髭半染霜。", "前緣竟何似，誰與問空王。"]'),
('a8244187-a87e-4e80-a3fe-8092bcf48107','病中書事','後主煜','唐','唐诗','tang','','[]','病身堅固道情深，宴坐清香思自任。',64,'全唐诗/poet.tang.0.json','["病身堅固道情深，宴坐清香思自任。", "月照靜居唯擣藥，門扃幽院只來禽。", "庸醫嬾聽詞何取，小婢將行力未禁。", "賴問空門知氣味，不然煩惱萬塗侵。"]'),
('2240c7b5-5ea2-43de-baa8-24fc03aa97cd','賜宮人慶奴','後主煜','唐','唐诗','tang','','["\u67f3\u6811"]','風情漸老見春羞，到處消魂感舊遊。',32,'全唐诗/poet.tang.0.json','["風情漸老見春羞，到處消魂感舊遊。", "多謝長條似相識，強垂煙態拂人頭。"]'),
('ba0ab762-8e4e-4965-a7dd-d47b6958adfb','題金樓子後','後主煜','唐','唐诗','tang','','[]','牙籤萬軸裹紅綃，王粲書同付火燒。',32,'全唐诗/poet.tang.0.json','["牙籤萬軸裹紅綃，王粲書同付火燒。", "不於祖龍留面目，遺篇那得到今朝。"]'),
('3ef4b782-4495-49dc-9da5-b022da15c2a6','句','後主煜','唐','唐诗','tang','','[]','迢迢牽牛星，杳在河之陽。',208,'全唐诗/poet.tang.0.json','["迢迢牽牛星，杳在河之陽。", "粲粲黃姑女，耿耿遙相望。", "鸎狂應有恨，蝶舞已無多。", "揖讓月在手，動搖風滿懷。", "病態如衰弱，厭厭向五年。", "衰顏一病難牽復，曉殿君臨頗自羞。", "冷笑秦皇經遠略，靜憐姬滿苦時巡。", "鬢從今日添新白，菊是去年依舊黃。", "萬古到頭歸一死，醉鄉葬地有高原。", "人生不滿百，剛作千年畫。", "日暎仙雲薄，秋高天碧深。", "烏照始潛輝，龍燭便爭秉。", "凝珠滿露枝，遊颺日已西。", "肅穆寒初至，九重開扇鵠。", "四牖炳燈魚，羽觴無算酌。", "傾盌更爲壽，深卮遞酬賓。"]'),
('a2468fbd-1835-4a66-a3a6-6f27f6d6417d','薔薇詩一首十八韻呈東海侍郎徐鉉','韓王從善','唐','唐诗','tang','','[]','綠影覆幽池，芳菲四月時。',216,'全唐诗/poet.tang.0.json','["綠影覆幽池，芳菲四月時。", "管弦朝夕興，組繡百千枝。", "盛引牆看徧，高煩架屢移。", "露輕濡綵筆，蜂誤拂吟髭。", "日照玲瓏幔，風搖翡翠帷。", "早紅飄蘚地，狂蔓挂蛛絲。", "嫩刺牽衣細，新條窣草垂。", "晚香難暫捨，嬌態自相窺。", "深淺分前後，榮華互盛衰。", "尊前留客久，月下欲歸遲。", "何處繁臨砌？誰家密映籬。", "絳羅房燦爛，碧玉葉參差。", "分得殷勤種，開來遠近知。", "晶熒歌袖袂，柔弱舞腰支。", "膏麝誰將比，庭萱自合嗤。", "勻妝低水鑑，泣淚滴煙𩅰。", "畫擬憑梁廣，名宜亞楚姬。", "寄君十八韻，思拙媿新奇。"]'),
('19466825-f62c-4d59-a528-b04de00054fd','觀棊','吉王從謙','唐','唐诗','tang','','[]','竹林二君子，盡日竟沈吟。',48,'全唐诗/poet.tang.0.json','["竹林二君子，盡日竟沈吟。", "相對終無語，爭先各有心。", "恃強斯有失，守分固無侵。", "若算機籌處，滄滄海未深。"]'),
('63107f94-980b-4fb4-93c1-1815654b77bd','贈別唐太師道襲','蜀高祖王建','唐','唐诗','tang','','[]','丱歲便將爲肘腋，二紀何曾離一日。',64,'全唐诗/poet.tang.0.json','["丱歲便將爲肘腋，二紀何曾離一日。", "更深猶尚立案前，敷奏柔和不傷物。", "今朝榮貴慰我心，雙旌引向重城出。", "褒斜舊地委勳賢，從此生靈永泰息。"]'),
('e66421b4-5322-4aa9-a64c-1bf8707decb7','幸秦川上梓潼山','後主衍','唐','唐诗','tang','','[]','喬巖簇冷煙，幽徑上寒天。',48,'全唐诗/poet.tang.0.json','["喬巖簇冷煙，幽徑上寒天。", "下瞰峨眉嶺，上窺華岳巔。", "驅馳非取樂，按幸爲憂邊。", "此去如登陟，歌樓路幾千。"]'),
('f26a4e37-57a6-4c7c-9d22-060e411a4424','題劒門','後主衍','唐','唐诗','tang','','[]','緩轡踰雙劒，行行躡石稜。',48,'全唐诗/poet.tang.0.json','["緩轡踰雙劒，行行躡石稜。", "作千尋壁壘，爲萬祀依憑。", "道德雖無取，江山粗可矜。", "回看城闕路，雲疊樹層層。"]'),
('61da3ad3-9e7f-4a1c-862d-7fdda6413288','過白衛嶺和韓昭','後主衍','唐','唐诗','tang','','[]','先朝神武力開邊，畫斷封疆四五千。',64,'全唐诗/poet.tang.0.json','["先朝神武力開邊，畫斷封疆四五千。", "前望隴山屯劒戟，後憑巫峽鎖烽煙。", "軒皇尚自親平寇，嬴政徒勞愛學仙。", "想到隗宮尋勝處，正應鶯語暮春天。"]'),
('ecc1774b-988c-40ea-95f3-312889a6e2a3','宮詞','後主衍','唐','唐诗','tang','','[]','輝輝赫赫浮玉雲，宣華池上月華新。',32,'全唐诗/poet.tang.0.json','["輝輝赫赫浮玉雲，宣華池上月華新。", "月華如水浸宮殿，有酒不醉真癡人。"]'),
('f27f6d5d-9d1b-4e86-b88e-efd452c1d424','醉妝詞','後主衍','唐','唐诗','tang','','[]','者邊走，那邊走，只是尋花柳。',28,'全唐诗/poet.tang.0.json','["者邊走，那邊走，只是尋花柳。", "那邊走，者邊走，莫厭金杯酒。"]'),
('10dd38a5-9bf1-4b83-b898-4692f718f0d7','句','後主衍','唐','唐诗','tang','','[]','不緣朝闕去，好此結茅廬。',12,'全唐诗/poet.tang.0.json','["不緣朝闕去，好此結茅廬。"]'),
('8799ff64-1456-4567-929d-8cbcadd3919b','巡衣錦軍製還鄉歌','吳越王錢鏐','唐','唐诗','tang','','[]','三節還鄉兮挂錦衣，碧天朗朗兮愛日暉。',72,'全唐诗/poet.tang.0.json','["三節還鄉兮挂錦衣，碧天朗朗兮愛日暉。", "功成道上兮列旌旗，父老遠來兮相追隨。", "家山鄉眷兮會時稀，今朝設宴兮觥散飛。", "斗牛無孛兮民無欺，吳越一王兮駟馬歸。"]'),
('ba8a1004-e3bc-4167-93e6-1adc22d3eedb','沒了期歌 一','吳越王錢鏐','唐','唐诗','tang','','[]','沒了期，沒了期，營基纔了又倉基。',16,'全唐诗/poet.tang.0.json','["沒了期，沒了期，營基纔了又倉基。"]'),
('0a5dd0d4-f619-4303-b2ed-7e40061c58aa','沒了期歌 二','吳越王錢鏐','唐','唐诗','tang','','[]','沒了期，沒了期，春衣纔了又冬衣。',16,'全唐诗/poet.tang.0.json','["沒了期，沒了期，春衣纔了又冬衣。"]'),
('7081981c-0e2b-4d64-b610-1cf2d95d5fbe','句','吳越王錢鏐','唐','唐诗','tang','','["\u9ec4\u6cb3"]','須將一片地，付與有心人。',44,'全唐诗/poet.tang.0.json','["須將一片地，付與有心人。", "黃河信有澄清日，後代應難繼此才。", "傳語龍王幷水府，錢塘借與築錢城。"]'),
('c31e7431-36e9-461c-978c-66d83c065598','宮中作','後王錢俶','唐','唐诗','tang','','[]','廊廡周遭翠幕遮，禁林深處絕喧譁。',64,'全唐诗/poet.tang.0.json','["廊廡周遭翠幕遮，禁林深處絕喧譁。", "界開日影憐窗紙，穿破苔痕惡筍芽。", "西第晚宜供露茗，小池寒欲結冰花。", "謝公未是深沈量，猶把輸贏局上誇。"]'),
('0a9b2767-706e-40b9-a423-2097e5f97d10','避暑摩訶池上作','後蜀嗣主孟昶','唐','唐诗','tang','','[]','冰肌玉骨清無汗，水殿風來暗香暖。',64,'全唐诗/poet.tang.0.json','["冰肌玉骨清無汗，水殿風來暗香暖。", "簾開明月獨窺人，敧枕釵橫雲鬢亂。", "起來瓊戶寂無聲，時見疎星渡河漢。", "屈指西風幾時來，只恐流年暗中換。"]'),
('e10bd711-4a4e-40e6-85a7-bcec617b61c0','批葉翹諫書紙尾','閩王王繼鵬','唐','唐诗','tang','','[]','春色曾看紫陌頭，亂紅飛盡不禁愁。',32,'全唐诗/poet.tang.0.json','["春色曾看紫陌頭，亂紅飛盡不禁愁。", "人情自厭芳華歇，一葉隨風落御溝。"]'),
('b343ce20-fa91-4e0a-b3e5-c6e1acf3244e','丈人觀','蜀太后徐氏','唐','唐诗','tang','','[]','早與元妃慕至化，同躋靈嶽訪真仙。',64,'全唐诗/poet.tang.0.json','["早與元妃慕至化，同躋靈嶽訪真仙。", "當時信有壺中景，今日親來洞裏天。", "儀仗影空寥廓外，金絲聲揭翠微巔。", "惟慙未致華胥理，徒卜升平萬萬年。"]'),
('b07e39b5-eafc-4493-a320-454e7a81149a','玄都觀','蜀太后徐氏','唐','唐诗','tang','','[]','千尋綠嶂夾流溪，登眺因知海岳低。',64,'全唐诗/poet.tang.0.json','["千尋綠嶂夾流溪，登眺因知海岳低。", "瀑布迸舂青石碎，輪茵橫翦翠峰齊。", "步黏苔蘚龍橋滑，日閉煙羅鳥徑迷。", "莫道穹天無路到，此山便是碧雲梯。"]'),
('288d5f1a-32d3-4be4-9aab-d266c1347c83','丈人觀謁先帝御容','蜀太后徐氏','唐','唐诗','tang','','[]','聖帝歸梧野，躬來謁聖顏。',48,'全唐诗/poet.tang.0.json','["聖帝歸梧野，躬來謁聖顏。", "旋登三徑路，似陟九嶷山。", "日照堆嵐迥，雲橫積翠間。", "期修封禪禮，方俟再躋攀。"]'),
('15bac88f-aae3-4249-861e-7d42a2120302','題金華宮','蜀太后徐氏','唐','唐诗','tang','','[]','再到金華頂，玄都訪道回。',48,'全唐诗/poet.tang.0.json','["再到金華頂，玄都訪道回。", "雲披分景象，黛鎖顯樓臺。", "雨滌前山淨，風吹去路開。", "翠屏夾流水，何必羨蓬萊。"]'),
('305a9001-cb99-4f20-a047-f44fa83e11c7','丹景山至德寺','蜀太后徐氏','唐','唐诗','tang','','[]','周回雲水遊丹景，因與真妃眺上方。',64,'全唐诗/poet.tang.0.json','["周回雲水遊丹景，因與真妃眺上方。", "晴日曉升金晃曜，寒泉夜落玉丁當。", "松梢月轉琴栖影，柏徑風牽麝食香。", "虔煠六銖宜鑄祝，惟祈聖祉保遐昌。"]'),
('6a5cfac3-3860-49c0-8a54-089397403f6f','題彭州陽平化','蜀太后徐氏','唐','唐诗','tang','','[]','尋真游勝境，巡禮到陽平。',48,'全唐诗/poet.tang.0.json','["尋真游勝境，巡禮到陽平。", "水遠波瀾碧，山高氣象清。", "殿嚴孫氏貌，碑暗係師名。", "夜月登壇醮，松風森磬聲。"]'),
('0fb2f812-c33e-41ec-91af-57bfb15e09e3','三學山夜看聖燈','蜀太后徐氏','唐','唐诗','tang','','[]','虔禱游靈境，元妃夙志同。',96,'全唐诗/poet.tang.0.json','["虔禱游靈境，元妃夙志同。", "玉香焚靜夜，銀燭炫遼空。", "泉漱雲根月，鐘敲檜杪風。", "印金標聖迹，飛石顯神功。", "滿望天涯極，平臨日脚紅。", "猿來齋石上，僧集講筵中。", "頓作超三界，渾疑證六通。", "願成修偃化，社稷保延洪。"]'),
('f6dff750-e7ff-414e-b31f-c463f81772ad','題天迴驛','蜀太后徐氏','唐','唐诗','tang','','[]','周遊靈境散幽情，千里江山暫得行。',32,'全唐诗/poet.tang.0.json','["周遊靈境散幽情，千里江山暫得行。", "所恨風光看未足，卻驅金翠入龜城。"]'),
('5b4f56ae-a285-4052-add2-f0e99a4bd393','丈人觀','蜀太妃徐氏','唐','唐诗','tang','','[]','獲陪翠輦喜殊常，同涉仙壇豈厭長。',32,'全唐诗/poet.tang.0.json','["獲陪翠輦喜殊常，同涉仙壇豈厭長。", "不羨乘鸞入煙霧，此中便是五雲鄉。"]'),
('565cad9c-b5b6-425f-86bc-0f33fec6fbd2','玄都觀','蜀太妃徐氏','唐','唐诗','tang','','[]','登尋丹壑到玄都，接日紅霞照座隅。',32,'全唐诗/poet.tang.0.json','["登尋丹壑到玄都，接日紅霞照座隅。", "即向周回巖下看，似看曾進畫圖無。"]'),
('3cdd3b0e-f6ff-4458-b49d-b81502e4d3cb','游丈人觀謁先帝御容','蜀太妃徐氏','唐','唐诗','tang','','[]','共謁御容儀，還同在禁闈。',48,'全唐诗/poet.tang.0.json','["共謁御容儀，還同在禁闈。", "笙歌喧寶殿，彩仗耀金徽。", "清淚霑羅袂，紅霞拂繡衣。", "九疑山水遠，無路繼湘妃。"]'),
('7c225364-4e21-428e-ac41-013a9eb0d8bb','題金華宮','蜀太妃徐氏','唐','唐诗','tang','','[]','碧煙紅霧漾人衣，宿霧蒼苔石徑危。',64,'全唐诗/poet.tang.0.json','["碧煙紅霧漾人衣，宿霧蒼苔石徑危。", "風巧解吹松上曲，蝶嬌頻采臉邊脂。", "同尋僻境思攜手，暗指遙山學畫眉。", "好把身心清淨處，角冠霞帔事希夷。"]'),
('a7434702-2fb1-40ed-8ade-b3f21154f4d2','和題丹景山至德寺','蜀太妃徐氏','唐','唐诗','tang','','[]','丹景山頭宿梵宮，玉輪金輅駐虛空。',64,'全唐诗/poet.tang.0.json','["丹景山頭宿梵宮，玉輪金輅駐虛空。", "軍持無水注寒碧，蘭若有花開晚紅。", "武士盡排青嶂下，內人皆在講筵中。", "我家帝子傳王業，積善終期四海同。"]'),
('50636f43-c98e-4bfe-b3d4-e671b1d8b6c4','題彭州陽平化','蜀太妃徐氏','唐','唐诗','tang','','[]','雲浮翠輦屆陽平，真似驂鸞到上清。',64,'全唐诗/poet.tang.0.json','["雲浮翠輦屆陽平，真似驂鸞到上清。", "風起半厓聞虎嘯，雨來當面見龍行。", "晚尋水澗聽松韻，夜上星壇看月明。", "長恐前身居此境，玉皇教向錦城生。"]'),
('ca2145e0-816c-435b-8e7b-5bb087f6568c','三學山夜看聖燈','蜀太妃徐氏','唐','唐诗','tang','','[]','聖燈千萬炬，旋向碧空生。',48,'全唐诗/poet.tang.0.json','["聖燈千萬炬，旋向碧空生。", "細雨溼不暗，好風吹更明。", "磬敲金地響，僧唱梵天聲。", "若說無心法，此光如有情。"]'),
('6a2e95e9-217d-43dc-8056-7e0e9a44358a','題天迴驛','蜀太妃徐氏','唐','唐诗','tang','','[]','翠驛紅亭近玉京，夢魂猶是在青城。',32,'全唐诗/poet.tang.0.json','["翠驛紅亭近玉京，夢魂猶是在青城。", "比來出看江山景，却被江山看出行。"]'),
('84ac369e-db24-4cc6-9eb7-aedca7e8bdb9','郊廟歌辭 祀圜丘樂章 豫和','褚亮','唐','唐诗','tang','','[]','上靈睠命膺會昌，盛德殷薦叶辰良。',32,'全唐诗/poet.tang.0.json','["上靈睠命膺會昌，盛德殷薦叶辰良。", "景福降兮聖德遠，玄化穆兮天曆長。"]'),
('d15f1209-3fb8-4c84-b1cf-a6607092c74d','郊廟歌辭 祀圜丘樂章 太和','褚亮','唐','唐诗','tang','','[]','穆穆我后，道應千齡。',40,'全唐诗/poet.tang.0.json','["穆穆我后，道應千齡。", "登三處大，得一居貞。", "禮惟崇德，樂以和聲。", "百神仰止，天下文明。"]'),
('cba1afc6-35ad-43bd-a997-2eb2fb1d2105','郊廟歌辭 祀圜丘樂章 肅和','褚亮','唐','唐诗','tang','','[]','闓陽播氣，甄曜垂明。',40,'全唐诗/poet.tang.0.json','["闓陽播氣，甄曜垂明。", "有赫圜宰，深仁曲成。", "日麗蒼璧，煙開紫營。", "聿遵乾享，式降鴻禎。"]'),
('92a8846f-c399-4145-a36b-4b8c0b7d9c14','郊廟歌辭 祀圜丘樂章 雍和','褚亮','唐','唐诗','tang','','[]','欽惟大帝，[載]仰皇穹。',42,'全唐诗/poet.tang.0.json','["欽惟大帝，[載]仰皇穹。", "始命田燭，爰啓郊宮。", "雲門駭聽，雷鼓鳴空。", "神其介祀，景祚斯融。"]'),
('c257fca7-3eb1-476c-b7bd-bb706269c904','郊廟歌辭 祀圜丘樂章 壽和','褚亮','唐','唐诗','tang','','[]','八音斯奏，三獻畢陳。',20,'全唐诗/poet.tang.0.json','["八音斯奏，三獻畢陳。", "寶祚惟永，暉光日新。"]'),
('6760691a-685c-4e01-9f8b-3e7384ed92fd','郊廟歌辭 祀圜丘樂章 舒和','褚亮','唐','唐诗','tang','','[]','疊璧凝影皇壇路，編珠流彩帝郊前。',32,'全唐诗/poet.tang.0.json','["疊璧凝影皇壇路，編珠流彩帝郊前。", "已奏黃鍾歌大呂，還符寶曆祚昌年。"]'),
('8fa4dd76-9d99-44fe-9b28-f16153115227','郊廟歌辭 祀圜丘樂章 凱安','褚亮','唐','唐诗','tang','','[]','昔在炎運終，中華亂無象。',48,'全唐诗/poet.tang.0.json','["昔在炎運終，中華亂無象。", "酆郊赤烏見，邙山黑雲上。", "大賚下周車，禁暴開殷網。", "幽明同叶贊，鼎祚齊天壤。"]'),
('e1e8a4d5-2124-4eab-a15e-bec5d6f3e880','郊廟歌辭 祀圜丘樂章 豫和','褚亮','唐','唐诗','tang','','[]','歌奏畢兮禮獻終，六龍馭兮神將昇。',32,'全唐诗/poet.tang.0.json','["歌奏畢兮禮獻終，六龍馭兮神將昇。", "明德感兮非黍稷，降福簡兮祚休徵。"]'),
('9acb90cb-451d-4c8c-8630-06dd81c45838','郊廟歌辭 郊天舊樂章 豫和','不詳','唐','唐诗','tang','','[]','蘋蘩禮著，黍稷誠微。',40,'全唐诗/poet.tang.0.json','["蘋蘩禮著，黍稷誠微。", "音盈鳳管，彩駐龍旂。", "洪歆式就，介福攸歸。", "送樂有闋，靈馭遄飛。"]'),
('0d9622c6-0120-4f70-ac8f-17996b69dd93','郊廟歌辭 武后大享昊天樂章 一','不詳','唐','唐诗','tang','','[]','大陰凝至化，真耀蘊軒儀。',36,'全唐诗/poet.tang.0.json','["大陰凝至化，真耀蘊軒儀。", "德邁娥臺敞，仁高姒幄披。", "捫天遂啓極，夢日乃昇曦。"]'),
('c9ef5ff3-9cfd-422b-9b0a-9b569826776f','郊廟歌辭 武后大享昊天樂章 二','不詳','唐','唐诗','tang','','[]','瞻紫極，望玄穹。',32,'全唐诗/poet.tang.0.json','["瞻紫極，望玄穹。", "翹至懇，罄深衷。", "聽雖遠，誠必通。", "垂厚澤，降雲宮。"]'),
('86f014f5-1e88-4a78-9efe-8e6b9f923c7a','郊廟歌辭 武后大享昊天樂章 三','不詳','唐','唐诗','tang','','[]','乾儀混成沖邃，天道下濟高明。',58,'全唐诗/poet.tang.0.json','["乾儀混成沖邃，天道下濟高明。", "闓陽晨披紫闕，太一曉降黃庭。", "圓壇敢[申]昭報，方璧冀展虔情。", "丹禁式敷衷懇，玄鑒庶察微誠。"]'),
('2ba7d411-0319-42c5-af8c-caa5c9373cf1','郊廟歌辭 武后大享昊天樂章 四','不詳','唐','唐诗','tang','','[]','巍巍睿業廣，赫赫聖基隆。',60,'全唐诗/poet.tang.0.json','["巍巍睿業廣，赫赫聖基隆。", "菲德承先顧，禎符萃眇躬。", "銘開武巖側，圖薦洛川中。", "微誠詎幽感，景命忽昭融。", "有懷慙紫極，無以謝玄穹。"]'),
('e4a0253f-6331-4902-87e3-a4307347319d','郊廟歌辭 武后大享昊天樂章 五','不詳','唐','唐诗','tang','','[]','朝壇霧卷，曙嶺煙沈。',40,'全唐诗/poet.tang.0.json','["朝壇霧卷，曙嶺煙沈。", "爰設筐幣，式表誠心。", "筵輝麗璧，樂暢和音。", "仰惟靈鑒，俯察翹襟。"]'),
('ab8a64ab-eefa-489f-9e1b-c7a0139d77d3','郊廟歌辭 武后大享昊天樂章 六','不詳','唐','唐诗','tang','','[]','昭昭上帝，穆穆下臨。',42,'全唐诗/poet.tang.0.json','["昭昭上帝，穆穆下臨。", "禮崇備物，樂奏鏘金。", "蘭羞委薦，桂醑盈斟。", "敢希[明]德，聿罄莊心。"]'),
('48d76427-8d1c-425a-9425-e4d4a8751f74','郊廟歌辭 武后大享昊天樂章 七','不詳','唐','唐诗','tang','','[]','樽浮九醞，禮備三周。',20,'全唐诗/poet.tang.0.json','["樽浮九醞，禮備三周。", "陳誠菲奠，契福神猷。"]'),
('ed819c5a-6f20-4664-848c-026b360befff','郊廟歌辭 武后大享昊天樂章 八','不詳','唐','唐诗','tang','','[]','奠璧郊壇昭大禮，鏘金拊石表虔誠。',32,'全唐诗/poet.tang.0.json','["奠璧郊壇昭大禮，鏘金拊石表虔誠。", "始奏承雲娛帝賞，復歌調露暢韶英。"]'),
('795d1301-ccde-472c-b455-15ffe10b3004','郊廟歌辭 武后大享昊天樂章 九','不詳','唐','唐诗','tang','','[]','荷恩承顧託，執契恭臨撫。',48,'全唐诗/poet.tang.0.json','["荷恩承顧託，執契恭臨撫。", "廟畧靜邊荒，天兵耀神武。", "有截資先化，無爲遵舊矩。", "禎符降昊穹，大業光寰宇。"]'),
('4b1c3a1b-97f1-4ce5-8bf5-75b37731ddbd','郊廟歌辭 武后大享昊天樂章 十','不詳','唐','唐诗','tang','','[]','肅肅祀典，邕邕禮秩。',40,'全唐诗/poet.tang.0.json','["肅肅祀典，邕邕禮秩。", "三獻已周，九成斯畢。", "爰撤其俎，載遷其實。", "或升或降，唯誠唯質。"]'),
('4e91f0e6-2031-46cf-95a8-0c4a5326929d','郊廟歌辭 武后大享昊天樂章 十一','不詳','唐','唐诗','tang','','[]','禮終肆類，樂闋九成。',40,'全唐诗/poet.tang.0.json','["禮終肆類，樂闋九成。", "仰惟明德，敢薦非馨。", "顧慙菲奠，久駐雲軿。", "瞻荷靈澤，悚戀兼盈。"]'),
('97918258-9ba8-4799-b271-650864515192','郊廟歌辭 武后大享昊天樂章 十二','不詳','唐','唐诗','tang','','[]','式乾路，闢天扉。',32,'全唐诗/poet.tang.0.json','["式乾路，闢天扉。", "迴日馭，動雲衣。", "登金闕，入紫微。", "望仙駕，仰恩徽。"]'),
('ba51429a-7ee2-44d2-a01f-61013d90419b','郊廟歌辭 中宗祀昊天樂章 豫和','不詳','唐','唐诗','tang','','[]','天之曆數歸睿唐，顧惟菲德欽昊蒼。',32,'全唐诗/poet.tang.0.json','["天之曆數歸睿唐，顧惟菲德欽昊蒼。", "撰吉日兮表殷薦，冀神鑒兮降闓陽。"]'),
('d845d3ba-d5d3-4ef3-a84b-4770683908db','郊廟歌辭 中宗祀昊天樂章 太和','不詳','唐','唐诗','tang','','[]','恭臨寶位，肅奉瑤圖。',40,'全唐诗/poet.tang.0.json','["恭臨寶位，肅奉瑤圖。", "恆思解網，每軫泣辜。", "德慙巢燧，化劣唐虞。", "期我良弼，式贊嘉謨。"]'),
('8c0642c4-2103-4d80-bff2-3549978fb9f4','郊廟歌辭 中宗祀昊天樂章 告謝','不詳','唐','唐诗','tang','','[]','得一流玄澤，通三御紫宸。',48,'全唐诗/poet.tang.0.json','["得一流玄澤，通三御紫宸。", "遠叶千齡運，遐銷九域塵。", "絕瑞駢闐集，殊祥絡繹臻。", "登年慶棲畝，稔歲賀盈囷。"]'),
('7a8ae628-df5e-4f11-b2a8-be2124d2ed93','郊廟歌辭 中宗祀昊天樂章 肅和','不詳','唐','唐诗','tang','','[]','悠哉廣覆，大矣曲成。',40,'全唐诗/poet.tang.0.json','["悠哉廣覆，大矣曲成。", "九玄著象，七曜貞明。", "珪璧是奠，醞酎斯盈。", "作樂崇德，爰暢咸英。"]'),
('e6cc0718-825c-47a3-a19d-a0b1bfbe1331','郊廟歌辭 中宗祀昊天樂章 雍和','不詳','唐','唐诗','tang','','[]','郊壇展敬，嚴配因心。',40,'全唐诗/poet.tang.0.json','["郊壇展敬，嚴配因心。", "孤竹簫管，空桑瑟琴。", "肅穆大禮，鏗鏘八音。", "恭惟上帝，希降靈歆。"]'),
('28dc3d1b-25a2-4533-a001-db852a669fd3','郊廟歌辭 中宗祀昊天樂章 福和','不詳','唐','唐诗','tang','','[]','九成爰奏，三獻式陳。',20,'全唐诗/poet.tang.0.json','["九成爰奏，三獻式陳。", "欽承景福，恭託明禋。"]'),
('b14702e8-e102-450b-b1d3-af3ab5e77d5e','郊廟歌辭 中宗祀昊天樂章 中宮助祭升壇','不詳','唐','唐诗','tang','','[]','坤元光至德，柔訓闡皇風。',48,'全唐诗/poet.tang.0.json','["坤元光至德，柔訓闡皇風。", "芣苡芳聲遠，螽斯美化隆。", "睿範超千載，嘉猷備六宮。", "肅恭陪盛典，欽若薦禋宗。"]'),
('2bb1431e-2471-49d5-a033-e474d1731d34','郊廟歌辭 中宗祀昊天樂章 亞獻','不詳','唐','唐诗','tang','','[]','三靈降饗，三后配神。',20,'全唐诗/poet.tang.0.json','["三靈降饗，三后配神。", "虔敷藻奠，敬展郊禋。"]'),
('c19f1e4c-2b6f-44cf-8ee2-0993f3ef2cf7','郊廟歌辭 中宗祀昊天樂章 舒和','不詳','唐','唐诗','tang','','[]','已陳粢盛敷嚴祀，更奏笙鏞協雅聲。',32,'全唐诗/poet.tang.0.json','["已陳粢盛敷嚴祀，更奏笙鏞協雅聲。", "璇圖寶曆欣寧謐，晏俗淳風樂太平。"]'),
('07b5a141-ac22-4ade-8e0e-3266a8154880','郊廟歌辭 中宗祀昊天樂章 凱安','不詳','唐','唐诗','tang','','[]','堂堂聖祖興，赫赫昌基泰。',48,'全唐诗/poet.tang.0.json','["堂堂聖祖興，赫赫昌基泰。", "戎車盟津偃，玉帛塗山會。", "舜日啓祥暉，堯雲卷征斾。", "風猷被有截，聲教覃無外。"]'),
('70860658-4a7c-4f94-b2cc-80a5afe07c67','郊廟歌辭 明皇祀圜丘樂章 豫和','不詳','唐','唐诗','tang','','[]','至矣丕搆，烝哉太平。',40,'全唐诗/poet.tang.0.json','["至矣丕搆，烝哉太平。", "授犧膺籙，復禹繼明。", "草木仁化，鳧鷖頌聲。", "祀宗陳德，無媿斯誠。"]'),
('a0f686a7-7573-4a32-a6fe-cffd5febe323','郊廟歌辭 明皇祀圜丘樂章 太和','不詳','唐','唐诗','tang','','[]','郊壇齋帝，禮樂祀天。',40,'全唐诗/poet.tang.0.json','["郊壇齋帝，禮樂祀天。", "丹青寰宇，宮徵山川。", "神祇畢降，行止重旋。", "融融穆穆，納祉洪延。"]'),
('57fe80f8-d358-44eb-9b4f-7b9af4148431','郊廟歌辭 明皇祀圜丘樂章 肅和','不詳','唐','唐诗','tang','','[]','止奏潛聆，登儀宿囀。',40,'全唐诗/poet.tang.0.json','["止奏潛聆，登儀宿囀。", "太玉躬奉，參鍾首奠。", "簠簋聿昇，犧牲遰薦。", "昭事顒若，存存以俔。"]'),
('06ba9596-90d1-44ce-aa16-bc7ba88cdb84','郊廟歌辭 明皇祀圜丘樂章 雍和','不詳','唐','唐诗','tang','','[]','爛雲普洽，律風無外。',40,'全唐诗/poet.tang.0.json','["爛雲普洽，律風無外。", "千品其凝，九賓斯會。", "禋尊晉燭，純犧滌汰。", "玄覆攸廣，鴻休汪濊。"]'),
('6bb0f308-c254-4a99-9204-638f271b76cd','郊廟歌辭 明皇祀圜丘樂章 壽和','不詳','唐','唐诗','tang','','[]','六變爰闋，八階載虔。',20,'全唐诗/poet.tang.0.json','["六變爰闋，八階載虔。", "祐我皇祚，於萬斯年。"]'),
('d375ceb0-0d16-47bc-949f-92117c1345b5','郊廟歌辭 明皇祀圜丘樂章 壽和','不詳','唐','唐诗','tang','','[]','於赫聖祖，龍飛晉陽。',40,'全唐诗/poet.tang.0.json','["於赫聖祖，龍飛晉陽。", "底定萬國，奄有四方。", "功格上下，道冠農黃。", "郊天配享，德合無疆。"]'),
('5ff8a176-d073-43b5-91e6-02d651771f36','郊廟歌辭 明皇祀圜丘樂章 壽和','不詳','唐','唐诗','tang','','[]','崇崇泰畤，肅肅嚴禋。',40,'全唐诗/poet.tang.0.json','["崇崇泰畤，肅肅嚴禋。", "粢盛既潔，金石畢陳。", "上帝來享，介福爰臻。", "受釐合祉，寶祚維新。"]'),
('b182e586-b9ce-4809-bc35-1674c35735fa','郊廟歌辭 明皇祀圜丘樂章 舒和','不詳','唐','唐诗','tang','','[]','祝史正辭，人神叶慶。',40,'全唐诗/poet.tang.0.json','["祝史正辭，人神叶慶。", "福以德招，享以誠應。", "六變云備，百禮斯浹。", "祀事孔明，祚流萬葉。"]'),
('888bef78-958e-43fc-bd06-3e0acac0016d','郊廟歌辭 明皇祀圜丘樂章 凱安','不詳','唐','唐诗','tang','','[]','馨香惟后德，明命光天保。',36,'全唐诗/poet.tang.0.json','["馨香惟后德，明命光天保。", "肅和崇聖靈，陳信表皇道。", "玉鏚初蹈厲，金匏既靜好。"]'),
('caf25139-a8d2-4ba1-83e2-2fcfe60ff6a9','郊廟歌辭 明皇祀圜丘樂章 豫和','不詳','唐','唐诗','tang','','[]','大號成命，思文配天。',40,'全唐诗/poet.tang.0.json','["大號成命，思文配天。", "神光肸蠁，龍駕言旋。", "眇眇閶闔，昭昭上玄。", "俾昌而大，於斯萬年。"]'),
('9ac3f210-c74e-403b-ae09-f1f955c0642c','郊廟歌辭 明皇祀圜丘樂章 太和','不詳','唐','唐诗','tang','','[]','六成既闋，三薦云終。',40,'全唐诗/poet.tang.0.json','["六成既闋，三薦云終。", "神心具醉，聖敬愈崇。", "受釐皇邸，回蹕帷宮。", "穰穰之福，永永無窮。"]'),
('80b9bf77-80cf-41a1-8278-5e5b37dd5b3b','郊廟歌辭 封泰山樂章 豫和 一','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','款泰壇，柴泰清。',32,'全唐诗/poet.tang.0.json','["款泰壇，柴泰清。", "受天命，報天成。", "竦皇心，薦樂聲。", "志上達，歌下迎。"]'),
('4902d495-3ed3-4aa2-9c67-36a054455042','郊廟歌辭 封泰山樂章 豫和 二','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','億上帝，臨下庭。',32,'全唐诗/poet.tang.0.json','["億上帝，臨下庭。", "騎日月，陪列星。", "嘉祝信，大糦馨。", "澹神心，醉皇靈。"]'),
('dedab53e-3cb6-4689-a4e9-538a0aaeb005','郊廟歌辭 封泰山樂章 豫和 三','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','相百辟，貢八荒。',32,'全唐诗/poet.tang.0.json','["相百辟，貢八荒。", "九歌敍，萬舞翔。", "肅振振，鏗皇皇。", "帝欣欣，福穰穰。"]'),
('fd353d00-a484-4bb1-a4d7-e595fac0ea52','郊廟歌辭 封泰山樂章 豫和 四','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','高在上，道光明。',32,'全唐诗/poet.tang.0.json','["高在上，道光明。", "物資始，德難名。", "承眷命，牧蒼生。", "寰宇謐，太階平。"]'),
('8e1b1d18-0810-4f49-a7d3-8a6332a51183','郊廟歌辭 封泰山樂章 豫和 五','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','天道無親，至誠與鄰。',40,'全唐诗/poet.tang.0.json','["天道無親，至誠與鄰。", "山川遍禮，宮徵維新。", "玉帛非盛，聰明會真。", "正斯一德，通乎百神。"]'),
('0e12fbf7-ae7c-4b70-83b4-d442fe1b23da','郊廟歌辭 封泰山樂章 豫和 六','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','饗帝饗親，維孝維聖。',40,'全唐诗/poet.tang.0.json','["饗帝饗親，維孝維聖。", "緝熙懿德，敷揚成命。", "華夷志同，笙鏞禮盛。", "明靈降止，感此誠敬。"]'),
('22c07619-9423-4f39-be66-e5380527651b','郊廟歌辭 封泰山樂章 太和','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','孝敬中發，和容外彰。',40,'全唐诗/poet.tang.0.json','["孝敬中發，和容外彰。", "騰華照宇，如昇太陽。", "貞璧就奠，玄靈垂光。", "禮樂具舉，濟濟洋洋。"]'),
('6497789f-342b-4c89-b330-b32ee23cb12f','郊廟歌辭 封泰山樂章 肅和','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','奠祖配天，承天享帝。',40,'全唐诗/poet.tang.0.json','["奠祖配天，承天享帝。", "百靈咸秩，四海來祭。", "植我蒼璧，布我玄製。", "華日裴回，神煙容裔。"]'),
('6bd61d48-95a3-4505-a201-27a22d06f17a','郊廟歌辭 封泰山樂章 雍和','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','俎豆有馥，粢盛潔豐。',40,'全唐诗/poet.tang.0.json','["俎豆有馥，粢盛潔豐。", "亦有和羹，既戒既平。", "鐘鼓管磬，肅唱和鳴。", "皇皇后祖，來我思成。"]'),
('4a9c0b9d-b051-4f1b-b4b7-c6b70db36ea7','郊廟歌辭 封泰山樂章 壽和','張說','唐','唐诗','tang','','["\u6cf0\u5c71"]','烝烝我后，享獻惟夤。',40,'全唐诗/poet.tang.0.json','["烝烝我后，享獻惟夤。", "躬酌鬱鬯，跪奠明神。", "孝莫孝乎，配上帝親。", "敬莫敬乎，教天下臣。"]'),
