('8cd434d7-67ab-4501-8aac-e4a5e8b12dd2','郊廟歌辭 五郊樂章 送神','不詳','唐','唐诗','tang','','[]','春末冬暮，徂夏杪秋。',40,'全唐诗/poet.tang.0.json','["春末冬暮，徂夏杪秋。", "土王四月，時季一周。", "黍稷已享，籩豆宜收。", "送神有樂，神其賜休。"]'),
('dd068ad5-f70a-41f7-a86d-5c0d996a8399','郊廟歌辭 五郊樂章 青郊迎神','不詳','唐','唐诗','tang','','[]','緹幕移候，青郊啓蟄。',40,'全唐诗/poet.tang.0.json','["緹幕移候，青郊啓蟄。", "淑景遲遲，和風習習。", "璧玉宵備，旌旄曙立。", "張樂以迎，帝神其入。"]'),
('de487473-c634-4314-9fda-e5e945a0a5ed','郊廟歌辭 五郊樂章 送神','不詳','唐','唐诗','tang','','[]','文物流彩，聲明動色。',40,'全唐诗/poet.tang.0.json','["文物流彩，聲明動色。", "人竭其恭，靈昭其飭。", "歆薦不已，垂禎無極。", "送禮有章，惟神還軾。"]'),
('b7249156-73d3-4b95-b933-3459e0a25e81','郊廟歌辭 五郊樂章 赤郊迎神','不詳','唐','唐诗','tang','','[]','青陽節謝，朱明候改。',40,'全唐诗/poet.tang.0.json','["青陽節謝，朱明候改。", "靡草彫華，含桃流彩。", "虡列鐘磬，筵陳脯醢。", "樂以迎神，神其如在。"]'),
('ef97a37d-c849-407d-b894-0d5df341d0ea','郊廟歌辭 五郊樂章 送神','不詳','唐','唐诗','tang','','[]','炎精式降，蒼生攸仰。',40,'全唐诗/poet.tang.0.json','["炎精式降，蒼生攸仰。", "羞列豆籩，酒陳犧象。", "昭祀有應，冥期不爽。", "送樂張音，惟靈之往。"]'),
