('1de9de27-5232-4680-98d6-3e30c7966dcc','郊廟歌辭 五郊樂章 送神','不詳','唐','唐诗','tang','','[]','祀遵五禮，時屬三秋。',40,'全唐诗/poet.tang.0.json','["祀遵五禮，時屬三秋。", "人懷肅敬，靈降禎休。", "奠歆旨酒，薦享珍羞。", "載張送樂，神其上遊。"]'),
('67965bb4-4aa6-4bbd-969a-a032f1ddf24d','郊廟歌辭 五郊樂章 黑郊迎神','不詳','唐','唐诗','tang','','[]','玄英戒序，黑郊臨候。',40,'全唐诗/poet.tang.0.json','["玄英戒序，黑郊臨候。", "掌禮陳彝，司筵執豆。", "寒氛斂色，沍泉凝漏。", "樂以迎神，八音斯奏。"]'),
('de1e351b-f879-43c8-9eea-a3f31c6372d0','郊廟歌辭 五郊樂章 送神','不詳','唐','唐诗','tang','','[]','北郊時冽，南陸輝處。',40,'全唐诗/poet.tang.0.json','["北郊時冽，南陸輝處。", "奠本虔誠，獻彌恭慮。", "上延祉福，下承歡豫。", "廣樂送神，神其整馭。"]'),
('ce27f085-cc00-44d2-8bdd-2732050b6f44','郊廟歌辭 朝日樂章 肅和','不詳','唐','唐诗','tang','','[]','惟聖格天，惟明饗日。',40,'全唐诗/poet.tang.0.json','["惟聖格天，惟明饗日。", "帝郊肆類，王宮戒吉。", "珪奠春舒，鐘歌曉溢。", "禮云克備，斯文有秩。"]'),
