('74ad9d08-4bcb-4844-b9bf-897afeaeb5ad','郊廟歌辭 祀九宮貴神樂章 豫和 二','不詳','唐','唐诗','tang','','[]','黑帝旋馭，青躔導日。',40,'全唐诗/poet.tang.0.json','["黑帝旋馭，青躔導日。", "金籙上玄，玉堂初吉。", "鉤陳夕次，鑾和先蹕。", "藹藹羣靈，昭昭咸秩。"]'),
('7c3567ec-56b5-4ca3-be4a-0be999fa4cfa','郊廟歌辭 祀九宮貴神樂章 豫和 三','不詳','唐','唐诗','tang','','[]','帝臨中壇，受釐元神。',40,'全唐诗/poet.tang.0.json','["帝臨中壇，受釐元神。", "皇靈萃止，羽旄肅陳。", "攝提運衡，招搖移輪。", "光光宇宙，電耀雷震。"]'),
('a859f0e3-355f-4385-bde8-1c793381a587','郊廟歌辭 祀九宮貴神樂章 豫和 四','不詳','唐','唐诗','tang','','[]','夜如何其，明星煌煌。',40,'全唐诗/poet.tang.0.json','["夜如何其，明星煌煌。", "天清容衛，露結壇場。", "樹羽幢幢，佩玉鏘鏘。", "凝精駐目，瞻望神光。"]'),
('44c39cce-e882-45bc-bc05-8ab1f8c0baf7','郊廟歌辭 祀九宮貴神樂章 豫和 五','不詳','唐','唐诗','tang','','[]','九位既肅，萬靈畢會。',40,'全唐诗/poet.tang.0.json','["九位既肅，萬靈畢會。", "天門啓扄，日馭飛蓋。", "煥兮棽離，儐兮暗靄。", "如山之福，惟聖時對。"]'),
('73235558-2399-4730-b8d9-d7dafb45ac29','郊廟歌辭 祀九宮貴神樂章 豫和 六','不詳','唐','唐诗','tang','','[]','崇崇泰壇，靈具臨兮。',40,'全唐诗/poet.tang.0.json','["崇崇泰壇，靈具臨兮。", "鏗鍠大樂，振動心兮。", "神之降矣，卿雲郁兮。", "神之至止，清風肅兮。"]'),
('2ead7ead-cc7f-410c-8767-d2b8083079fe','郊廟歌辭 祀九宮貴神樂章 太和','不詳','唐','唐诗','tang','','[]','帝在靈壇，大明登光。',40,'全唐诗/poet.tang.0.json','["帝在靈壇，大明登光。", "天回雲粹，穆穆皇皇。", "金奏九夏，圭陳八薌。", "曠哉動植，如熙春陽。"]'),
