('ca30b92d-722c-42dc-89fd-f9a3316d3b9d','郊廟歌辭 祀九宮貴神樂章 雍和','不詳','唐','唐诗','tang','','[]','俎豆有踐，黃流在尊。',40,'全唐诗/poet.tang.0.json','["俎豆有踐，黃流在尊。", "九宮之祀，三代莫存。", "樂變六宮，壇開八門。", "聖皇昭對，祐我黎元。"]'),
('d9e99408-1966-4113-a6c0-10216d7de918','郊廟歌辭 祀九宮貴神樂章 壽和','不詳','唐','唐诗','tang','','[]','時文哲后，肅事嚴禋。',40,'全唐诗/poet.tang.0.json','["時文哲后，肅事嚴禋。", "馨我明德，享於貴神。", "大庖載盈，旨酒斯醇。", "精意所屬，期於利人。"]'),
('75ae8f5c-a3a8-4a62-9ad4-a0260250aa1f','郊廟歌辭 祀九宮貴神樂章 福和','不詳','唐','唐诗','tang','','[]','祀既云畢，明靈告旋。',40,'全唐诗/poet.tang.0.json','["祀既云畢，明靈告旋。", "禮洽和應，神歆福延。", "動植咸若，陰陽不愆。", "錫茲純嘏，天子萬年。"]'),
('a7cca728-ddd3-41a8-b38b-a29a3bfd6ab9','郊廟歌辭 祀九宮貴神樂章 舒和','不詳','唐','唐诗','tang','','[]','羽籥既闋干戚陳，八音克諧六變新。',32,'全唐诗/poet.tang.0.json','["羽籥既闋干戚陳，八音克諧六變新。", "愉貴神兮般以樂，保皇祚兮萬斯春。"]'),
