('ed30bc82-7666-4957-9e8b-6cda14f46dac','郊廟歌辭 祀風師樂章 迎俎酌獻','包佶','唐','唐诗','tang','','[]','德盛昭臨，迎拜巽方。',40,'全唐诗/poet.tang.0.json','["德盛昭臨，迎拜巽方。", "爰候發生，式薦馨香。", "酌醴具舉，工歌載揚。", "神歆六律，恩降百祥。"]'),
('76ea75c2-9fce-4c89-9452-c7f53343d43f','郊廟歌辭 祀風師樂章 亞獻終獻','包佶','唐','唐诗','tang','','[]','膋薌備，玉帛陳。',32,'全唐诗/poet.tang.0.json','["膋薌備，玉帛陳。", "風動物，樂感神。", "三獻終，百神臻。", "草木榮，天下春。"]'),
('fd76be6d-7ece-4852-94d3-381fae092e8f','郊廟歌辭 祀風師樂章 送神','包佶','唐','唐诗','tang','','[]','微穆敷華能應節，飄揚發彩宜行慶。',64,'全唐诗/poet.tang.0.json','["微穆敷華能應節，飄揚發彩宜行慶。", "送迎靈駕神心享，跪拜靈壇禮容盛。", "氣和草木發萌芽，德暢禽魚遂翔泳。", "永望翠蓋逐流雲，自茲率土調春令。"]'),
('e40f240c-8c10-410d-ba39-157d186b593b','郊廟歌辭 祀雨師樂章 迎神','包佶','唐','唐诗','tang','','[]','陟降左右，誠達幽圜。',40,'全唐诗/poet.tang.0.json','["陟降左右，誠達幽圜。", "作解之功，樂惟有年。", "雲軿戾止，灑霧飄煙。", "惟馨展禮，爰列豆籩。"]'),
('c721f02a-3227-4c0e-8506-8f7aa683399d','郊廟歌辭 祀雨師樂章 奠幣登歌','包佶','唐','唐诗','tang','','[]','歲正朱明，禮布元制。',40,'全唐诗/poet.tang.0.json','["歲正朱明，禮布元制。", "惟樂能感，與神合契。", "陰霧離翍，靈馭搖裔。", "膏澤之慶，期於稔歲。"]'),
('63f19307-80fe-4569-9f60-7c69d85d3672','郊廟歌辭 祀雨師樂章 迎俎酌獻','包佶','唐','唐诗','tang','','[]','陽開幽蟄，躬奉鬱鬯。',40,'全唐诗/poet.tang.0.json','["陽開幽蟄，躬奉鬱鬯。", "禮備節應，震來靈降。", "動植求聲，飛沈允望。", "時康氣茂，惟神之貺。"]'),
('7cb6c10b-4d17-4b83-99d8-f29cbdb84529','郊廟歌辭 祀雨師樂章 亞獻終獻','包佶','唐','唐诗','tang','','[]','奠既備，獻將終。',32,'全唐诗/poet.tang.0.json','["奠既備，獻將終。", "神行令，瑞飛空。", "迎乾德，祈歲功。", "乘煙燎，儼從風。"]'),
('2e2bb285-70d5-4a1c-9fc4-78be6c5f811d','郊廟歌辭 祀雨師樂章 送神','包佶','唐','唐诗','tang','','[]','整駕昇車望寥廓，垂陰薦祉蕩昏氛。',64,'全唐诗/poet.tang.0.json','["整駕昇車望寥廓，垂陰薦祉蕩昏氛。", "饗時靈貺僾如在，樂罷餘聲遙可聞。", "飲福陳誠禮容備，撤俎終獻曙光分。", "跪拜臨壇結空想，年年應節候油雲。"]'),
('d4e88f07-0b85-4b8d-b243-ff17ce413e33','郊廟歌辭 祭方丘樂章 順和','褚亮','唐','唐诗','tang','','[]','萬方資以化，交泰屬昇平。',48,'全唐诗/poet.tang.0.json','["萬方資以化，交泰屬昇平。", "易從業惟簡，得一道斯寧。", "具儀光玉帛，送舞變咸英。", "黍稷良非貴，明德信惟馨。"]'),
('44cc1286-e8d7-4374-8cb6-96067c6a09fa','郊廟歌辭 祭方丘樂章 肅和','褚亮','唐','唐诗','tang','','[]','至矣坤德，皇哉地祇。',40,'全唐诗/poet.tang.0.json','["至矣坤德，皇哉地祇。", "開元統紐，合大承規。", "九宮肅列，六典相儀。", "永言配命，長保無虧。"]'),
('e817249e-2008-482a-b5b9-b1afeb1fead6','郊廟歌辭 祭方丘樂章 雍和','褚亮','唐','唐诗','tang','','[]','柔而能方，直而能敬。',40,'全唐诗/poet.tang.0.json','["柔而能方，直而能敬。", "載厚以德，大亨以正。", "有滌斯牷，有馨斯盛。", "介茲景福，祚我休慶。"]'),
('bfb12894-0564-4e10-af0e-17f0d58cec07','郊廟歌辭 祭方丘樂章 舒和','褚亮','唐','唐诗','tang','','[]','玉幣牲牷分薦享，羽旄干鏚遰成容。',32,'全唐诗/poet.tang.0.json','["玉幣牲牷分薦享，羽旄干鏚遰成容。", "一德惟寧兩儀泰，三才保合四時邕。"]'),
('98035eea-d155-46b8-aca0-45c7a343993c','郊廟歌辭 祭方丘樂章 順和','褚亮','唐','唐诗','tang','','[]','陰祇協贊，厚載方貞。',40,'全唐诗/poet.tang.0.json','["陰祇協贊，厚載方貞。", "牲幣具舉，簫管備成。", "其禮惟肅，其德惟明。", "神之聽矣，式鑒虔誠。"]'),
('6aa54435-8335-4fff-959a-c6b92f8d9080','郊廟歌辭 武后大享拜洛樂章 昭和','不詳','唐','唐诗','tang','','[]','九玄眷命，三聖基隆。',40,'全唐诗/poet.tang.0.json','["九玄眷命，三聖基隆。", "奉承先旨，明臺畢功。", "宗祀展敬，冀表深衷。", "永昌帝業，式播淳風。"]'),
('67cecd8e-3739-47ab-a664-a3181bc2fc5c','郊廟歌辭 武后大享拜洛樂章 致和','不詳','唐','唐诗','tang','','[]','神功不測兮運陰陽，包藏萬宇兮孕八荒。',36,'全唐诗/poet.tang.0.json','["神功不測兮運陰陽，包藏萬宇兮孕八荒。", "天符既出兮帝業昌，願臨明祀兮降禎祥。"]'),
('5c7a41e6-d997-46f3-a6b2-bac41d354e35','郊廟歌辭 武后大享拜洛樂章 咸和','不詳','唐','唐诗','tang','','[]','坎澤祠容備舉，坤壇祭典爰申。',49,'全唐诗/poet.tang.0.json','["坎澤祠容備舉，坤壇祭典爰申。", "靈睠遙行祕躅，嘉貺荐委殊珍。", "肅禮恭禋載展，翹襟邈志逾殷。", "方期交際懸應。"]'),
('e23a8660-0f59-4a83-8593-28fe70439e76','郊廟歌辭 武后大享拜洛樂章 九和','不詳','唐','唐诗','tang','','[]','祗荷坤德，欽若乾靈。',40,'全唐诗/poet.tang.0.json','["祗荷坤德，欽若乾靈。", "慙惕罔寘，興居匪寧。", "恭崇禮則，肅奉儀形。", "惟憑展敬，敢薦非馨。"]'),
('327ba2ad-484a-4131-b902-17b0938ea157','郊廟歌辭 武后大享拜洛樂章 顯和','不詳','唐','唐诗','tang','','[]','菲躬承睿顧，薄德忝坤儀。',48,'全唐诗/poet.tang.0.json','["菲躬承睿顧，薄德忝坤儀。", "乾乾遵後命，翼翼奉先規。", "撫俗勤雖切，還淳化尚虧。", "未能弘至道，何以契明祇。"]'),
('b815af7f-d48d-4db1-9b2f-22cb3117497d','郊廟歌辭 武后大享拜洛樂章 顯和','不詳','唐','唐诗','tang','','[]','顧德有慙虛菲，明祇屢降禎符。',42,'全唐诗/poet.tang.0.json','["顧德有慙虛菲，明祇屢降禎符。", "汜水初呈祕象，溫洛薦表昌圖。", "玄澤流恩載洽，丹襟荷渥增愉。"]'),
('6a86c51e-e062-44b9-bf59-a3f54c997775','郊廟歌辭 武后大享拜洛樂章 昭和','不詳','唐','唐诗','tang','','[]','舒陰致養，合大資生。',40,'全唐诗/poet.tang.0.json','["舒陰致養，合大資生。", "德以恆固，功由永貞。", "升歌薦序，垂幣翹誠。", "虹開玉照，鳳引金聲。"]'),
('5c1c4e9f-9c4c-45e6-8931-886636ca1ce8','郊廟歌辭 武后大享拜洛樂章 敬和','不詳','唐','唐诗','tang','','[]','蘭俎既昇，蘋羞可薦。',40,'全唐诗/poet.tang.0.json','["蘭俎既昇，蘋羞可薦。", "金石載設，咸英已變。", "林澤斯總，山川是遍。", "敢用敷誠，實惟忘倦。"]'),
('47041f69-1316-4058-9660-f47427973d22','郊廟歌辭 武后大享拜洛樂章 齊和','不詳','唐','唐诗','tang','','[]','沈潛演貺分三極，廣大凝禎總萬方。',32,'全唐诗/poet.tang.0.json','["沈潛演貺分三極，廣大凝禎總萬方。", "既薦羽旌文化啓，還呈干鏚武威揚。"]'),
('a69e1314-b376-449b-9db5-58233b8c54d0','郊廟歌辭 武后大享拜洛樂章 德和','不詳','唐','唐诗','tang','','[]','夕惕司龍契，晨兢當鳳扆。',48,'全唐诗/poet.tang.0.json','["夕惕司龍契，晨兢當鳳扆。", "崇儒習舊規，偃伯循先旨。", "絕壤飛冠蓋，遐區麗山水。", "幸承三聖餘，忻屬千年始。"]'),
('dad4a5b3-fa77-4fd3-8967-62bc7ca721ac','郊廟歌辭 武后大享拜洛樂章 禋和','不詳','唐','唐诗','tang','','[]','百禮崇容，千官肅事。',40,'全唐诗/poet.tang.0.json','["百禮崇容，千官肅事。", "靈降無兆，神凝有粹。", "奠享咸周，威儀畢備。", "奏夏登列，歌雍徹肆。"]'),
('ca5a942e-3be3-43f9-b962-847374e44b02','郊廟歌辭 武后大享拜洛樂章 通和','不詳','唐','唐诗','tang','','[]','皇皇靈睠，穆穆神心。',40,'全唐诗/poet.tang.0.json','["皇皇靈睠，穆穆神心。", "暫動凝質，還歸積陰。", "功玄樞紐，理寂高深。", "銜恩佩德，聳志翹襟。"]'),
('903b1584-af9d-4ac6-a017-4df18161929c','郊廟歌辭 武后大享拜洛樂章 歸和','不詳','唐','唐诗','tang','','[]','言旋雲洞兮躡煙途，永寧中宇兮安下都。',36,'全唐诗/poet.tang.0.json','["言旋雲洞兮躡煙途，永寧中宇兮安下都。", "包涵動植兮順榮枯，長貽寶貺兮贊璇圖。"]'),
('1c4d57af-c114-4c20-afc4-5f7d1c79c9c6','郊廟歌辭 武后大享拜洛樂章 又歸和','不詳','唐','唐诗','tang','','[]','調雲闋兮神座興，驂雲駕兮儼將昇。',32,'全唐诗/poet.tang.0.json','["調雲闋兮神座興，驂雲駕兮儼將昇。", "騰絳霄兮垂景祐，翹丹懇兮荷休徵。"]'),
('a5616d09-2763-4ec5-9f72-1eb3992c6bff','郊廟歌辭 祭方丘樂章 順和','不詳','唐','唐诗','tang','','[]','坤厚載物，德柔垂祉。',40,'全唐诗/poet.tang.0.json','["坤厚載物，德柔垂祉。", "九域咸雍，四溟爲紀。", "敬因良節，虔修陰祀。", "廣樂式張，靈其降止。"]'),
('7c643aeb-d85f-4619-87e5-ba68c9880228','郊廟歌辭 祭方丘樂章 金奏','不詳','唐','唐诗','tang','','[]','坤元至德，品物資生。',40,'全唐诗/poet.tang.0.json','["坤元至德，品物資生。", "神凝博厚，道協高明。", "列鎮五嶽，環流四瀛。", "于何不載，萬寶斯成。"]'),
('c17456c2-eeda-45aa-a9ae-41981d4dca57','郊廟歌辭 祭方丘樂章 順和','不詳','唐','唐诗','tang','','[]','樂備金石，禮光尊俎。',40,'全唐诗/poet.tang.0.json','["樂備金石，禮光尊俎。", "大享爰終，洪休是舉。", "雨零感節，雲飛應序。", "纓紱載辭，皇靈具舉。"]'),
('1ad5a5b5-d7d7-4678-a728-02e11204bc29','郊廟歌辭 祭汾陰樂章 順和','林鍾宮','唐','唐诗','tang','','[]','大樂和暢，殷薦明神。',40,'全唐诗/poet.tang.0.json','["大樂和暢，殷薦明神。", "一降通感，八變必臻。", "有求斯應，無德不親。", "降靈醉止，休徵萬人。"]'),
('b82134e2-ef7b-41be-be33-96703019de32','郊廟歌辭 祭汾陰樂章 太簇角','盧從愿','唐','唐诗','tang','','[]','坤元載物，陽樂發生。',40,'全唐诗/poet.tang.0.json','["坤元載物，陽樂發生。", "播殖資始，品彙咸亨。", "列俎棋布，方壇砥平。", "神歆禋祀，后德惟明。"]'),
('c5a37461-128d-40ab-ac19-dc2231d5fc61','郊廟歌辭 祭汾陰樂章 姑洗徵','劉晃','唐','唐诗','tang','','[]','大君出震，有事郊禋。',40,'全唐诗/poet.tang.0.json','["大君出震，有事郊禋。", "齋戒既肅，馨香畢陳。", "樂和禮備，候暖風春。", "恭惟降福，實賴明神。"]'),
('ce5de9eb-170d-4efc-a629-caf1172d66ab','郊廟歌辭 祭汾陰樂章 南呂羽','韓休','唐','唐诗','tang','','[]','於穆濬哲，維清緝熙。',40,'全唐诗/poet.tang.0.json','["於穆濬哲，維清緝熙。", "肅事昭配，永言孝思。", "滌濯靜嘉，馨香在茲。", "神之聽之，用受福釐。"]'),
('b8d19e39-7b1f-4e69-89b9-65c63ac96963','郊廟歌辭 祭汾陰樂章 太和','王晙','唐','唐诗','tang','','[]','於穆聖皇，六葉重光。',40,'全唐诗/poet.tang.0.json','["於穆聖皇，六葉重光。", "太原刻頌，后土疎場。", "寶鼎呈符，歊雲孕祥。", "禮樂備矣，降福穰穰。"]'),
('f2ed282e-8ac4-43a9-bc5c-14aa2b39591d','郊廟歌辭 祭汾陰樂章 肅和','崔玄童','唐','唐诗','tang','','[]','聿修嚴配，展事禋宗。',42,'全唐诗/poet.tang.0.json','["聿修嚴配，展事禋宗。", "祥符寶鼎，禮備黃琮。", "[祝]詞以信，明德惟聰。", "介茲景福，永永無窮。"]'),
('6c9b601a-649e-4380-8ce3-14e8d40b841f','郊廟歌辭 祭汾陰樂章 雍和','賈曾','唐','唐诗','tang','','[]','蠲我饎餴，絜我膋薌。',40,'全唐诗/poet.tang.0.json','["蠲我饎餴，絜我膋薌。", "有豆孔碩，爲羞既臧。", "至誠無昧，精意惟芳。", "神其醉止，欣欣樂康。"]'),
('a9e54c24-f9ba-454c-872f-356e5bbe0986','郊廟歌辭 祭汾陰樂章 壽和','蘇頲','唐','唐诗','tang','','[]','禮物斯具，樂章乃陳。',40,'全唐诗/poet.tang.0.json','["禮物斯具，樂章乃陳。", "誰其作主，皇考聖真。", "對越在天，聖明佐神。", "窅然汾上，厚澤如春。"]'),
('bb7ce140-36ff-4da2-b753-c91987b4aec6','郊廟歌辭 祭汾陰樂章 舒和','何鸞','唐','唐诗','tang','','[]','樂奏云闋，禮章載虔。',40,'全唐诗/poet.tang.0.json','["樂奏云闋，禮章載虔。", "禋宗於地，昭假於天。", "惟馨薦矣，既醉歆焉。", "神之降福，永永萬年。"]'),
('e263b90b-b39e-4eb7-a648-5f7f2b74db68','郊廟歌辭 祭汾陰樂章 凱安','蔣挺','唐','唐诗','tang','','[]','維歲之吉，維辰之良。',42,'全唐诗/poet.tang.0.json','["維歲之吉，維辰之良。", "聖君紱冕，肅事壇場。", "大禮已備，大樂斯[張]。", "神其醉止，降福無疆。"]'),
('f7ba4362-047b-40e8-8a43-17e6a1d93ca2','郊廟歌辭 祭汾陰樂章 順和','源光裕','唐','唐诗','tang','','[]','方丘既膳，嘉饗載謐。',40,'全唐诗/poet.tang.0.json','["方丘既膳，嘉饗載謐。", "齊敬畢誠，陶匏貴質。", "秀畢豐薦，芳俎盈實。", "永永福流，其昇如日。"]'),
('089b535d-2b28-486b-b58d-d8a3670c83b2','郊廟歌辭 禪社首樂章 順和','賀知章、源乾曜','唐','唐诗','tang','','["\u6292\u60c5", "\u53d9\u4e8b", "\u5199\u666f"]','至哉含柔德，萬物資以生。',48,'全唐诗/poet.tang.0.json','["至哉含柔德，萬物資以生。", "常順稱厚載，流謙通變盈。", "聖心事能察，增廣陳厥誠。", "黃祇僾如在，泰折俟咸亨。"]'),
('187bb2c5-4648-43a5-9361-e1b3a8aa65f8','郊廟歌辭 禪社首樂章 太和','賀知章、源乾曜','唐','唐诗','tang','','[]','肅我成命，於昭黃祇。',40,'全唐诗/poet.tang.0.json','["肅我成命，於昭黃祇。", "裘冕而祀，陟降在斯。", "五音克備，八音聿施。", "緝熙肆靖，厥心匪離。"]'),
('22e1c91f-ce17-4cb1-8ea4-b10773525c5c','郊廟歌辭 禪社首樂章 肅和','賀知章、源乾曜','唐','唐诗','tang','','[]','黃祇是[祗]，我其夙夜。',42,'全唐诗/poet.tang.0.json','["黃祇是[祗]，我其夙夜。", "寅畏誠絜，匪遑寧舍。", "禮以琮玉，薦厥茅藉。", "念茲降康，胡寧克暇。"]'),
('c3ef6911-ab4b-41fb-9614-1fc519b996d1','郊廟歌辭 禪社首樂章 雍和','賀知章、源乾曜','唐','唐诗','tang','','[]','夙夜宥密，不敢寧宴。',40,'全唐诗/poet.tang.0.json','["夙夜宥密，不敢寧宴。", "五齊既陳，八音在縣。", "粢盛以潔，房俎斯薦。", "惟德惟馨，尚茲克徧。"]'),
('e110a26e-5f86-457d-838d-2566c1d9269e','郊廟歌辭 禪社首樂章 壽和','賀知章、源乾曜','唐','唐诗','tang','','[]','惟以明發，有懷載殷。',40,'全唐诗/poet.tang.0.json','["惟以明發，有懷載殷。", "樂盈而反，禮順其禋。", "立清以獻，薦欲是親。", "於穆不已，裒對斯臻。"]'),
('3c19217c-7f07-45f9-b317-3744725dc11c','郊廟歌辭 禪社首樂章 福和','賀知章、源乾曜','唐','唐诗','tang','','["\u6cf0\u5c71"]','穆穆天子，告成岱宗。',40,'全唐诗/poet.tang.0.json','["穆穆天子，告成岱宗。", "大裘如濡，執珽有顒。", "樂以平志，禮以和容。", "上帝臨我，云胡肅邕。"]'),
('ab812eee-9ec2-43c1-8f1e-98ccbe583ede','郊廟歌辭 禪社首樂章 太和','賀知章、源乾曜','唐','唐诗','tang','','[]','昭昭有唐，天俾萬國。',40,'全唐诗/poet.tang.0.json','["昭昭有唐，天俾萬國。", "列祖應命，四宗順則。", "申錫無疆，宗我同德。", "曾孫繼序，享神配極。"]'),
('0e1af8d7-0b33-4175-b3a3-4ddeebe8703a','郊廟歌辭 禪社首樂章 靈具醉','賀知章、源乾曜','唐','唐诗','tang','','[]','靈具醉，杳熙熙。',32,'全唐诗/poet.tang.0.json','["靈具醉，杳熙熙。", "靈將往，眇禗禗。", "顧明德，吐正辭。", "爛遺光，流禎祺。"]'),
('f969fcea-2dd7-4d7b-8257-8f228da97489','郊廟歌辭 祭神州樂章 肅和','褚亮','唐','唐诗','tang','','[]','大矣坤儀，至哉神縣。',40,'全唐诗/poet.tang.0.json','["大矣坤儀，至哉神縣。", "包含日域，牢籠月竁。", "露絜三清，風調六變。", "皇祇介祉，式歆恭薦。"]'),
('06d1e418-5974-47f5-9855-5b2976a02345','郊廟歌辭 祭神州樂章 雍和','褚亮','唐','唐诗','tang','','[]','泰折嚴享，陰郊展敬。',40,'全唐诗/poet.tang.0.json','["泰折嚴享，陰郊展敬。", "禮以導神，樂以和性。", "黝牲在列，黃琮俯暎。", "九土既平，萬邦貽慶。"]'),
('ad3c4762-ee21-4eaf-a31d-d553075afdfb','郊廟歌辭 祭神州樂章 舒和','褚亮','唐','唐诗','tang','','[]','坤道降祥和庶品，靈心載德厚羣生。',32,'全唐诗/poet.tang.0.json','["坤道降祥和庶品，靈心載德厚羣生。", "水土既調三極泰，文武畢備九區平。"]'),
('c7b4ab4c-0e3f-4fa0-b1e1-09b4e98fc4ac','郊廟歌辭 祭神州樂章 迎神','不詳','唐','唐诗','tang','','[]','黃輿厚載，赤寰歸德。',40,'全唐诗/poet.tang.0.json','["黃輿厚載，赤寰歸德。", "含育九區，保安萬國。", "誠敬無怠，禋祀有則。", "樂以迎神，其儀不忒。"]'),
('d70c3690-62ad-4004-b45e-6bb39c53f844','郊廟歌辭 祭神州樂章 送神','不詳','唐','唐诗','tang','','[]','神州陰祀，洪恩廣濟。',40,'全唐诗/poet.tang.0.json','["神州陰祀，洪恩廣濟。", "草樹霑和，飛沈沐惠。", "禮修鼎俎，奠歆瑤幣。", "送樂有章，靈軒其逝。"]'),
('b5d4951c-59b8-4760-986a-7148a540990f','郊廟歌辭 祭[太]社樂章 肅和','褚亮','唐','唐诗','tang','','[]','后土凝德，神功協契。',40,'全唐诗/poet.tang.0.json','["后土凝德，神功協契。", "九域底平，兩儀交際。", "戊期應序，陰墉展幣。", "靈車少留，俯歆樽桂。"]'),
('4e16514b-49db-4319-a118-d8a6e866e300','郊廟歌辭 祭[太]社樂章 雍和','褚亮','唐','唐诗','tang','','[]','美報崇本，嚴恭展事。',40,'全唐诗/poet.tang.0.json','["美報崇本，嚴恭展事。", "受露疎壇，承風啓地。", "絜粢登俎，醇犧入饋。", "介福遠流，羣生畢遂。"]'),
('3ea3afb2-2d7f-49c2-86d7-f7bc456a95b0','郊廟歌辭 祭[太]社樂章 舒和','褚亮','唐','唐诗','tang','','[]','神道發生敷九稼，陰極乘仁暢八埏。',32,'全唐诗/poet.tang.0.json','["神道發生敷九稼，陰極乘仁暢八埏。", "緯武經文隆景化，登祥薦祉啓豐年。"]'),
('e5d1f782-e5e2-44b0-9b08-7aff1e502a52','郊廟歌辭 祭大社樂章 迎神','不詳','唐','唐诗','tang','','[]','烈山有子，后土有臣。',40,'全唐诗/poet.tang.0.json','["烈山有子，后土有臣。", "播種百穀，濟育兆人。", "春官緝禮，宗伯司禋。", "戊爲吉日，迎享茲辰。"]'),
('24cd0f32-73a5-4845-b3ad-91745863b6c9','郊廟歌辭 祭大社樂章 送神','不詳','唐','唐诗','tang','','[]','吉祥式就，酬功載畢。',40,'全唐诗/poet.tang.0.json','["吉祥式就，酬功載畢。", "親地尊天，禮文經術。", "貺徵令序，福流初日。", "神馭爰歸，祠官其出。"]'),
('8006371c-8fd6-4529-973b-8c10b8b0d68b','郊廟歌辭 蜡百神樂章 肅和','不詳','唐','唐诗','tang','','[]','序迫歲陰，日躔星紀。',40,'全唐诗/poet.tang.0.json','["序迫歲陰，日躔星紀。", "爰稽茂典，聿崇清祀。", "綺幣霞舒，瑞珪虹起。", "百禩垂裕，萬靈薦祉。"]'),
('d441fe0d-554f-42aa-9e65-272f75f506e3','郊廟歌辭 蜡百神樂章 雍和','不詳','唐','唐诗','tang','','[]','緹籥勁序，玄英晚候。',40,'全唐诗/poet.tang.0.json','["緹籥勁序，玄英晚候。", "姬蜡開儀，豳歌入奏。", "蕙馥雕俎，蘭芬玉酎。", "大享明祇，永綏多祐。"]'),
('743645c1-d6de-4101-8366-5863356dfb22','郊廟歌辭 蜡百神樂章 舒和','不詳','唐','唐诗','tang','','[]','經緯兩儀文化洽，削平方域武功成。',32,'全唐诗/poet.tang.0.json','["經緯兩儀文化洽，削平方域武功成。", "瑤弦自樂乾坤泰，玉鏚長歡區宇寧。"]'),
('bce616a3-7b02-4cbd-a8da-7138e7c8114e','郊廟歌辭 蜡百神樂章 迎神','不詳','唐','唐诗','tang','','[]','八蜡開祭，萬物合祀。',40,'全唐诗/poet.tang.0.json','["八蜡開祭，萬物合祀。", "上極天維，下窮坤紀。", "鼎俎流芬，罇彝薦美。", "有靈有祇，咸希來止。"]'),
('2018c223-52fe-41f5-bdb9-68c152fb4835','郊廟歌辭 蜡百神樂章 送神','不詳','唐','唐诗','tang','','[]','十旬歡洽，一日祠終。',40,'全唐诗/poet.tang.0.json','["十旬歡洽，一日祠終。", "澄彝拂俎，報德酬功。", "慮虔容肅，禮縟儀豐。", "神其降祉，整馭隨風。"]'),
('4f2d62ab-804e-46d4-b5c9-567328452dc4','郊廟歌辭 享先農樂章 咸和','褚亮','唐','唐诗','tang','','[]','粒食伊始，農之所先。',40,'全唐诗/poet.tang.0.json','["粒食伊始，農之所先。", "古今攸賴，是曰人天。", "耕斯帝籍，播厥公田。", "式崇明祀，神其福焉。"]'),
('be5e396e-7e85-43bd-95e9-b016642f6186','郊廟歌辭 享先農樂章 肅和','褚亮','唐','唐诗','tang','','[]','樽彝既列，瑚簋方薦。',40,'全唐诗/poet.tang.0.json','["樽彝既列，瑚簋方薦。", "歌工載登，幣禮斯奠。", "肅肅享祀，顒顒纓弁。", "神之聽之，福流寰縣。"]'),
('c509642d-6de2-48b7-89dd-cc55ee3d84a3','郊廟歌辭 享先農樂章 雍和','褚亮','唐','唐诗','tang','','[]','前夕視牲，質明奉俎。',40,'全唐诗/poet.tang.0.json','["前夕視牲，質明奉俎。", "沐芳整弁，其儀式序。", "盛禮畢陳，嘉樂備舉。", "歆我懿德，非馨稷黍。"]'),
('8c8af1df-4b92-4010-b723-32326a23bf82','郊廟歌辭 享先農樂章 舒和','褚亮','唐','唐诗','tang','','[]','羽籥低昂文綴已，干戚蹈厲武行初。',32,'全唐诗/poet.tang.0.json','["羽籥低昂文綴已，干戚蹈厲武行初。", "望歲祈農神所聽，延祥介福豈云虛。"]'),
('c59b71b4-9c2a-4ee1-9fa7-385f8fe27ad9','郊廟歌辭 享先農樂章 咸和','不詳','唐','唐诗','tang','','[]','三推禮就，萬庾祈凝。',40,'全唐诗/poet.tang.0.json','["三推禮就，萬庾祈凝。", "夤賓志遠，藨衮惟興。", "降歆肅薦，垂祐祗膺。", "送神有樂，神其上昇。"]'),
('2768e7c5-c9dd-4054-8ce2-a0a82e063ba1','郊廟歌辭 享先蠶樂章 永和','不詳','唐','唐诗','tang','','[]','芳春開令序，韶苑暢和風。',48,'全唐诗/poet.tang.0.json','["芳春開令序，韶苑暢和風。", "惟靈申廣祐，利物表神功。", "綺會周天宇，黼黻藻寰中。", "庶幾承慶節，歆奠下帷宮。"]'),
('21ecddbf-197c-4098-be7b-c79a907408f0','郊廟歌辭 享先蠶樂章 肅和','不詳','唐','唐诗','tang','','[]','明靈光至德，深功掩百神。',48,'全唐诗/poet.tang.0.json','["明靈光至德，深功掩百神。", "祥源應節啓，福緒逐年新。", "萬宇承恩覆，七廟佇恭禋。", "于茲申至懇，方期遠慶臻。"]'),
('ad1c2f33-55e1-410d-a3f1-5d661498c129','郊廟歌辭 享先蠶樂章 展敬','不詳','唐','唐诗','tang','','[]','霞莊列寶衛，雲集動和聲。',48,'全唐诗/poet.tang.0.json','["霞莊列寶衛，雲集動和聲。", "金卮薦綺席，玉幣委芳庭。", "因心罄丹款，先己勵蒼生。", "所冀延明福，於茲享至誠。"]'),
('95f75391-e77c-421b-9cc0-6b96cc319e1c','郊廟歌辭 享先蠶樂章 絜誠','不詳','唐','唐诗','tang','','[]','桂筵開玉俎，蘭圃薦瓊芳。',48,'全唐诗/poet.tang.0.json','["桂筵開玉俎，蘭圃薦瓊芳。", "八音調鳳曆，三獻奉鸞觴。", "絜粢申大享，庭宇冀降祥。", "神其覃有慶，契福永無疆。"]'),
('3df7186e-9419-4cd7-81b0-3f8eafda73e1','郊廟歌辭 享先蠶樂章 昭慶','不詳','唐','唐诗','tang','','[]','仙壇禮既畢，神駕儼將昇。',48,'全唐诗/poet.tang.0.json','["仙壇禮既畢，神駕儼將昇。", "佇屬深祥起，方期庶績凝。", "虔誠資宇內，務本勖黎蒸。", "靈心昭備享，率土洽休徵。"]'),
('9fa19c0d-5c19-4494-bcca-e56c3151c36b','郊廟歌辭 釋奠文宣王樂章 誠和','不詳','唐','唐诗','tang','','[]','聖道日用，神幾不測。',40,'全唐诗/poet.tang.0.json','["聖道日用，神幾不測。", "金石以陳，弦歌載陟。", "爰釋其菜，匪馨于稷。", "來顧來享，是宗是極。"]'),
('c8b5b494-9707-4004-8646-caf765ef20b8','郊廟歌辭 釋奠文宣王樂章 承和','不詳','唐','唐诗','tang','','[]','萬國以貞光上嗣，三善茂德表重輪。',32,'全唐诗/poet.tang.0.json','["萬國以貞光上嗣，三善茂德表重輪。", "視膳寢門尊要道，高闢崇賢引正人。"]'),
('e5c8f884-6a1c-4336-b457-9f84b56797a3','郊廟歌辭 釋奠文宣王樂章 肅和','不詳','唐','唐诗','tang','','[]','粤惟上聖，有縱自天。',40,'全唐诗/poet.tang.0.json','["粤惟上聖，有縱自天。", "傍周萬物，俯應千年。", "舊章允著，嘉贄孔虔。", "王化茲首，儒風是宣。"]'),
('cf401a0e-dbe5-49ad-837f-403e55314b41','郊廟歌辭 釋奠文宣王樂章 雍和','不詳','唐','唐诗','tang','','[]','堂獻瑤篚，庭敷璆縣。',40,'全唐诗/poet.tang.0.json','["堂獻瑤篚，庭敷璆縣。", "禮備其容，樂和其變。", "肅肅親享，雍雍執奠。", "明德惟馨，蘋蘩可薦。"]'),
('1b5f1748-0c57-4ee8-8e49-980d85ba3fa0','郊廟歌辭 釋奠文宣王樂章 舒和','不詳','唐','唐诗','tang','','[]','隼集龜開昭聖烈，龍蹲鳳跱肅神儀。',32,'全唐诗/poet.tang.0.json','["隼集龜開昭聖烈，龍蹲鳳跱肅神儀。", "尊儒敬業宏圖闡，緯武經文盛德施。"]'),
('c42c018c-b12b-4cd5-8cda-b3141fdbd036','郊廟歌辭 享孔子廟樂章 迎神','不詳','唐','唐诗','tang','','[]','通吳表聖，問老探真。',40,'全唐诗/poet.tang.0.json','["通吳表聖，問老探真。", "三千弟子，五百賢人。", "億齡規法，萬載嗣禋。", "潔誠以祭，奏樂迎神。"]'),
('51112703-7fe7-4e72-afa1-c0f46be39947','郊廟歌辭 享孔子廟樂章 送神','不詳','唐','唐诗','tang','','[]','醴溢犧象，羞陳俎豆。',40,'全唐诗/poet.tang.0.json','["醴溢犧象，羞陳俎豆。", "魯壁類聞，泗川入覯。", "里校覃福，胄筵承祐。", "雅樂清音，送神具奏。"]'),
('07dfbf80-7b02-4ce1-8bf5-db426350aeed','郊廟歌辭 釋奠武成王樂章 迎神','于邵','唐','唐诗','tang','','[]','卜畋不從，兆發非熊。',50,'全唐诗/poet.tang.0.json','["卜畋不從，兆發非熊。", "乃傾荒政，爰佐一戎。", "盛烈載垂，命祀惟崇。", "日練上戊，宿嚴閟宮。", "迎奏嘉至，感而遂通。"]'),
('06ac6e8f-cc16-4f18-8e80-709cf2282987','郊廟歌辭 釋奠武成王樂章 奠幣登歌','于邵','唐','唐诗','tang','','[]','管磬升，羶薌集。',48,'全唐诗/poet.tang.0.json','["管磬升，羶薌集。", "上公進，嘉幣執。", "信以通，僾如及。", "恢帝功，錫后邑。", "四維張，百度立。", "綿億載，邈難挹。"]'),
('b9d3edd9-a17c-47ce-b299-241f611917cd','郊廟歌辭 釋奠武成王樂章 迎俎酌獻','于邵','唐','唐诗','tang','','[]','五齊潔，九牢碩。',48,'全唐诗/poet.tang.0.json','["五齊潔，九牢碩。", "梡橛循，罍斝滌。", "進具物，揚鴻績。", "和奏發，高靈寂。", "虔告終，繁祉錫。", "昭秩祀，永無易。"]'),
('12ec2d0d-8a04-46d8-873b-b3ed0b88b4d8','郊廟歌辭 釋奠武成王樂章 亞獻終獻','于邵','唐','唐诗','tang','','[]','貳觴以獻，三變其終。',50,'全唐诗/poet.tang.0.json','["貳觴以獻，三變其終。", "顧此非馨，尚達斯衷。", "茅縮可致，神歆載融。", "始神翊周，拯溺除凶。", "時維降祐，永絕興戎。"]'),
('fdd061fc-2394-4fa9-8664-3adf4f36da02','郊廟歌辭 釋奠武成王樂章 送神','于邵','唐','唐诗','tang','','[]','明祀方終，備樂斯闋。',40,'全唐诗/poet.tang.0.json','["明祀方終，備樂斯闋。", "黝纁就瘞，豆籩告撤。", "肸蠁尚餘，光景云滅。", "返歸虛極，神心則悅。"]'),
('b01eb82d-f629-456b-ba87-1573a9bfadd8','郊廟歌辭 享龍池樂章 第一章','姚崇','唐','唐诗','tang','','[]','恭聞帝里生靈沼，應報明君鼎業新。',64,'全唐诗/poet.tang.0.json','["恭聞帝里生靈沼，應報明君鼎業新。", "既協翠泉光寶命，還符白水出真人。", "此時舜海潛龍躍，此地堯河帶馬巡。", "獨有前池一小雁，叨承舊惠入天津。"]'),
('7a39a755-afc4-4c50-95d7-49c2edf85494','郊廟歌辭 享龍池樂章 第二章','蔡孚','唐','唐诗','tang','','[]','帝宅王家大道邊，神馬龍龜涌聖泉。',64,'全唐诗/poet.tang.0.json','["帝宅王家大道邊，神馬龍龜涌聖泉。", "昔日昔時經此地，看來看去漸成川。", "歌臺舞榭宜正月，柳岸梅洲勝往年。", "莫言波上春雲少，祗爲從龍直上天。"]'),
('d291f734-2ec4-4eed-9c5e-8f14c4d11921','郊廟歌辭 享龍池樂章 第三章','沈佺期','唐','唐诗','tang','','[]','龍池躍龍龍已飛，龍德[光]天天不違。',66,'全唐诗/poet.tang.0.json','["龍池躍龍龍已飛，龍德[光]天天不違。", "池開天漢分黃道，龍向天門入紫微。", "邸第樓臺多氣色，君王鳧雁有光輝。", "爲報寰中百川水，來朝此地莫東歸。"]'),
('1a201161-2e55-4ad6-a9ff-8db614d1cd00','郊廟歌辭 享龍池樂章 第四章','盧懷慎','唐','唐诗','tang','','[]','代邸東南龍躍泉，清漪碧浪遠浮天。',64,'全唐诗/poet.tang.0.json','["代邸東南龍躍泉，清漪碧浪遠浮天。", "樓臺影就波中出，日月光疑鏡裏懸。", "雁沼回流成舜海，龜書薦祉應堯年。", "大川既濟慙爲檝，報德空思奉細涓。"]'),
('037a76e5-2949-43de-850c-5bf8f5010ffd','郊廟歌辭 享龍池樂章 第五章','姜皎','唐','唐诗','tang','','[]','龍池初出此龍山，常經此地謁龍顏。',64,'全唐诗/poet.tang.0.json','["龍池初出此龍山，常經此地謁龍顏。", "日日芙蓉生夏水，年年楊柳變春灣。", "堯壇寶匣餘煙霧，舜海漁舟尚往還。", "願似飄颻五雲影，從來從去九天間。"]'),
('e38b8c76-9f0b-484c-8791-34340abf20b1','郊廟歌辭 享龍池樂章 第六章','崔日用','唐','唐诗','tang','','[]','龍興白水漢興符，聖主時乘運斗樞。',64,'全唐诗/poet.tang.0.json','["龍興白水漢興符，聖主時乘運斗樞。", "岸上丰茸五花樹，波中的皪千金珠。", "操環昔聞迎夏啓，發匣先來瑞有虞。", "風色雲光隨隱見，赤雲神化象江湖。"]'),
('53bfd457-c415-4a5e-8022-547f6d3ee63e','郊廟歌辭 享龍池樂章 第七章','蘇頲','唐','唐诗','tang','','[]','西京鳳邸躍龍泉，佳氣休光鎮在天。',64,'全唐诗/poet.tang.0.json','["西京鳳邸躍龍泉，佳氣休光鎮在天。", "軒后霧圖今已得，秦王水劒昔常傳。", "恩魚不似昆明釣，瑞鶴長如太液仙。", "願侍巡游同舊里，更聞簫鼓濟樓船。"]'),
('139c0bdc-57df-43ea-ab82-7f9db95554cf','郊廟歌辭 享龍池樂章 第八章','李乂','唐','唐诗','tang','','[]','星分邑里四人居，水洊源流萬頃餘。',64,'全唐诗/poet.tang.0.json','["星分邑里四人居，水洊源流萬頃餘。", "魏國君王稱象處，晉家藩邸化龍初。", "青蒲暫似遊梁馬，綠藻還疑宴鎬魚。", "自有神靈滋液地，年年雲物史官書。"]'),
('0a05c8f5-0bdb-494b-bb42-7a780b603745','郊廟歌辭 享龍池樂章 第九章','姜皎','唐','唐诗','tang','','[]','靈沼縈迴邸第前，浴日涵天寫曙天。',64,'全唐诗/poet.tang.0.json','["靈沼縈迴邸第前，浴日涵天寫曙天。", "始見龍臺昇鳳闕，應如霄漢起神泉。", "石匱渚傍還啓聖，桃李初生更有仙。", "欲化帝圖從此受，正同河變一千年。"]'),
('b3f5fd27-c2a3-4007-9a52-21ac2aca7644','郊廟歌辭 享龍池樂章 第十章','裴璀','唐','唐诗','tang','','[]','乾坤啓聖吐龍泉，泉水年年勝一年。',64,'全唐诗/poet.tang.0.json','["乾坤啓聖吐龍泉，泉水年年勝一年。", "始看魚躍方成海，即覩龍飛利在天。", "洲渚遙將銀漢接，樓臺直與紫微連。", "休氣榮光常不散，懸知此地是神仙。"]'),
('6c6f3aee-8862-4281-92f2-c963a5fdebef','郊廟歌辭 享太廟樂章 永和','魏徵、褚亮','唐','唐诗','tang','','[]','於穆烈祖，弘此丕基。',40,'全唐诗/poet.tang.0.json','["於穆烈祖，弘此丕基。", "永言配命，子孫保之。", "百神既洽，萬國在茲。", "是用孝享，神其格思。"]'),
('9eee091a-7070-4989-b87a-7c2f6dd4b20d','郊廟歌辭 享太廟樂章 肅和','魏徵、褚亮','唐','唐诗','tang','','[]','大哉至德，允茲明聖。',40,'全唐诗/poet.tang.0.json','["大哉至德，允茲明聖。", "格于上下，聿遵誠敬。", "嘉樂斯登，鳴球以詠。", "神其降止，式隆景命。"]'),
('0b1a491d-c0c1-4ac2-9643-2f598cee7f77','郊廟歌辭 享太廟樂章 雍和','魏徵、褚亮','唐','唐诗','tang','','[]','崇茲享祀，誠敬兼至。',40,'全唐诗/poet.tang.0.json','["崇茲享祀，誠敬兼至。", "樂以感靈，禮以昭事。", "粢盛咸絜，牲牷孔備。", "永言孝思，庶幾不匱。"]'),
('62ac1952-e0f1-4935-8e06-9d8f9f72bb6f','郊廟歌辭 享太廟樂章 長發舞','魏徵、褚亮','唐','唐诗','tang','','[]','睿哲維唐，長發其祥。',40,'全唐诗/poet.tang.0.json','["睿哲維唐，長發其祥。", "帝命斯祐，王業克昌。", "配天載德，就日重光。", "本支百代，申錫無疆。"]'),
('b8e2aabe-4e9c-4a5d-8f4a-299d7f6624e7','郊廟歌辭 享太廟樂章 大基舞','魏徵、褚亮','唐','唐诗','tang','','[]','猗與祖業，皇矣帝先。',40,'全唐诗/poet.tang.0.json','["猗與祖業，皇矣帝先。", "翦商德厚，封唐慶延。", "在姬猶稷，方晉喻宣。", "基我鼎運，於萬斯年。"]'),
('da2fb201-1711-47f6-9858-6a1b6fc753c6','郊廟歌辭 享太廟樂章 大成舞','魏徵、褚亮','唐','唐诗','tang','','[]','周稱王季，晉美帝文。',40,'全唐诗/poet.tang.0.json','["周稱王季，晉美帝文。", "明明盛德，穆穆齊芬。", "藏用四履，屈道三分。", "鏗鏘鍾石，載紀鴻勳。"]'),
('dc517fb4-afe5-4836-82dd-4b05d9a66851','郊廟歌辭 享太廟樂章 大明舞','魏徵、褚亮','唐','唐诗','tang','','[]','五紀更運，三正遞升。',120,'全唐诗/poet.tang.0.json','["五紀更運，三正遞升。", "勛華既沒，禹湯勃興。", "神武命代，靈睠是膺。", "望雲彰德，察緯告徵。", "上紐天維，下安地軸。", "徵師涿野，萬國咸服。", "偃伯靈臺，九官允穆。", "殊域委賮，懷生介福。", "大禮既飾，大樂已和。", "黑章擾囿，赤字浮河。", "功宣載籍，德被詠歌。", "克昌厥後，百祿是荷。"]'),
('e3cb5d89-401f-42ca-8694-6e30d10c049c','郊廟歌辭 享太廟樂章 壽和','魏徵、褚亮','唐','唐诗','tang','','[]','八音斯奏，三獻畢陳。',20,'全唐诗/poet.tang.0.json','["八音斯奏，三獻畢陳。", "寶祚惟永，暉光日新。"]'),
('b75f9864-ebbc-4b6c-8758-9a8e4fb27d05','郊廟歌辭 享太廟樂章 舒和','魏徵、褚亮','唐','唐诗','tang','','[]','聖敬通神光七廟，靈心薦祚和萬方。',32,'全唐诗/poet.tang.0.json','["聖敬通神光七廟，靈心薦祚和萬方。", "嚴禋克配鴻基遠，明德惟馨鳳曆昌。"]'),
('3776e703-3ed3-4c65-95ea-62eed3e929c0','郊廟歌辭 享太廟樂章 雍和','魏徵、褚亮','唐','唐诗','tang','','[]','於穆清廟，聿修嚴祀。',40,'全唐诗/poet.tang.0.json','["於穆清廟，聿修嚴祀。", "四縣載陳，三獻斯止。", "籩豆徹薦，人祇介祉。", "神維格思，錫祚不已。"]'),
('433e5a5c-0e39-419f-8ef5-e672dd4f56af','郊廟歌辭 享太廟樂章 永和','魏徵、褚亮','唐','唐诗','tang','','[]','肅肅清祀，烝烝孝思。',40,'全唐诗/poet.tang.0.json','["肅肅清祀，烝烝孝思。", "薦享昭備，虔恭在茲。", "雍歌徹俎，祝嘏陳辭。", "用光武志，永固鴻基。"]'),
('064b1fa2-3649-4b01-a0c0-4bc73c9d8a89','郊廟歌辭 享太廟樂章 崇德舞','不詳','唐','唐诗','tang','','[]','五運改卜，千齡啓聖。',120,'全唐诗/poet.tang.0.json','["五運改卜，千齡啓聖。", "彤雲曉聚，黃星夜映。", "葉闡珠囊，基開玉鏡。", "下臨萬宇，上齊七政。", "霧開三象，塵清九服。", "海溓星暉，遠安邇肅。", "天地交泰，華夷輯睦。", "翔泳歸仁，中外禔福。", "績踰黜夏，勳高翦商。", "武陳七德，刑設三章。", "祥禽巢閣，仁獸遊梁。", "卜年惟永，景福無疆。"]'),
('bad3700c-fcfe-4096-a11b-1ba4c67a66fe','郊廟歌辭 享太廟樂章 鈞天[舞]','不詳','唐','唐诗','tang','','[]','承天撫籙，纂聖登皇。',120,'全唐诗/poet.tang.0.json','["承天撫籙，纂聖登皇。", "遐清萬宇，仰協三光。", "功成日用，道濟時康。", "璇圖載永，寶曆斯昌。", "日月揚暉，煙雲爛色。", "河嶽修貢，神祇効職。", "舜風攸偃，堯曦先就。", "睿感通寰，孝思浹宙。", "奉揚先德，虔遵曩狩。", "展義天扄，飛英雲岫。", "化逸王表，神凝帝先。", "乘雲厭俗，馭日登玄。"]'),
('26d7dd17-808c-4735-93d1-e74127c33838','郊廟歌辭 享太廟樂章 太和舞','不詳','唐','唐诗','tang','','[]','廣樂既備，嘉薦既新。',40,'全唐诗/poet.tang.0.json','["廣樂既備，嘉薦既新。", "述先惟德，孝饗惟親。", "七獻具舉，五齊畢陳。", "錫茲祚福，於萬斯春。"]'),
('f53dcca3-2e68-4719-a490-eb845dd6bb79','郊廟歌辭 享太廟樂章 景雲舞','不詳','唐','唐诗','tang','','[]','惟睿作聖，惟聖登皇。',120,'全唐诗/poet.tang.0.json','["惟睿作聖，惟聖登皇。", "精感耀魄，時膺會昌。", "舜慙大孝，堯推讓王。", "能事斯極，振古誰方。", "文明履運，車書同軌。", "巍巍赫赫，盡善盡美。", "衢室凝旒，大庭端扆。", "釋負之寄，事光復子。", "脫屣高天，登遐上玄。", "龍湖超忽，象野芊綿。", "遊衣復道，薦果初年。", "新廟奕奕，明德配天。"]'),
('d5fc1717-a9ac-45d4-bab0-7a54ec6e831e','郊廟歌辭 享太廟樂章 光大舞','不詳','唐','唐诗','tang','','[]','大業龍祉，徽音駿尊。',40,'全唐诗/poet.tang.0.json','["大業龍祉，徽音駿尊。", "潛居皇德，赫嗣天昆。", "展儀宗祖，重誠孝孫。", "春秋無極，享奏存存。"]'),
('70baddd6-6128-41d4-bc8c-a409dd9a9939','郊廟歌辭 享太廟樂章 迎神','不詳','唐','唐诗','tang','','[]','七廟觀德，百靈攸仰。',40,'全唐诗/poet.tang.0.json','["七廟觀德，百靈攸仰。", "俗荷財成，物資含養。", "道光執契，化籠提象。", "肅肅雍雍，神其來饗。"]'),
('15e0461a-bd33-4197-8613-4c7adffe3fdd','郊廟歌辭 享太廟樂章 金奏','不詳','唐','唐诗','tang','','[]','肅肅清廟，巍巍盛唐。',40,'全唐诗/poet.tang.0.json','["肅肅清廟，巍巍盛唐。", "配天立極，累聖重光。", "樂和管磬，禮備烝嘗。", "永惟來格，降福無疆。"]'),
('6ddd9228-e9ac-4ff1-b20c-79781d3deb46','郊廟歌辭 享太廟樂章 送神','不詳','唐','唐诗','tang','','[]','五聲備奏，三獻終祠。',40,'全唐诗/poet.tang.0.json','["五聲備奏，三獻終祠。", "車移鳳輦，斾轉虹旗。", "禮周籩豆，誠效虔祗。", "皇靈徙蹕，簪紳拜辭。"]'),
