('7b639cc5-5c54-46ca-95ee-ba9ec02726aa','郊廟歌辭 享太廟樂章 誠敬','不詳','唐','唐诗','tang','','[]','顧惟菲質，忝位椒宮。',40,'全唐诗/poet.tang.0.json','["顧惟菲質，忝位椒宮。", "虔奉蘋藻，肅事神宗。", "敢申誠絜，庶罄深衷。", "睟容有裕，靈享無窮。"]'),
('47211b3f-f590-48eb-bd73-b92297761131','郊廟歌辭 享太廟樂章 肅和','不詳','唐','唐诗','tang','','[]','月禮已周，雲和將變。',40,'全唐诗/poet.tang.0.json','["月禮已周，雲和將變。", "爰獻其醑，載遷其奠。", "明德逾隆，非馨是薦。", "澤霑動植，仁覃宇縣。"]'),
('bac63ce9-8353-4527-bde9-a8ed8152df49','郊廟歌辭 享太廟樂章 昭感','不詳','唐','唐诗','tang','','[]','鏗鏘韶濩，肅穆神容。',40,'全唐诗/poet.tang.0.json','["鏗鏘韶濩，肅穆神容。", "洪規赫赫，祠典雍雍。", "已周三獻，將乘六龍。", "虔誠有託，懇志無從。"]'),
('712d4015-f37f-4b13-9445-f14daa6586fd','郊廟歌辭 享太廟樂章 永和三章 一','張說','唐','唐诗','tang','','[]','肅九室，諧八音。',34,'全唐诗/poet.tang.0.json','["肅九室，諧八音。", "歌皇慕，動神心。", "禮宿設，樂妙尋。", "聲明備，[祼]奠臨。"]'),
('47749fe4-e4f7-44cd-9dfc-9c177de3c646','郊廟歌辭 享太廟樂章 永和三章 二','張說','唐','唐诗','tang','','[]','律迓氣，音入玄。',32,'全唐诗/poet.tang.0.json','["律迓氣，音入玄。", "依玉几，御黼筵。", "聆愾息，僾周旋。", "九韶遍，百福傳。"]'),
('656928fe-763c-49d0-a587-b6857ab23734','郊廟歌辭 享太廟樂章 永和三章 三','張說','唐','唐诗','tang','','[]','信工祝，永頌聲。',32,'全唐诗/poet.tang.0.json','["信工祝，永頌聲。", "來祖考，聽和平。", "相百辟，貢九瀛。", "神休委，帝孝成。"]'),
('06273196-6d2a-4c70-9680-257cea297824','郊廟歌辭 享太廟樂章 太和','張說','唐','唐诗','tang','','[]','時文聖后，清廟肅邕。',40,'全唐诗/poet.tang.0.json','["時文聖后，清廟肅邕。", "致誠勤薦，在貌思恭。", "玉節肆夏，金鏘五鍾。", "繩繩雲步，穆穆天容。"]'),
('db927e94-ccb0-43f8-8d1c-d595e32aa205','郊廟歌辭 享太廟樂章 肅和','張說','唐','唐诗','tang','','[]','天子享孝，工歌溥將。',42,'全唐诗/poet.tang.0.json','["天子享孝，工歌溥將。", "躬[祼]鬱鬯，乃焚膋薌。", "臭以達陰，聲以求陽。", "奉時烝嘗，永代不忘。"]'),
('076bc804-c0d9-4d33-bfbb-857a1b28d4fe','郊廟歌辭 享太廟樂章 雍和二章 一','張說','唐','唐诗','tang','','[]','在滌嘉豢，麗碑敬牲。',42,'全唐诗/poet.tang.0.json','["在滌嘉豢，麗碑敬牲。", "角握之牡，色純之騂。", "火傳陽燧，水溉陰精。", "太公胖俎，[傅]說和羹。"]'),
('7196811a-78b3-4b37-b38d-4f312579860c','郊廟歌辭 享太廟樂章 雍和二章 二','張說','唐','唐诗','tang','','[]','俎豆有馥，粢盛絜豐。',40,'全唐诗/poet.tang.0.json','["俎豆有馥，粢盛絜豐。", "亦有和羹，既戒既平。", "鼓鐘管磬，肅唱和鳴。", "皇皇后祖，來我思成。"]'),
('f3bc86a7-d987-48d2-9f94-5df3bdc2934c','郊廟歌辭 享太廟樂章 文舞','張說','唐','唐诗','tang','','[]','聖謩九德，真言五千。',100,'全唐诗/poet.tang.0.json','["聖謩九德，真言五千。", "慶集昌胄，符開帝先。", "高文杖鉞，克配彼天。", "三宗握鏡，六合渙然。", "帝其承祀，率禮罔愆。", "圖書霧出，日月清懸。", "舞形德類，詠諗功傳。", "黃龍蜿蟺，彩雲蹁躚。", "五行氣順，八佾風宣。", "介此百祿，於皇萬年。"]'),
('3e34baf9-9b4b-43d9-9333-5c3e5a72f841','郊廟歌辭 享太廟樂章 光大舞','張說','唐','唐诗','tang','','[]','肅肅藝祖，滔滔濬源。',40,'全唐诗/poet.tang.0.json','["肅肅藝祖，滔滔濬源。", "有雄玉劍，作鎮金門。", "玄王貽緒，后稷謀孫。", "肇禋九廟，四海來尊。"]'),
('062d7a61-9db6-4470-abf0-cf8d77eeffc5','郊廟歌辭 享太廟樂章 長發舞','張說','唐','唐诗','tang','','[]','具禮崇德，備樂承風。',40,'全唐诗/poet.tang.0.json','["具禮崇德，備樂承風。", "魏推幢主，周贈司空。", "不行而至，無成有終。", "神興王業，天歸帝功。"]'),
('884a1a63-e25d-4735-8987-3e557d13bb58','郊廟歌辭 享太廟樂章 大政舞','張說','唐','唐诗','tang','','[]','於赫元命，權輿帝文。',40,'全唐诗/poet.tang.0.json','["於赫元命，權輿帝文。", "天齊八柱，地半三分。", "宗廟觀德，笙鏞樂勳。", "封唐之兆，成天下君。"]'),
('357ac431-f7b8-4c06-823d-61254b5c1546','郊廟歌辭 享太廟樂章 大成舞','張說','唐','唐诗','tang','','[]','帝舞季歷，龍聖生昌。',40,'全唐诗/poet.tang.0.json','["帝舞季歷，龍聖生昌。", "后歌有蟜，胎炎孕黃。", "天地合德，日月齊光。", "肅雝孝享，祚我萬方。"]'),
('e8bdfd81-4fdb-4c89-b7e6-6124331870d0','郊廟歌辭 享太廟樂章 大明舞','張說','唐','唐诗','tang','','[]','赤精亂德，四海困窮。',40,'全唐诗/poet.tang.0.json','["赤精亂德，四海困窮。", "黃旗舉義，三靈會同。", "旱望春雨，雲披大風。", "溥天來祭，高祖之功。"]'),
('fcebe002-b5e1-41e4-b269-ccd09098e0b7','郊廟歌辭 享太廟樂章 崇德舞','張說','唐','唐诗','tang','','[]','皇合一德，朝宗百神。',40,'全唐诗/poet.tang.0.json','["皇合一德，朝宗百神。", "削平天地，大拯生人。", "上帝配食，單于入臣。", "戎歌陳舞，曄曄震震。"]'),
('b237c02d-7936-4f51-9e88-b11b6640df3e','郊廟歌辭 享太廟樂章 鈞天舞','張說','唐','唐诗','tang','','[]','高皇邁道，端拱無爲。',40,'全唐诗/poet.tang.0.json','["高皇邁道，端拱無爲。", "化懷獯鬻，兵賦句驪。", "禮尊封禪，樂盛來儀。", "合位媧后，同稱伏羲。"]'),
('f6f5e42d-b1c0-4fb7-ba33-3928a50a9cd5','郊廟歌辭 享太廟樂章 大和舞','張說','唐','唐诗','tang','','[]','退居江水，鬱起丹陵。',40,'全唐诗/poet.tang.0.json','["退居江水，鬱起丹陵。", "禮物還舊，朝章中興。", "龍圖友及，駿命恭膺。", "鳴球香瓚，大糦是承。"]'),
('3ff56a31-51e0-4926-a44e-73635f47c545','郊廟歌辭 享太廟樂章 景雲舞','張說','唐','唐诗','tang','','[]','景雲霏爛，告我帝符。',40,'全唐诗/poet.tang.0.json','["景雲霏爛，告我帝符。", "噫帝沖德，與天爲徒。", "笙鏞遙遠，俎豆虛無。", "春秋孝獻，迴復此都。"]'),
('3f77cc4a-756b-4d49-9f61-9f06765a6bad','郊廟歌辭 享太廟樂章 福和','張說','唐','唐诗','tang','','[]','備禮用樂，崇親致尊。',50,'全唐诗/poet.tang.0.json','["備禮用樂，崇親致尊。", "誠通慈降，敬徹愛存。", "獻懷稱壽，啐感承恩。", "皇帝孝德，子孫千億。", "大包天域，長亙不極。"]'),
('26890912-7fd0-4218-bb30-2e78c8c5842c','郊廟歌辭 享太廟樂章 舒和','張說','唐','唐诗','tang','','[]','六鐘翕協六變成，八佾徜徉八風生。',32,'全唐诗/poet.tang.0.json','["六鐘翕協六變成，八佾徜徉八風生。", "樂九韶兮人神感，美七德兮天地清。"]'),
('9cc352d4-75fb-463a-9bda-f24ff3310cb4','郊廟歌辭 享太廟樂章 凱安四章 一','張說','唐','唐诗','tang','','[]','瑟彼瑤爵，亞惟上公。',40,'全唐诗/poet.tang.0.json','["瑟彼瑤爵，亞惟上公。", "室如屏氣，門不容躬。", "禮殷其本，樂執其中。", "聖皇永慕，天地幽通。"]'),
('53c38627-d071-4c1c-8d48-f7cdd7f9c026','郊廟歌辭 享太廟樂章 凱安四章 二','張說','唐','唐诗','tang','','[]','禮匝三獻，樂遍九成。',42,'全唐诗/poet.tang.0.json','["禮匝三獻，樂遍九成。", "降循軒陛，仰欷皇情。", "福與仁合，德因孝明。", "百年[神畏]，四海風行。"]'),
('fd5cc7ad-fb0e-434e-b731-6967676f7f39','郊廟歌辭 享太廟樂章 凱安四章 三','張說','唐','唐诗','tang','','[]','總總干戚，填填鼓鐘。',40,'全唐诗/poet.tang.0.json','["總總干戚，填填鼓鐘。", "奮揚爭氣，坐作爲容。", "離若鷙鳥，合如戰龍。", "萬方觀德，肅肅雝雝。"]'),
('eb23e85d-52f7-41bc-aef5-25b219f6f699','郊廟歌辭 享太廟樂章 凱安四章 四','張說','唐','唐诗','tang','','[]','烈祖順三靈，文宗威四海。',48,'全唐诗/poet.tang.0.json','["烈祖順三靈，文宗威四海。", "黃鉞誅羣盜，朱旗掃多罪。", "戢兵天下安，約法人心改。", "大哉干羽意，長見風雲在。"]'),
('153776ca-d0c7-40ce-af6a-568daf6a79eb','郊廟歌辭 享太廟樂章 登歌','張說','唐','唐诗','tang','','[]','止笙磬，撤豆籩。',40,'全唐诗/poet.tang.0.json','["止笙磬，撤豆籩。", "廓無響，窅入玄。", "主在室，神在天。", "情餘慕，禮罔愆。", "喜黍稷，屢豐年。"]'),
('e70176f2-53b1-4dbe-963c-ef6fc9e3e64d','郊廟歌辭 享太廟樂章 永和','張說','唐','唐诗','tang','','[]','眇嘉樂，授靈爽。',40,'全唐诗/poet.tang.0.json','["眇嘉樂，授靈爽。", "感若來，思如往。", "休氣散，迴風上。", "返寂寞，還惚恍。", "懷靈駕，結空想。"]'),
('d9adcff7-7ac4-4ac2-be95-df151a920114','郊廟歌辭 享太廟樂章 廣運舞','郭子儀','唐','唐诗','tang','','[]','於赫皇祖，昭明有融。',40,'全唐诗/poet.tang.0.json','["於赫皇祖，昭明有融。", "惟文之德，惟武之功。", "河海靜謐，車書混同。", "虔恭孝饗，穆穆玄風。"]'),
('e86a6a73-602c-4745-ab81-541d27786663','郊廟歌辭 享太廟樂章 惟新舞','劉晏','唐','唐诗','tang','','[]','漢祚惟永，神功中興。',40,'全唐诗/poet.tang.0.json','["漢祚惟永，神功中興。", "風驅氛祲，天覆黎蒸。", "三光再朗，庶績其凝。", "重熙累洽，景命是膺。"]'),
('1700afdb-215f-4a06-b555-c4b3fb9e9375','郊廟歌辭 享太廟樂章 保大舞','郭子儀','唐','唐诗','tang','','[]','於穆文考，聖神昭章。',40,'全唐诗/poet.tang.0.json','["於穆文考，聖神昭章。", "肅勺羣慝，含光遠方。", "萬物茂遂，九夷賓王。", "愔愔雲韶，德音不忘。"]'),
('fd9ee03c-96d1-4c84-b8ea-6d85f0e0f46f','郊廟歌辭 享太廟樂章 文明舞','鄭餘慶','唐','唐诗','tang','','[]','開邸除暴，時邁勛尊。',40,'全唐诗/poet.tang.0.json','["開邸除暴，時邁勛尊。", "三元告命，四極駿奔。", "金枝翠葉，輝燭瑤琨。", "象德億載，貽慶湯孫。"]'),
('27173453-b779-41af-a14b-aa21a44a4ecb','郊廟歌辭 享太廟樂章 大順舞','鄭絪','唐','唐诗','tang','','[]','於穆時文，受天明命。',40,'全唐诗/poet.tang.0.json','["於穆時文，受天明命。", "允恭玄默，化成理定。", "出震嗣德，應乾傳聖。", "猗歟緝熙，千億流慶。"]'),
('24daec53-cf05-46fb-bfac-051e9eb4b8ce','郊廟歌辭 享太廟樂章 象德舞','段文昌','唐','唐诗','tang','','[]','肅肅清廟，登顯至德。',40,'全唐诗/poet.tang.0.json','["肅肅清廟，登顯至德。", "澤周八荒，兵定四極。", "生物咸遂，羣盜滅息。", "明聖欽承，子孫千億。"]'),
('811d83e1-a2d7-4ffd-93b3-5705c81706e2','郊廟歌辭 享太廟樂章 和寧舞','牛僧孺','唐','唐诗','tang','','[]','湜湜頎頎，融昭德輝。',40,'全唐诗/poet.tang.0.json','["湜湜頎頎，融昭德輝。", "不紐不舒，貫成九圍。", "武烈文經，敷施當宜。", "纂堯付啓，億萬熙熙。"]'),
('7595547c-5365-491b-912f-ab12784afc15','郊廟歌辭 享太廟樂章 大定舞','李回','唐','唐诗','tang','','[]','受天明命，敷佑下土。',40,'全唐诗/poet.tang.0.json','["受天明命，敷佑下土。", "化時以儉，衛文以武。", "氛消夷夏，俗臻往古。", "億萬斯年，形于律呂。"]'),
('70332c1e-72b9-41d2-9752-ea1b4bf356c4','郊廟歌辭 享太廟樂章 宣宗室舞','夏侯孜','唐','唐诗','tang','','[]','於鑠令主，聖祚重昌。',40,'全唐诗/poet.tang.0.json','["於鑠令主，聖祚重昌。", "興起教義，申明典章。", "俗尚素朴，人皆樂康。", "積德可報，流慶無疆。"]'),
('ccf34b3e-9e90-4bd2-8ea4-65948bd3d19b','郊廟歌辭  懿宗室舞','蕭倣','唐','唐诗','tang','','[]','聖祚無疆，慶傳樂章。',42,'全唐诗/poet.tang.0.json','["聖祚無疆，慶傳樂章。", "金枝繁茂，玉葉延長。", "海瀆常[晏]，波濤不揚。", "汪汪美化，垂範今王。"]'),
('09c0c6b5-b13f-4473-8618-eb160494b202','郊廟歌辭 享太廟樂章 咸寧舞','不詳','唐','唐诗','tang','','[]','於鑠丕嗣，惟帝之光。',40,'全唐诗/poet.tang.0.json','["於鑠丕嗣，惟帝之光。", "羽籥象德，金石薦祥。", "聖系無極，景命永昌。", "神降上哲，維天配長。"]'),
('fe138730-cbf4-45ab-9763-ed22317873a9','郊廟歌辭 太清宮樂章 煌煌','不詳','唐','唐诗','tang','','[]','煌煌道宮，肅肅太清。',60,'全唐诗/poet.tang.0.json','["煌煌道宮，肅肅太清。", "禮光尊祖，樂備充庭。", "罄竭誠至，希夷降靈。", "雲凝翠蓋，風燄紅旌。", "衆真以從，九奏初迎。", "永惟休祐，是錫和平。"]'),
('b0ea6d16-5fd3-47e4-bdb5-27562528afe2','郊廟歌辭 太清宮樂章 沖和','不詳','唐','唐诗','tang','','[]','虛無結思，鐘磬和音。',40,'全唐诗/poet.tang.0.json','["虛無結思，鐘磬和音。", "歌以頌德，香以達心。", "禮殊祼鬯，義感昭臨。", "雲車至止，慶垂愔愔。"]'),
('c03752f1-fff4-459b-931e-896dedb77384','郊廟歌辭 太清宮樂章 香初上','不詳','唐','唐诗','tang','','[]','肅肅我祖，緜緜道宗。',40,'全唐诗/poet.tang.0.json','["肅肅我祖，緜緜道宗。", "至感潛達，靈心暗通。", "雲軿御氣，芝蓋隨風。", "四時禋祀，萬國來同。"]'),
('72199536-ac42-4142-9756-75719946c1ef','郊廟歌辭 太清宮樂章 再上','不詳','唐','唐诗','tang','','[]','仙宗績道，我李承天。',40,'全唐诗/poet.tang.0.json','["仙宗績道，我李承天。", "慶深虛極，符光象先。", "俗登仁壽，化闡蟺涓。", "五千貽範，億萬斯年。"]'),
('12c1a825-4611-4f3a-869d-0ee8b443513c','郊廟歌辭 太清宮樂章 終上','不詳','唐','唐诗','tang','','[]','不宰元功，無爲上聖。',40,'全唐诗/poet.tang.0.json','["不宰元功，無爲上聖。", "洪源長發，誕受天命。", "金奏迎真，璇宮展盛。", "備禮周樂，垂光儲慶。"]'),
('fd921ba1-15e1-4b4c-96e5-a127f6678ea7','郊廟歌辭 太清宮樂章 紫極舞','不詳','唐','唐诗','tang','','[]','至道生元氣，重圓法混成。',72,'全唐诗/poet.tang.0.json','["至道生元氣，重圓法混成。", "無爲觀大象，沖用體常名。", "仙樂臨丹闕，雲車出玉京。", "靈符百代應，瑞節九貞迎。", "寶運開皇極，天臨映太清。", "長垂一德慶，永庇萬方寧。"]'),
('8d862501-b360-4e47-bf4b-9ebd1406bc42','郊廟歌辭 太清宮樂章 序入破第一奏','不詳','唐','唐诗','tang','','[]','真宗開妙理，沖教統清虛。',48,'全唐诗/poet.tang.0.json','["真宗開妙理，沖教統清虛。", "化演無爲日，言昭有象初。", "瑤臺肅靈瑞，金闕映仙居。", "一奏三清樂，長回八景輿。"]'),
('fa252fae-6e68-425e-b0b3-89acc657b20c','郊廟歌辭 太清宮樂章 序入破第二奏','不詳','唐','唐诗','tang','','[]','虛極仙宗本，希夷象帝先。',48,'全唐诗/poet.tang.0.json','["虛極仙宗本，希夷象帝先。", "百靈朝太上，萬法祖重圓。", "善貸惟沖德，功成謂自然。", "雲門達和氣，思用合鈞天。"]'),
('0a2ad219-b391-4410-8915-80de4cee5715','郊廟歌辭 太清宮樂章 序入破第三奏','不詳','唐','唐诗','tang','','[]','元符傳紫極，寶祚啓高真。',48,'全唐诗/poet.tang.0.json','["元符傳紫極，寶祚啓高真。", "道德先垂裕，沖和已化淳。", "人風齊太古，天瑞叶惟新。", "仙樂清都上，長明交泰辰。"]'),
('30c24c3f-d61b-4577-84de-f25af23a069c','郊廟歌辭 太清宮樂章 登歌','不詳','唐','唐诗','tang','','[]','嚴禋展事，理潔烝嘗。',40,'全唐诗/poet.tang.0.json','["嚴禋展事，理潔烝嘗。", "皇矣聖祖，德惟馨香。", "盛薦既撤，工歌載揚。", "大來之慶，降福穰穰。"]'),
('69bacbb3-1d7d-4e86-81c5-48f7789a4862','郊廟歌辭 太清宮樂章 真和','不詳','唐','唐诗','tang','','[]','玉磬含香，金爐既馥。',40,'全唐诗/poet.tang.0.json','["玉磬含香，金爐既馥。", "風馭泠泠，雲壇肅肅。", "杳歸大象，霈流嘉福。", "俾寧萬邦，無思不服。"]'),
('3d290e33-710f-4419-a30d-2d76a3b3e54a','郊廟歌辭 德明興聖廟樂章 迎神','李舒','唐','唐诗','tang','','[]','元尊九德，佐堯光宅。',40,'全唐诗/poet.tang.0.json','["元尊九德，佐堯光宅。", "烈祖太宗，方周作伯。", "響懷霜露，樂變金石。", "白雲清風，髣髴來格。"]'),
('ea9c019e-a6fb-4620-847b-130634b1b349','郊廟歌辭 德明興聖廟樂章 登歌奠幣','李舒','唐','唐诗','tang','','[]','四時有典，百事來祭。',40,'全唐诗/poet.tang.0.json','["四時有典，百事來祭。", "尊祖奉宗，嚴禋大帝。", "禮先蒼璧，奠幣黝制。", "於斯萬年，熙成帝系。"]'),
('7e9c2d4d-32af-4938-a890-b2f658f7db72','郊廟歌辭 德明興聖廟樂章 迎俎','李舒','唐','唐诗','tang','','[]','盛牲實俎，涓選休成。',40,'全唐诗/poet.tang.0.json','["盛牲實俎，涓選休成。", "鼎煁陽燧，玉盥陰精。", "有飶嘉豆，既和大羹。", "侑以清樂，細齊人情。"]'),
('78f6ace2-c073-4935-a33d-5146e337527f','郊廟歌辭 德明興聖廟樂章 德明酌獻','李舒','唐','唐诗','tang','','[]','清廟奕奕，和樂雍雍。',40,'全唐诗/poet.tang.0.json','["清廟奕奕，和樂雍雍。", "器尊犧象，禮屬宗公。", "白水方祼，黃流在中。", "謨明之德，萬古清風。"]'),
('b254f983-1f0a-40c9-9a35-19d1699fb83b','郊廟歌辭 德明興聖廟樂章 興聖酌獻','李舒','唐','唐诗','tang','','[]','閟宮靜謐，合樂周張。',40,'全唐诗/poet.tang.0.json','["閟宮靜謐，合樂周張。", "泰尊始獻，百末重觴。", "震澹存誠，庶幾迪嘗。", "遙源之祚，天漢靈長。"]'),
('8df415f8-1217-4d67-b74c-eb561ae5bee5','郊廟歌辭 德明興聖廟樂章 亞獻終獻','李舒','唐','唐诗','tang','','[]','惟清惟肅，靡聞靡見。',40,'全唐诗/poet.tang.0.json','["惟清惟肅，靡聞靡見。", "舉備九成，俛終三獻。", "慶彰曼壽，胙徹嘉薦。", "瘞玉埋牲，禮神斯徧。"]'),
('db9b8092-5124-4685-8416-c092806d6bef','郊廟歌辭 德明興聖廟樂章 送神','李舒','唐','唐诗','tang','','[]','元精回復，靈貺繁滋。',40,'全唐诗/poet.tang.0.json','["元精回復，靈貺繁滋。", "風灑蘭路，雲搖桂旗。", "高丘緬邈，涼部逶遲。", "瞻望靡及，纏綿永思。"]'),
('1c5a317d-fe60-4e67-a0b5-a9ed42e5aa6a','郊廟歌辭 儀坤廟樂章 永和','徐彥伯','唐','唐诗','tang','','[]','猗若清廟，肅肅熒熒。',40,'全唐诗/poet.tang.0.json','["猗若清廟，肅肅熒熒。", "國薦嚴祀，坤興淑靈。", "有几在室，有樂在庭。", "臨茲孝享，百祿惟寧。"]'),
('fe67914f-1ea9-4c19-96cd-fd01efec5274','郊廟歌辭 儀坤廟樂章 金奏','不詳','唐','唐诗','tang','','[]','陰靈曜祉，軒曜降精。',40,'全唐诗/poet.tang.0.json','["陰靈曜祉，軒曜降精。", "祥符淑氣，慶集柔明。", "瑤俎既列，雕桐發聲。", "徽猷永遠，比德皇英。"]'),
('181cf5ae-f642-4a02-81f0-ae4685bed51f','郊廟歌辭 儀坤廟樂章 太和','丘說','唐','唐诗','tang','','[]','孝哉我后，沖乎迺聖。',40,'全唐诗/poet.tang.0.json','["孝哉我后，沖乎迺聖。", "道映重華，德輝文命。", "慕深視篋，情殷撫鏡。", "萬國移風，兆人承慶。"]'),
('27377974-8e63-49d7-8da0-8608a884d0a2','郊廟歌辭 儀坤廟樂章 肅和','張齊賢','唐','唐诗','tang','','[]','祼圭既濯，鬱鬯既陳。',40,'全唐诗/poet.tang.0.json','["祼圭既濯，鬱鬯既陳。", "畫幕雲舉，黃流玉醇。", "儀充獻酌，禮盛衆禋。", "地察惟孝，愉焉饗親。"]'),
('3fa22cad-259c-44ee-9895-cae13745127c','郊廟歌辭 儀坤廟樂章 雍和','鄭善玉','唐','唐诗','tang','','[]','酌鬱既灌，薌蕭方爇。',40,'全唐诗/poet.tang.0.json','["酌鬱既灌，薌蕭方爇。", "籩豆靜器，簠簋芬飶。", "魚腊薦美，牲牷表潔。", "是戢是將，載迎載列。"]'),
('085598ca-4735-4f96-8681-491f4d7a3260','郊廟歌辭 儀坤廟樂章 昭升','薛稷','唐','唐诗','tang','','[]','陽靈配德，陰魄昭升。',80,'全唐诗/poet.tang.0.json','["陽靈配德，陰魄昭升。", "堯壇鳳下，漢室龍興。", "俔天作對，前旒是凝。", "化行南國，道盛西陵。", "造舟集灌，無德而稱。", "我粢既絜，我醴既澄。", "陰陰靈廟，光靈若憑。", "德馨惟享，孝思烝烝。"]'),
('235e8677-6e47-4e04-9422-c1a98acd3773','郊廟歌辭 儀坤廟樂章 坤貞','不詳','唐','唐诗','tang','','[]','乾道既亨，坤元以貞。',80,'全唐诗/poet.tang.0.json','["乾道既亨，坤元以貞。", "肅雍攸在，輔佐斯成。", "外睦九族，內光一庭。", "克生睿哲，祚我休明。", "欽若徽範，悠哉淑靈。", "建茲清宮，于彼上京。", "縮茅以獻，絜秬惟馨。", "實受其福，期乎億齡。"]'),
('d95c1136-9489-4d8b-a72e-22d1b0e7f1a3','郊廟歌辭 儀坤廟樂章 壽和','徐堅','唐','唐诗','tang','','[]','於穆清廟，肅雍嚴祀。',22,'全唐诗/poet.tang.0.json','["於穆清廟，肅雍嚴祀。", "合福受釐，介以繁[祉]。"]'),
('0b15d19b-79e5-4872-8e52-77d26c711632','郊廟歌辭 儀坤廟樂章 舒和','胡雄','唐','唐诗','tang','','[]','送文迎武遞參差，一始一終光聖儀。',32,'全唐诗/poet.tang.0.json','["送文迎武遞參差，一始一終光聖儀。", "四海生人歌有慶，千齡孝享肅無虧。"]'),
('201aff1c-c3f8-4327-93bf-c1d6a1232ac7','郊廟歌辭 儀坤廟樂章 安和','劉子玄','唐','唐诗','tang','','[]','妙筭申帷幄，神謀及廟庭。',48,'全唐诗/poet.tang.0.json','["妙筭申帷幄，神謀及廟庭。", "兩階文物備，七德武功成。", "校獵長楊苑，屯軍細柳營。", "將軍獻凱入，歌舞溢重城。"]'),
('2bcac1d6-b744-4060-9ef5-7f35dad5db8f','郊廟歌辭 儀坤廟樂章 雍和','員半千','唐','唐诗','tang','','[]','孝享云畢，惟徹有章。',40,'全唐诗/poet.tang.0.json','["孝享云畢，惟徹有章。", "雲感玄羽，風悽素商。", "瞻望神座，祗戀匪遑。", "禮終樂闋，肅雍鏘鏘。"]'),
('eed3132b-db96-48c9-aefc-898186012ccc','郊廟歌辭 儀坤廟樂章 永和','祝欽明','唐','唐诗','tang','','[]','閟宮實實，清廟微微。',40,'全唐诗/poet.tang.0.json','["閟宮實實，清廟微微。", "降格無象，馨香有依。", "式昭纂慶，方融嗣徽。", "明禋是享，神保聿歸。"]'),
('f9531bb3-bce8-42e3-9e73-28de161c2b1a','郊廟歌辭 儀坤廟樂章 迎神','不詳','唐','唐诗','tang','','[]','月靈降德，坤元授光。',40,'全唐诗/poet.tang.0.json','["月靈降德，坤元授光。", "娥英比秀，任姒均芳。", "瑤臺薦祉，金屋延祥。", "迎神有樂，歆此嘉薌。"]'),
('5df204cd-62f9-4d08-baa7-2d75bae5a9dd','郊廟歌辭 儀坤廟樂章 送神','不詳','唐','唐诗','tang','','[]','玉帛儀大，金絲奏廣。',40,'全唐诗/poet.tang.0.json','["玉帛儀大，金絲奏廣。", "靈應有孚，冥徵不爽。", "降彼休福，歆茲禋享。", "送樂有章，神麾其上。"]'),
('389ab6fd-17b0-4633-af04-f1f4d9985116','郊廟歌辭 昭德皇后廟樂章 永和','不詳','唐','唐诗','tang','','[]','穆清廟，薦嚴禋。',32,'全唐诗/poet.tang.0.json','["穆清廟，薦嚴禋。", "昭禮備，和樂新。", "望靈光，集元辰。", "祚無極，享萬春。"]'),
('85a46f9d-724e-4e70-9a94-280ac37dcb72','郊廟歌辭 昭德皇后廟樂章 肅和','不詳','唐','唐诗','tang','','[]','誠心達，娛樂分。',32,'全唐诗/poet.tang.0.json','["誠心達，娛樂分。", "升簫膋，鬱氛氳。", "茅既縮，鬯既薰。", "后來思，福如雲。"]'),
('3e035238-dd9f-4544-b1d6-85dc9eb46810','郊廟歌辭 昭德皇后廟樂章 雍和','不詳','唐','唐诗','tang','','[]','我將我享，盡明而誠。',40,'全唐诗/poet.tang.0.json','["我將我享，盡明而誠。", "載芬黍稷，載滌犧牲。", "懿矣元良，萬邦以貞。", "心乎愛敬，若覩容聲。"]'),
('c124fb36-862f-4c52-8ca3-d2ec5c92f80e','郊廟歌辭 昭德皇后廟樂章 坤元','不詳','唐','唐诗','tang','','[]','於穆先后，麗聖稱崇。',42,'全唐诗/poet.tang.0.json','["於穆先后，麗聖稱崇。", "母臨萬宇，道[被]六宮。", "昌時協慶，理內成功。", "殷薦明德，傳芳國風。"]'),
('01780a1c-3926-44f0-a75e-bf97d4624284','郊廟歌辭 昭德皇后廟樂章 壽和','不詳','唐','唐诗','tang','','[]','工祝致告，徽音不遐。',30,'全唐诗/poet.tang.0.json','["工祝致告，徽音不遐。", "酒醴咸旨，馨香具嘉。", "受釐獻祉，永慶邦家。"]'),
('39971b18-28f4-4de4-be97-f327fd3433fd','郊廟歌辭 昭德皇后廟樂章 舒和','不詳','唐','唐诗','tang','','[]','金枝羽部徹清歌，瑤臺肅穆笙磬羅。',32,'全唐诗/poet.tang.0.json','["金枝羽部徹清歌，瑤臺肅穆笙磬羅。", "諧音遍響合明意，萬類昭融靈應多。"]'),
('bde04cd8-18fd-45eb-80ea-fdc0af36c6d4','郊廟歌辭 昭德皇后廟樂章 凱安','不詳','唐','唐诗','tang','','[]','辰位列四星，帝功參十亂。',48,'全唐诗/poet.tang.0.json','["辰位列四星，帝功參十亂。", "進賢勤內輔，扈蹕清多難。", "承天厚載均，並耀宵光璨。", "留徽藹前躅，萬古披圖煥。"]'),
('ab29bc48-2530-448e-ad7e-d8bef40d1ac9','郊廟歌辭 昭德皇后廟樂章 雍和','不詳','唐','唐诗','tang','','[]','公尸既起，享禮載終。',30,'全唐诗/poet.tang.0.json','["公尸既起，享禮載終。", "稱歌進徹，盡敬繇衷。", "澤流惠下，大小咸同。"]'),
('03981ca7-42b0-4400-af87-2106d8d2ab83','郊廟歌辭 昭德皇后廟樂章 永和','不詳','唐','唐诗','tang','','[]','昭事終，幽享餘。',32,'全唐诗/poet.tang.0.json','["昭事終，幽享餘。", "移月御，返仙居。", "璇庭寂，靈幄虛。", "顧裴回，感皇儲。"]'),
('429d126e-c2a3-4496-8481-fb7d16a587d0','郊廟歌辭 讓皇帝廟樂章 迎神','李舒','唐','唐诗','tang','','[]','皇矣天宗，德先王季。',40,'全唐诗/poet.tang.0.json','["皇矣天宗，德先王季。", "因心則友，克讓以位。", "爰命有司，式遵前志。", "神其降靈，昭饗祀事。"]'),
('41ecef75-7b10-43ec-bd23-77fab837ced4','郊廟歌辭 讓皇帝廟樂章 奠幣','李舒','唐','唐诗','tang','','[]','惟帝時若，去而上仙。',40,'全唐诗/poet.tang.0.json','["惟帝時若，去而上仙。", "祀用商舞，樂備宮懸。", "白璧加薦，玄纁告虔。", "子孫拜後，承茲吉蠲。"]'),
('92be38ae-8f3e-4b9b-ba7c-7064eb84e63f','郊廟歌辭 讓皇帝廟樂章 迎俎','李舒','唐','唐诗','tang','','[]','祀盛體薦，禮協粢盛。',40,'全唐诗/poet.tang.0.json','["祀盛體薦，禮協粢盛。", "方周假廟，用魯純牲。", "捧徹祗敬，擊拊和鳴。", "受釐歸胙，既戒而平。"]'),
('8af69bf5-5208-4b2c-9b2c-97c904af1b2d','郊廟歌辭 讓皇帝廟樂章 酌獻','李舒','唐','唐诗','tang','','[]','八音具舉，三壽既盥。',40,'全唐诗/poet.tang.0.json','["八音具舉，三壽既盥。", "潔茲宗彝，瑟彼圭瓚。", "蘭肴重錯，椒醑飄散。", "降胙維城，永爲藩翰。"]'),
('b3e0ba41-a564-4cf0-97d9-bb4185a5ace2','郊廟歌辭 讓皇帝廟樂章 亞獻終獻','李舒','唐','唐诗','tang','','[]','秩禮有序，和音既同。',40,'全唐诗/poet.tang.0.json','["秩禮有序，和音既同。", "九儀不忒，三揖將終。", "孝感藩后，相維辟公。", "四時之典，永永無窮。"]'),
('206cead0-3581-4c90-806d-73c1988744cf','郊廟歌辭 讓皇帝廟樂章 送神','李舒','唐','唐诗','tang','','[]','奠獻已事，昏昕載分。',40,'全唐诗/poet.tang.0.json','["奠獻已事，昏昕載分。", "風搖雨散，靈衛絪緼。", "龍駕帝服，上騰五雲。", "泮宮復閟，寂寞無聞。"]'),
('46a7c1f9-9435-4a65-a047-b3522122d754','郊廟歌辭 享隱太子廟樂章 誠和','不詳','唐','唐诗','tang','','[]','道閟鶴關，運纏鳩里。',40,'全唐诗/poet.tang.0.json','["道閟鶴關，運纏鳩里。", "門集大命，俾歆嘉祀。", "禮亞六瑚，誠殫二簋。", "有誠顒若，神斯戾止。"]'),
('fce85010-8fcb-42b5-8ac1-db094c76e69e','郊廟歌辭 享隱太子廟樂章 肅和','不詳','唐','唐诗','tang','','[]','歲肇春宗，乾開震長。',40,'全唐诗/poet.tang.0.json','["歲肇春宗，乾開震長。", "瑤山既寂，戾園斯享。", "玉肅其事，物昭其象。", "弦誦成風，笙歌合響。"]'),
('1dc3f1e4-38a9-44d2-b041-7818ef30f0b4','郊廟歌辭 享隱太子廟樂章 雍和','不詳','唐','唐诗','tang','','[]','明典肅陳，神居邃啓。',40,'全唐诗/poet.tang.0.json','["明典肅陳，神居邃啓。", "春伯聯事，秋官相禮。", "有來雍雍，登歌濟濟。", "緬維主鬯，庶歆芳醴。"]'),
('a0853819-25ae-442f-8f48-c0bf2717023e','郊廟歌辭 享隱太子廟樂章 舒和','不詳','唐','唐诗','tang','','[]','三縣已判歌鐘列，六佾將開羽鏚分。',32,'全唐诗/poet.tang.0.json','["三縣已判歌鐘列，六佾將開羽鏚分。", "尚想燕飛來蔽日，終疑鶴影降凌雲。"]'),
('033790bd-6e98-4c99-b4b7-2f3fe8d87c93','郊廟歌辭 享隱太子廟樂章 凱安','不詳','唐','唐诗','tang','','[]','天步昔將開，商郊初欲踐。',48,'全唐诗/poet.tang.0.json','["天步昔將開，商郊初欲踐。", "撫戎金陣廓，貳極瑤圖闡。", "雞戟遂崇儀，龍樓期好善。", "弄兵隳震業，啓聖隆嗣典。"]'),
('78ae9964-a188-450b-ba7c-7c6386a2a980','郊廟歌辭 隱太子廟樂章 迎神','不詳','唐','唐诗','tang','','[]','蒼震有位，黃離蔽明。',40,'全唐诗/poet.tang.0.json','["蒼震有位，黃離蔽明。", "江充禍結，戾據災成。", "銜冤昔痛，贈典今榮。", "享靈有秩，奉樂以迎。"]'),
('867ad8d9-f1b1-43a5-94d7-7dac74332b1f','郊廟歌辭 隱太子廟樂章 送神','不詳','唐','唐诗','tang','','[]','皇情悼往，祀議增設。',40,'全唐诗/poet.tang.0.json','["皇情悼往，祀議增設。", "鐘鼓鏗鏘，羽旄昭晰。", "掌禮云備，司筵告徹。", "樂以送神，靈其鑒闋。"]'),
('f03e0bf6-9cfd-4209-9617-f25c4499343a','郊廟歌辭 享章懷太子廟樂章 迎神','不詳','唐','唐诗','tang','','[]','副君昭象，道應黃離。',40,'全唐诗/poet.tang.0.json','["副君昭象，道應黃離。", "銅樓備德，玉裕成規。", "仙氣靄靄，靈從師師。", "前驅戾止，控鶴來儀。"]'),
('c33a6b03-6ab3-42eb-b49a-4c3327d34f3f','郊廟歌辭 享章懷太子廟樂章 登歌酌鬯','不詳','唐','唐诗','tang','','[]','忠孝本著，羽翼先成。',40,'全唐诗/poet.tang.0.json','["忠孝本著，羽翼先成。", "寢門昭德，馳道爲程。", "幣帛有典，容衛無聲。", "司存既肅，廟享惟清。"]'),
('b94c383f-7e56-4f31-97d9-f5e0b11f6bec','郊廟歌辭 享章懷太子廟樂章 迎俎酌獻','不詳','唐','唐诗','tang','','[]','通三錫胤，明兩承英。',40,'全唐诗/poet.tang.0.json','["通三錫胤，明兩承英。", "太山比赫，伊水聞笙。", "宗祧是寄，禮樂其亨。", "嘉辰薦俎，以發聲明。"]'),
('0f875d13-f28a-4fb6-8770-c599af4c1909','郊廟歌辭 享章懷太子廟樂章 送文舞迎武舞','不詳','唐','唐诗','tang','','[]','羽籥崇文禮以畢，干鏚奮武事將行。',32,'全唐诗/poet.tang.0.json','["羽籥崇文禮以畢，干鏚奮武事將行。", "用舍繇來其有致，壯志宣威樂太平。"]'),
('b3e2191a-e121-4ddc-a90c-f39467dabf75','郊廟歌辭 享章懷太子廟樂章 武舞作','不詳','唐','唐诗','tang','','[]','綠林熾炎曆，黃虞格有苗。',48,'全唐诗/poet.tang.0.json','["綠林熾炎曆，黃虞格有苗。", "沙塵驚塞外，帷幄命嫖姚。", "七德干戈止，三邊雲霧消。", "寶祚長無極，歌舞盛今朝。"]'),
('6629ab09-a177-43fc-b434-b5b5c4aca1d3','郊廟歌辭 享懿德太子廟樂章 迎神','不詳','唐','唐诗','tang','','[]','甲觀昭祥，畫堂升位。',40,'全唐诗/poet.tang.0.json','["甲觀昭祥，畫堂升位。", "禮絕羣后，望尊儲貳。", "啓誦慙德，莊丕掩粹。", "伊浦鳳翔，緱峰鶴至。"]'),
('ebaa76e9-e569-4145-bf34-2c543612c475','郊廟歌辭 享懿德太子廟樂章 登歌酌鬯','不詳','唐','唐诗','tang','','[]','譽闡元儲，寄崇明兩。',40,'全唐诗/poet.tang.0.json','["譽闡元儲，寄崇明兩。", "玉裕雖晦，銅樓可想。", "弦誦輟音，笙歌罷響。", "幣帛言設，禮容無爽。"]'),
('638dc04a-2956-4d8c-9953-bd99b6f07b10','郊廟歌辭 享懿德太子廟樂章 迎俎酌獻','不詳','唐','唐诗','tang','','[]','雍雍盛典，肅肅靈祠。',40,'全唐诗/poet.tang.0.json','["雍雍盛典，肅肅靈祠。", "賓天有聖，對日無期。", "飄颻羽服，掣曳雲旗。", "眷言主鬯，心乎愴茲。"]'),
('2fd8d994-fa15-4dd6-9619-af4802e819fc','郊廟歌辭 享懿德太子廟樂章 送文舞迎武舞','不詳','唐','唐诗','tang','','[]','八音協奏陳金石，六佾分行整禮容。',32,'全唐诗/poet.tang.0.json','["八音協奏陳金石，六佾分行整禮容。", "滄溟赴海還稱少，素月開輪即是重。"]'),
