('b58d8eef-5c3d-4ffc-a8d8-1444d5788cd0','郊廟歌辭 享節愍太子廟樂章 迎神','不詳','唐','唐诗','tang','','[]','儲后望崇，元良寄切。',40,'全唐诗/poet.tang.0.json','["儲后望崇，元良寄切。", "寢門是仰，馳道不絕。", "仙袂雲會，靈旗電晰。", "煌煌而來，禮物攸設。"]'),
('79ddee12-c5fd-4c8d-a46b-eb1d6649d850','郊廟歌辭 享節愍太子廟樂章 登歌酌鬯','不詳','唐','唐诗','tang','','[]','灼灼重明，仰承元首。',40,'全唐诗/poet.tang.0.json','["灼灼重明，仰承元首。", "既賢且哲，惟孝與友。", "惟孝雖遙，靈規不朽。", "禮因誠致，備絜玄酒。"]'),
('0ff5fdc0-c751-4486-badb-b915f2846d71','郊廟歌辭 享節愍太子廟樂章 迎俎酌獻','不詳','唐','唐诗','tang','','[]','嘉薦有典，至誠莫騫。',40,'全唐诗/poet.tang.0.json','["嘉薦有典，至誠莫騫。", "畫梁雲亙，雕俎星連。", "樂器周列，禮容備宣。", "依稀如在，若未賓天。"]'),
('d20096b1-0638-4ae2-8991-63dd8cc416f6','郊廟歌辭 享節愍太子廟樂章 送文舞出迎武舞入','不詳','唐','唐诗','tang','','[]','邕邕闡化憑文德，赫赫宣威藉武功。',32,'全唐诗/poet.tang.0.json','["邕邕闡化憑文德，赫赫宣威藉武功。", "既執羽旄先拂吹，還持玉鏚更揮空。"]'),
('7ad961c0-606b-4c1d-ae90-257a622641a5','郊廟歌辭 享節愍太子廟樂章 武舞作','不詳','唐','唐诗','tang','','[]','武德諒雍雍，由來掃寇戎。',48,'全唐诗/poet.tang.0.json','["武德諒雍雍，由來掃寇戎。", "劒光揮作電，旗影列成虹。", "霧廓三邊靜，波澄四海同。", "睿圖今已盛，相共舞皇風。"]'),
('cc49c7e9-6335-48b7-bef3-6302b96ca84c','郊廟歌辭 享文敬太子廟樂章 請神','許孟容','唐','唐诗','tang','','[]','觴牢具品，管磬有節。',40,'全唐诗/poet.tang.0.json','["觴牢具品，管磬有節。", "祝道夤恭，神儀昭晰。", "桐圭早貴，象輅追設。", "聲達樂成，降歆豐潔。"]'),
('87a78b1d-6698-48af-9dee-5f1ed107b418','郊廟歌辭 享文敬太子廟樂章 登歌','陳京','唐','唐诗','tang','','[]','歌以德發，聲以樂貴。',40,'全唐诗/poet.tang.0.json','["歌以德發，聲以樂貴。", "樂善名存，追仙禮異。", "鸞旌拱修，鳳鳴合吹。", "神聽皇慈，仲月皆至。"]'),
('a6e3064d-ee05-4ca8-b10d-30c7216efdd1','郊廟歌辭 享文敬太子廟樂章 迎俎酌獻','馮伉','唐','唐诗','tang','','[]','撰日瞻景，誠陳樂張。',40,'全唐诗/poet.tang.0.json','["撰日瞻景，誠陳樂張。", "禮容秩秩，羽舞煌煌。", "肅將滌濯，祗薦芬芳。", "永錫繁祉，思深饗嘗。"]'),
('0da37a4d-2fd4-4bfd-b23f-c2aeccdfb968','郊廟歌辭 享文敬太子廟樂章 送文舞迎武舞','不詳','唐','唐诗','tang','','[]','干旄羽籥相虧蔽，一進一退殊行綴。',32,'全唐诗/poet.tang.0.json','["干旄羽籥相虧蔽，一進一退殊行綴。", "昔獻三雍盛禮容，今陳六佾崇儀制。"]'),
('2b3a1327-3904-4065-b735-f5bed808f6ea','郊廟歌辭 享文敬太子廟樂章 亞獻終獻','崔邠','唐','唐诗','tang','','[]','醴齊泛尊彝，軒縣動干戚。',48,'全唐诗/poet.tang.0.json','["醴齊泛尊彝，軒縣動干戚。", "入室僾如在，升階虔所歷。", "奮疾合威容，定利舒皦繹。", "方崇廟貌禮，永被君恩錫。"]'),
('62ce882e-643b-4de0-9fb0-29097e6440c4','郊廟歌辭 享文敬太子廟樂章 送神','張薦','唐','唐诗','tang','','[]','三獻具舉，九旗將旋。',40,'全唐诗/poet.tang.0.json','["三獻具舉，九旗將旋。", "追勞表德，罷享賓天。", "風引仙管，堂虛畫筵。", "芳馨常在，瞻望悠然。"]'),
('8f1bdb64-597c-4b05-ba77-8ed259edfb60','郊廟歌辭 享惠昭太子廟樂章 請神','歸登','唐','唐诗','tang','','[]','嘉薦既陳，祀事孔明。',40,'全唐诗/poet.tang.0.json','["嘉薦既陳，祀事孔明。", "閒歌在堂，萬舞在庭。", "外則盡物，內則盡誠。", "鳳笙如聞，歌其潔精。"]'),
('49fbd5f0-3471-45c5-a64a-bc40941ecc7f','郊廟歌辭 享惠昭太子廟樂章 登歌','杜羔','唐','唐诗','tang','','[]','因心克孝，位震遺芬。',40,'全唐诗/poet.tang.0.json','["因心克孝，位震遺芬。", "賓天道茂，軫懷氣分。", "發祗乃祀，咳歎如聞。", "二歌斯升，以詠德薰。"]'),
('9634986a-188d-4cde-b2c7-41b5036d2c16','郊廟歌辭 享惠昭太子廟樂章 迎俎酌獻','李逢吉','唐','唐诗','tang','','[]','既潔酒醴，聿陳熟腥。',40,'全唐诗/poet.tang.0.json','["既潔酒醴，聿陳熟腥。", "肅將震念，昭格儲靈。", "展矣禮典，薰然德馨。", "愔愔管磬，亦具是聽。"]'),
('fa313434-c420-4913-949b-ecca22c5d5a4','郊廟歌辭 享惠昭太子廟樂章 送文舞出迎武舞入','孟簡','唐','唐诗','tang','','[]','喧喧金石容既缺，肅肅羽駕就行列。',32,'全唐诗/poet.tang.0.json','["喧喧金石容既缺，肅肅羽駕就行列。", "緱山遺響昔所聞，廟庭進旅今攸設。"]'),
('c6230e55-bf8d-4279-8516-d7c1480d7dcb','郊廟歌辭 享惠昭太子廟樂章 亞獻終獻','裴度','唐','唐诗','tang','','[]','重輪始發祥，齒胄方興學。',48,'全唐诗/poet.tang.0.json','["重輪始發祥，齒胄方興學。", "冥然升紫府，鏗爾薦清樂。", "奠斝致馨香，在庭紛羽籥。", "禮成神既醉，髣髴緱山鶴。"]'),
('5d132fee-78bd-4ca6-9f30-ebe3c81c95f7','郊廟歌辭 享惠昭太子廟樂章 送神','王涯','唐','唐诗','tang','','[]','威儀畢陳，備樂將闋。',40,'全唐诗/poet.tang.0.json','["威儀畢陳，備樂將闋。", "苞茅酒縮，膋蕭香徹。", "宮臣展事，肅雍在列。", "迎精送往，厥鑒昭晰。"]'),
('0cb1c0b0-5d86-4916-8d89-6ff586e84308','郊廟歌辭 武后崇先廟樂章','不詳','唐','唐诗','tang','','[]','先德謙撝冠昔，嚴規節素超今。',84,'全唐诗/poet.tang.0.json','["先德謙撝冠昔，嚴規節素超今。", "奉國忠誠每竭，承家至孝純深。", "追崇懼乖尊意，顯號恐玷徽音。", "既迫王公屢請，方乃俯遂羣心。", "有限無由展敬，奠醑每闕親斟。", "大禮虔申典冊，蘋藻敬薦翹襟。"]'),
('cc360c8a-07ac-45e0-bd96-bf2e8dfba5da','郊廟歌辭 襃德廟樂章 昭德','不詳','唐','唐诗','tang','','[]','道赫梧宮，悲盈蒿里。',40,'全唐诗/poet.tang.0.json','["道赫梧宮，悲盈蒿里。", "爰賜徽烈，載敷嘉祀。", "享洽四時，規陳二簋。", "靈應昭格，神其戾止。"]'),
('2a013e18-54cc-4269-a082-97cf543ddf65','郊廟歌辭 襃德廟樂章 進德','不詳','唐','唐诗','tang','','[]','塗山懿戚，媯汭崇姻。',40,'全唐诗/poet.tang.0.json','["塗山懿戚，媯汭崇姻。", "祠筵肇啓，祭典方申。", "禮以備物，樂以感神。", "用隆敦敍，載穆彝倫。"]'),
('9ee1a9cc-06b3-43f2-843e-2c18869a92c4','郊廟歌辭 襃德廟樂章 襃德','不詳','唐','唐诗','tang','','[]','家著累仁，門昭積善。',20,'全唐诗/poet.tang.0.json','["家著累仁，門昭積善。", "瑤篚既列，金縣式展。"]'),
('46351d94-3e29-45c5-a09a-b37e306bdfdd','郊廟歌辭 襃德廟樂章 武舞作','不詳','唐','唐诗','tang','','[]','昭昭竹殿開，奕奕蘭宮啓。',48,'全唐诗/poet.tang.0.json','["昭昭竹殿開，奕奕蘭宮啓。", "懿範隆丹掖，殊榮闢朱邸。", "六佾薦徽容，三簋陳芳醴。", "萬石覃貽厥，分珪崇祖禰。"]'),
('0012fad3-1326-4cba-95b2-d420ec573977','郊廟歌辭 襃德廟樂章 彰德','不詳','唐','唐诗','tang','','[]','名隆五嶽，秩映三台。',22,'全唐诗/poet.tang.0.json','["名隆五嶽，秩映三台。", "嚴祠已備，[睟]影方迴。"]'),
('4976a8f8-250f-4373-bdb4-19222eaf4ec0','舞曲歌辭 功成慶善樂舞詞','不詳','唐','唐诗','tang','','[]','壽丘惟舊跡，酆邑乃前基。',120,'全唐诗/poet.tang.0.json','["壽丘惟舊跡，酆邑乃前基。", "粤余承累聖，懸弧亦在茲。", "弱齡逢運改，提劒鬱匡時。", "指麾八荒定，懷柔萬國夷。", "梯山盛入欵，駕海亦來思。", "單于陪武帳，日逐衛文㮰。", "端扆朝四岳，無爲任百司。", "霜節明秋景，輕冰結水湄。", "芸黃遍原隰，禾頴積京坻。", "共樂還譙宴，歡此大風詩。"]'),
('0bf4db06-9f1f-4d9a-bf85-57a742b46a17','舞曲歌辭 中和樂舞詞','不詳','唐','唐诗','tang','','[]','芳歲肇佳節，物華當仲春。',96,'全唐诗/poet.tang.0.json','["芳歲肇佳節，物華當仲春。", "乾坤既昭泰，煙景含氤氳。", "德淺荷玄貺，樂成思治人。", "前庭列鐘鼓，廣殿延羣臣。", "八卦隨舞意，五音轉曲新。", "顧非咸池奏，庶協南風薰。", "式宴禮所重，浹歡情必均。", "同和諒在茲，萬國希可親。"]'),
('1a189c45-aa28-4599-96c8-dd55e1d67a23','舞曲歌辭 凱樂歌辭 破陣樂','不詳','唐','唐诗','tang','','[]','受律辭元首，相將討叛臣。',24,'全唐诗/poet.tang.0.json','["受律辭元首，相將討叛臣。", "咸歌破陣樂，共賞太平人。"]'),
('bf410866-e96c-46e5-a6af-f54971f61820','舞曲歌辭 凱樂歌辭 應聖期','不詳','唐','唐诗','tang','','[]','聖德期昌運，雍熙萬宇清。',48,'全唐诗/poet.tang.0.json','["聖德期昌運，雍熙萬宇清。", "乾坤資化育，海嶽共休明。", "闢土欣耕稼，銷戈遂偃兵。", "殊方歌帝澤，執贄賀昇平。"]'),
('55c332db-d62a-45b9-83ce-1b22f3261c7a','舞曲歌辭 凱樂歌辭 賀聖歡','不詳','唐','唐诗','tang','','[]','四海皇風被，千年德水清。',24,'全唐诗/poet.tang.0.json','["四海皇風被，千年德水清。", "戎衣更不著，今日告功成。"]'),
('5fe98de1-5cd1-4a24-892c-56e058583719','舞曲歌辭 凱樂歌辭 君臣同慶樂','不詳','唐','唐诗','tang','','[]','主聖開昌曆，臣忠奉大猷。',24,'全唐诗/poet.tang.0.json','["主聖開昌曆，臣忠奉大猷。", "君看偃革後，便是太平秋。"]'),
('e6bc971a-81b0-42db-b6e7-7f3e6d2aa250','郊廟歌辭 梁郊祀樂章 慶和 一','趙光逢、張衮','唐','唐诗','tang','','[]','就陽位，升圓丘。',32,'全唐诗/poet.tang.0.json','["就陽位，升圓丘。", "佩雙玉，御大裘。", "膺天命，擁神休。", "萬靈感，百祿遒。"]'),
('85735127-9249-41f5-8c05-ffc89bbe34d2','郊廟歌辭 梁郊祀樂章 慶和 二','趙光逢、張衮','唐','唐诗','tang','','[]','秉黃鉞，建朱旗。',32,'全唐诗/poet.tang.0.json','["秉黃鉞，建朱旗。", "震八表，清二儀。", "帝業顯，王道夷。", "受景命，啓皇基。"]'),
('c83d6fd3-b533-4f81-8274-cfc77d39ce77','郊廟歌辭 梁郊祀樂章 慶和 三','趙光逢、張衮','唐','唐诗','tang','','[]','開九門，懷百神。',32,'全唐诗/poet.tang.0.json','["開九門，懷百神。", "通肸蠁，接氤氳。", "明粢薦，廣樂陳。", "奠嘉璧，燎芳薪。"]'),
('3c02395c-ea77-4e2e-b356-da5a089542c7','郊廟歌辭 梁郊祀樂章 慶和 四','趙光逢、張衮','唐','唐诗','tang','','[]','膺寶圖，執左契。',32,'全唐诗/poet.tang.0.json','["膺寶圖，執左契。", "德應天，聖饗帝。", "薦表衷，荷靈惠。", "壽萬年，祚百世。"]'),
('72d9dcc7-c6eb-4b78-8d05-f1f3b6963937','郊廟歌辭 梁郊祀樂章 慶和 五','趙光逢、張衮','唐','唐诗','tang','','[]','惟德動天，有感必通。',40,'全唐诗/poet.tang.0.json','["惟德動天，有感必通。", "秉茲一德，禋於六宗。", "欽夤寶命，恭肅禮容。", "來顧來享，永穆皇風。"]'),
('2838b215-b643-4eba-83f3-74c33b9b0a78','郊廟歌辭 梁郊祀樂章 慶和 六','趙光逢、張衮','唐','唐诗','tang','','[]','天惟佑德，辟乃奉天。',40,'全唐诗/poet.tang.0.json','["天惟佑德，辟乃奉天。", "交感斯在，昭事罔愆。", "歲功已就，王道無偏。", "於焉報本，是用告虔。"]'),
('aea2ebbd-30af-49d6-a669-4d2e230fbcf2','郊廟歌辭 梁郊祀樂章 慶順','趙光逢、張衮','唐','唐诗','tang','','[]','聖皇戾止，天步舒遲。',40,'全唐诗/poet.tang.0.json','["聖皇戾止，天步舒遲。", "乾乾睿相，穆穆皇儀。", "進退必肅，陟降是祗。", "六變克協，萬靈協隨。"]'),
('6b5da87f-0b2d-4b82-8461-174658630b20','郊廟歌辭 梁郊祀樂章 慶平','趙光逢、張衮','唐','唐诗','tang','','[]','天命降鑒，帝德惟馨。',40,'全唐诗/poet.tang.0.json','["天命降鑒，帝德惟馨。", "享祀不忒，禮容孔明。", "奠璧布幣，薦神獻精。", "神佑以答，敷錫永寧。"]'),
('31f00e5a-29bd-41ee-b876-1555098dc862','郊廟歌辭 梁郊祀樂章 慶肅','趙光逢、張衮','唐','唐诗','tang','','[]','籩豆簠簋，黍稷非馨。',40,'全唐诗/poet.tang.0.json','["籩豆簠簋，黍稷非馨。", "懿茲彝器，厥德惟明。", "金石匏革，以和以平。", "繇此無體，期乎永寧。"]'),
('323842d9-5424-473b-b736-17a756fa6bb8','郊廟歌辭 梁郊祀樂章 慶熙','趙光逢、張衮','唐','唐诗','tang','','[]','哲后躬享，旨酒斯陳。',40,'全唐诗/poet.tang.0.json','["哲后躬享，旨酒斯陳。", "王恭無斁，嚴祀維夤。", "皇祖以配，大孝以振。", "宜錫景福，永休下民。"]'),
('0422e5c8-5a58-467c-9bd8-c38a585b0ac2','郊廟歌辭 梁郊祀樂章 慶隆','趙光逢、張衮','唐','唐诗','tang','','[]','恭祀上帝，于國之陽。',20,'全唐诗/poet.tang.0.json','["恭祀上帝，于國之陽。", "爵醴是荷，鴻基永昌。"]'),
('6947499c-32e9-4bd7-9df9-7cfb4a9b9c26','郊廟歌辭 梁郊祀樂章 慶融','趙光逢、張衮','唐','唐诗','tang','','[]','道和氣兮襲氤氳，宣皇規兮彰聖神。',32,'全唐诗/poet.tang.0.json','["道和氣兮襲氤氳，宣皇規兮彰聖神。", "服遐裔兮敷質文，格苗扈兮息煙塵。"]'),
('a4ed9fc0-2f60-4076-bdc6-10647b93bb3a','郊廟歌辭 梁郊祀樂章 慶休','趙光逢、張衮','唐','唐诗','tang','','[]','大業來四夷，仁風和萬國。',48,'全唐诗/poet.tang.0.json','["大業來四夷，仁風和萬國。", "白日體無私，皇天輔有德。", "七旬罪已服，六月師方克。", "偉哉帝道隆，終始常作則。"]'),
('aa9edde0-b875-4ac6-ad28-2643d36fe463','郊廟歌辭 梁郊祀樂章 慶和','趙光逢、張衮','唐','唐诗','tang','','[]','煙燎升，禮容徹。',32,'全唐诗/poet.tang.0.json','["煙燎升，禮容徹。", "誠感達，人神悅。", "靈貺彰，聖情結。", "玉座寂，金爐歇。"]'),
('874cb9ab-1d1d-46d0-a2f6-ca86a74f6a8b','郊廟歌辭 周郊祀樂章 昭順樂','不詳','唐','唐诗','tang','','[]','五兵勿用，萬國咸安。',40,'全唐诗/poet.tang.0.json','["五兵勿用，萬國咸安。", "告功圓蓋，受命雲壇。", "樂鳴鳳律，禮備雞竿。", "神光欲降，衆目遐觀。"]'),
('0e853c39-1a72-4671-86c1-562805f0d563','郊廟歌辭 周郊祀樂章 治順樂','不詳','唐','唐诗','tang','','[]','羽衛離丹闕，金軒赴泰壇。',48,'全唐诗/poet.tang.0.json','["羽衛離丹闕，金軒赴泰壇。", "珠旗明月色，玉佩曉霜寒。", "黼黻龍衣備，琮璜寶器完。", "百神將受職，宗社保長安。"]'),
('8c45a628-700b-4822-80b5-01cff6f7997b','郊廟歌辭 周郊祀樂章 感順樂','不詳','唐','唐诗','tang','','[]','明君陳大禮，展幣祀圓丘。',24,'全唐诗/poet.tang.0.json','["明君陳大禮，展幣祀圓丘。", "雅樂聲其發，祥雲色正浮。"]'),
('0ff009da-1154-46ae-bc65-af8c9372f08d','郊廟歌辭 周郊祀樂章 禋順樂','不詳','唐','唐诗','tang','','[]','黃彝將獻，特牲預迎。',20,'全唐诗/poet.tang.0.json','["黃彝將獻，特牲預迎。", "既修昭事，潛達明誠。"]'),
('da032cf6-0cbf-4ac0-89c5-ca1f30d1103c','郊廟歌辭 周郊祀樂章 福順樂','不詳','唐','唐诗','tang','','[]','相承五運，取法三才。',40,'全唐诗/poet.tang.0.json','["相承五運，取法三才。", "大禮爰展，率土咸來。", "卿雲祕室，甘泉寶臺。", "象樽初酌，受福不回。"]'),
('d4a3572e-6a8b-48dd-b783-fdcad0b18c3f','郊廟歌辭 周郊祀樂章 福順樂','不詳','唐','唐诗','tang','','[]','昊天成命，邦國盛儀。',40,'全唐诗/poet.tang.0.json','["昊天成命，邦國盛儀。", "多士齊列，六龍載馳。", "壇升泰一，樂奏咸池。", "高明祚德，永致昌期。"]'),
('52d4576e-8c59-4eb6-b447-418a531cb97e','郊廟歌辭 周郊祀樂章 福順樂','不詳','唐','唐诗','tang','','[]','上天垂景貺，哲后舉鸞觴。',24,'全唐诗/poet.tang.0.json','["上天垂景貺，哲后舉鸞觴。", "明德今方祚，邦家萬世昌。"]'),
('8ca290b9-18af-4403-bdc7-00c6d0aa3211','郊廟歌辭 周郊祀樂章 忠順樂','不詳','唐','唐诗','tang','','[]','木鐸敷音文德昌，朱干成列武功彰。',32,'全唐诗/poet.tang.0.json','["木鐸敷音文德昌，朱干成列武功彰。", "雷鼗鷺羽今休用，玉鏚相參正發揚。"]'),
('ae1d49cc-efe9-4014-ad98-8417fedced83','郊廟歌辭 周郊祀樂章 武舞樂','不詳','唐','唐诗','tang','','[]','圭瓚方陳禮，干旄乃象功。',24,'全唐诗/poet.tang.0.json','["圭瓚方陳禮，干旄乃象功。", "成文非羽籥，猛勢若羆熊。"]'),
('f5c60e4b-e1c7-4071-8d05-b4e786788e12','郊廟歌辭 周郊祀樂章 昭順樂','不詳','唐','唐诗','tang','','[]','雲門孤竹，蒼璧黃琮。',40,'全唐诗/poet.tang.0.json','["雲門孤竹，蒼璧黃琮。", "既祀天地，克配祖宗。", "虔修盛禮，仰荅玄功。", "神歸碧落，福降無窮。"]'),
('0a53428d-1ee1-4404-81a3-8aeaae4894fa','郊廟歌辭 梁太廟樂舞辭 開平舞','不詳','唐','唐诗','tang','','[]','黍稷馨，醴𨣧清。',32,'全唐诗/poet.tang.0.json','["黍稷馨，醴𨣧清。", "牲牷潔，金石鏗。", "恭祀事，結皇情。", "神來格，歌頌聲。"]'),
('f6c8f066-5e4e-44d0-853d-13902a670a69','郊廟歌辭 梁太廟樂舞辭 皇帝行','不詳','唐','唐诗','tang','','[]','莫高者天，攀躋弗克。',40,'全唐诗/poet.tang.0.json','["莫高者天，攀躋弗克。", "隮天有方，累仁積德。", "祖宗隆之，子孫履之。", "配天明祀，永永孝思。"]'),
('64e7b48a-305f-4d78-a810-c84a76b7b348','郊廟歌辭 梁太廟樂舞辭 帝盥','不詳','唐','唐诗','tang','','[]','莊肅蒞事，周旋禮容。',20,'全唐诗/poet.tang.0.json','["莊肅蒞事，周旋禮容。", "裸鬯嚴潔，穆穆雍雍。"]'),
('630ab837-d414-4cce-bf80-bc615a6c15fd','郊廟歌辭 梁太廟樂舞辭 登歌','不詳','唐','唐诗','tang','','[]','於赫我皇，建中立極。',40,'全唐诗/poet.tang.0.json','["於赫我皇，建中立極。", "動以武功，靜以文德。", "昭事上帝，歡心萬國。", "大報嚴禋，四海述職。"]');
